-- Meeting: Rugged Robotics <> MiD Bi-Weekly (2026-02-04 15:00:00+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    'db0afec5-85bc-41b0-8c0f-79b368eb3b16',
    '2026-02-04 15:00:00+00',
    'fireflies',
    '01KG33WXAXHCRDV7YHTM6SQN9C',
    'Rugged Robotics <> MiD Bi-Weekly',
    '{"Nathalie Mintjens","Tristan Pelligrino","Baylee Gunnell","Rob Schnitzler"}'::text[],
    1033,
    'https://us02web.zoom.us/j/84801960534?pwd=tq9BFJBUCprJPJ0W7NRoAlJYH7bZXD.1',
    '{"id":"01KG33WXAXHCRDV7YHTM6SQN9C","title":"Rugged Robotics <> MiD Bi-Weekly","summary":{"notes":"## **Website Updates and Content Development**\n\nThe website updates have been largely completed, with a few final tweaks pending to ensure consistency and usability.\n\n- **Demir completed the latest round of website updates**, including the About tab with a new \"Meet Rugged\" section and consistent styling across pages (04:01)  \n    - The use cases section was reordered and one was removed per Rob’s feedback  \n    - Rob plans to finish minor text and photo edits himself due to limited time before the board meeting  \n    - The footer navigation alignment issue was noted and will be fixed later to match the existing site’s layout  \n    - The case studies PDFs have been redesigned and are ready for deployment on the staging site once Rob confirms (06:13)  \n\n- **Rob confirmed the redesigned case studies PDFs cover all current content**, with a new PDF expected soon to add to the system (06:29)  \n    - Nathalie will proceed to develop these PDFs on the staging site without waiting for individual reviews  \n    - This system aims to speed up future updates and maintain consistency across case studies  \n\n## **Account-Based Marketing (ABM) Performance and Lead Management**\n\nThe ABM email campaign continues to perform steadily, with ongoing efforts to nurture engaged contacts and refine lead handling processes.\n\n- **Since the last meeting, 1,074 leads were contacted via email, maintaining strong open and click rates** (07:23)  \n    - Nathalie created an email open tracking sheet showing individual contact engagement in January 2026 for monthly review  \n    - Rob and team may integrate this tracking into HubSpot to focus nurturing on highly engaged leads  \n    - Baylee cautioned that open counts can be inflated by automated systems, so trends matter more than raw numbers (08:33)  \n\n- **Paid media efforts in January yielded six Google search ad conversions and three LinkedIn conversions** (09:26)  \n    - Rob is reviewing lead annotation lists to identify high-value prospects and refine targeting  \n    - He highlighted green-coded leads as potential direct customers and yellow-coded leads as partner or secondary market prospects (13:11)  \n    - Rob emphasized the need to update HubSpot notifications so he receives all lead form submissions promptly for better tracking and responsiveness (11:42)  \n\n## **Lead Notification and Response Process Improvements**\n\nThere is a need to enhance the lead notification system and clarify lead response roles to improve follow-up efficiency.\n\n- **Tristan confirmed LinkedIn leads come through website HubSpot forms, which currently lack full notification coverage for Rob’s team** (10:17)  \n    - The HubSpot form notifications will be updated to include Rob and others on the alert list immediately after the meeting (11:42)  \n    - Rob suspects internal follow-up gaps and some lead noise contribute to missed responses, not vendor issues (10:39)  \n    - The team agreed to monitor lead quality and adjust outreach focus accordingly, especially filtering out lower-value Gmail leads (12:44)  \n\n## **Strategic ABM Initiatives and Next Steps**\n\nThe team will pause new ABM expansions until after the board meeting, focusing on current outreach and refining lead segmentation.\n\n- **Rob will share a “Do Not Contact” list of about seven contacts to exclude from ABM efforts** (15:27)  \n    - No immediate action on new LinkedIn ad campaigns or additional passive target lists until after the board meeting workload eases  \n    - The plan is to review two more weeks of ABM results before deciding on further ABM refinements or expansions (15:50)  \n    - This approach prioritizes bandwidth management and ensures focus on high-value leads and campaigns  \n\n## **Overall Team Sentiment and Forward Momentum**\n\nThe team is aligned and optimistic about progress, with clear next steps to maintain momentum post-board meeting.\n\n- **Rob expressed excitement about the website progress and momentum despite recent time constraints** (16:19)  \n    - Nathalie reassured that case studies deployment will proceed and further updates will be made after Rob’s review  \n    - The team agreed to reconvene after the board meeting to refocus on ABM and website content updates (16:37)","outline":null,"keywords":["Website Updates","Case Studies","ABM Reporting","Lead Nurturing","HubSpot Forms","Paid Media Conversions"],"overview":"- **Website Updates Near Completion:** Final tweaks to website almost done; case studies redesign ready for deployment after Rob''s confirmation.  \n- **ABM Campaign Performance Steady:** 1,074 leads contacted; email engagement tracked for review; focus on high-value leads.  \n- **Lead Notification Gaps Identified:** Current HubSpot forms lack full notifications; updates planned for improved tracking and response.  \n- **Pause on New ABM Initiatives:** No new campaigns until after the board meeting; focus on existing outreach and lead quality.  \n- **Team Optimistic About Progress:** General excitement about website and ABM initiatives, with plans for follow-up post-board meeting.","action_items":"\n**Rob Schnitzler**\nComplete final text and photo updates on the website homepage and other pages as time permits (04:57)\nProvide upcoming case study PDF for upload and systematize rapid case study updates (07:11)\nAnnotate and send “Do Not Contact” list for HubSpot to Nathalie (15:12)\nReview ABM progress after board meeting and prepare for next steps on LinkedIn campaign and contact lists (15:27)\n\n**Nathalie Mintjens**\nDevelop redesigned case study PDFs on the staging site (07:17)\nSend email open tracking sheet to Rob monthly to support nurture efforts (08:11)\nUpdate HubSpot forms to ensure Rob and his team receive lead notifications (14:49)\n\n**Tristan Pelligrino**\nCheck and adjust HubSpot form notifications to include Rob and relevant stakeholders on lead submissions (11:30)\n\n**Baylee Gunnell**\nShare an article on email open data reliability with Rob for reference (08:33)\n"},"duration":17.219999313354492,"speakers":[{"id":0,"name":"Nathalie Mintjens"},{"id":1,"name":"Tristan Pelligrino"},{"id":2,"name":"Baylee Gunnell"},{"id":3,"name":"Rob Schnitzler"}],"sentences":[{"text":"Hello?","index":0,"end_time":10.16,"speaker_id":0,"start_time":9.84,"speaker_name":"Nathalie Mintjens"},{"text":"Hey, Bailey.","index":1,"end_time":11.8,"speaker_id":1,"start_time":11.04,"speaker_name":"Tristan Pelligrino"},{"text":"What''s happening?","index":2,"end_time":12.48,"speaker_id":1,"start_time":11.8,"speaker_name":"Tristan Pelligrino"},{"text":"Just good.","index":3,"end_time":14.64,"speaker_id":2,"start_time":14,"speaker_name":"Baylee Gunnell"},{"text":"Good to be here.","index":4,"end_time":15.76,"speaker_id":2,"start_time":14.8,"speaker_name":"Baylee Gunnell"},{"text":"I know I''m.","index":5,"end_time":19.88,"speaker_id":1,"start_time":18.96,"speaker_name":"Tristan Pelligrino"},{"text":"I''m like losing my voice and stuff.","index":6,"end_time":21.44,"speaker_id":1,"start_time":19.88,"speaker_name":"Tristan Pelligrino"},{"text":"Oh, no.","index":7,"end_time":22,"speaker_id":0,"start_time":21.44,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah.","index":8,"end_time":24.08,"speaker_id":1,"start_time":23.52,"speaker_name":"Tristan Pelligrino"},{"text":"So.","index":9,"end_time":26.25,"speaker_id":3,"start_time":26.01,"speaker_name":"Rob Schnitzler"},{"text":"Hopefully it doesn''t completely go away.","index":10,"end_time":31.77,"speaker_id":1,"start_time":28.57,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, that''s never fun.","index":11,"end_time":35.85,"speaker_id":2,"start_time":34.41,"speaker_name":"Baylee Gunnell"},{"text":"No.","index":12,"end_time":36.81,"speaker_id":1,"start_time":36.41,"speaker_name":"Tristan Pelligrino"},{"text":"Did you catch, like, a cold or something?","index":13,"end_time":39.45,"speaker_id":2,"start_time":37.61,"speaker_name":"Baylee Gunnell"},{"text":"Something''s going on.","index":14,"end_time":41.17,"speaker_id":1,"start_time":40.09,"speaker_name":"Tristan Pelligrino"},{"text":"I woke up this morning.","index":15,"end_time":42.13,"speaker_id":1,"start_time":41.17,"speaker_name":"Tristan Pelligrino"},{"text":"It was like a truck hit me.","index":16,"end_time":43.53,"speaker_id":1,"start_time":42.13,"speaker_name":"Tristan Pelligrino"},{"text":"I was like, oh, no.","index":17,"end_time":45.53,"speaker_id":1,"start_time":43.85,"speaker_name":"Tristan Pelligrino"},{"text":"Oh, no.","index":18,"end_time":46.41,"speaker_id":2,"start_time":45.69,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":19,"end_time":47.53,"speaker_id":1,"start_time":46.97,"speaker_name":"Tristan Pelligrino"},{"text":"And I haven''t even had a drink this year.","index":20,"end_time":50.25,"speaker_id":1,"start_time":48.09,"speaker_name":"Tristan Pelligrino"},{"text":"You went all January.","index":21,"end_time":53.94,"speaker_id":2,"start_time":52.26,"speaker_name":"Baylee Gunnell"},{"text":"Dry.","index":22,"end_time":56.26,"speaker_id":1,"start_time":55.86,"speaker_name":"Tristan Pelligrino"},{"text":"January still dry.","index":23,"end_time":57.54,"speaker_id":1,"start_time":56.26,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":24,"end_time":58.1,"speaker_id":3,"start_time":57.7,"speaker_name":"Rob Schnitzler"},{"text":"So it''s.","index":25,"end_time":58.7,"speaker_id":1,"start_time":58.1,"speaker_name":"Tristan Pelligrino"},{"text":"Wow.","index":26,"end_time":59.22,"speaker_id":2,"start_time":58.7,"speaker_name":"Baylee Gunnell"},{"text":"I told my wife.","index":27,"end_time":60.54,"speaker_id":1,"start_time":59.7,"speaker_name":"Tristan Pelligrino"},{"text":"I was like, man, I feel more hungover this morning than I felt long time.","index":28,"end_time":66.18,"speaker_id":1,"start_time":60.54,"speaker_name":"Tristan Pelligrino"},{"text":"So that''s awesome.","index":29,"end_time":70.34,"speaker_id":2,"start_time":68.1,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":30,"end_time":71.22,"speaker_id":1,"start_time":70.74,"speaker_name":"Tristan Pelligrino"},{"text":"Can you hear my dog?","index":31,"end_time":77.46,"speaker_id":2,"start_time":76.26,"speaker_name":"Baylee Gunnell"},{"text":"No.","index":32,"end_time":79.09,"speaker_id":1,"start_time":78.85,"speaker_name":"Tristan Pelligrino"},{"text":"No.","index":33,"end_time":79.65,"speaker_id":3,"start_time":79.33,"speaker_name":"Rob Schnitzler"},{"text":"Okay.","index":34,"end_time":80.13,"speaker_id":2,"start_time":79.65,"speaker_name":"Baylee Gunnell"},{"text":"Can you?","index":35,"end_time":80.89,"speaker_id":1,"start_time":80.45,"speaker_name":"Tristan Pelligrino"},{"text":"Natalie?","index":36,"end_time":81.29,"speaker_id":1,"start_time":80.89,"speaker_name":"Tristan Pelligrino"},{"text":"I can''t hear it.","index":37,"end_time":82.05,"speaker_id":1,"start_time":81.29,"speaker_name":"Tristan Pelligrino"},{"text":"I heard one bark.","index":38,"end_time":83.81,"speaker_id":0,"start_time":82.53,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":39,"end_time":84.77,"speaker_id":2,"start_time":84.13,"speaker_name":"Baylee Gunnell"},{"text":"It''s always the Amazon delivery.","index":40,"end_time":89.09,"speaker_id":2,"start_time":85.73,"speaker_name":"Baylee Gunnell"},{"text":"My camera''s blurry.","index":41,"end_time":91.25,"speaker_id":2,"start_time":89.89,"speaker_name":"Baylee Gunnell"},{"text":"Okay.","index":42,"end_time":103.27,"speaker_id":3,"start_time":92.05,"speaker_name":"Rob Schnitzler"},{"text":"It.","index":43,"end_time":103.66,"speaker_id":3,"start_time":103.42,"speaker_name":"Rob Schnitzler"},{"text":"All right.","index":44,"end_time":134.109,"speaker_id":3,"start_time":133.749,"speaker_name":"Rob Schnitzler"},{"text":"There we go.","index":45,"end_time":134.749,"speaker_id":1,"start_time":134.109,"speaker_name":"Tristan Pelligrino"},{"text":"Rob here.","index":46,"end_time":135.509,"speaker_id":3,"start_time":134.749,"speaker_name":"Rob Schnitzler"},{"text":"Hey.","index":47,"end_time":145.909,"speaker_id":3,"start_time":145.429,"speaker_name":"Rob Schnitzler"},{"text":"Sorry I''m a couple minutes late.","index":48,"end_time":147.509,"speaker_id":3,"start_time":146.069,"speaker_name":"Rob Schnitzler"},{"text":"No worries.","index":49,"end_time":152.949,"speaker_id":2,"start_time":152.229,"speaker_name":"Baylee Gunnell"},{"text":"Yeah.","index":50,"end_time":153.669,"speaker_id":2,"start_time":153.189,"speaker_name":"Baylee Gunnell"},{"text":"Good to see you.","index":51,"end_time":154.709,"speaker_id":2,"start_time":153.829,"speaker_name":"Baylee Gunnell"},{"text":"How is everyone doing?","index":52,"end_time":160.32,"speaker_id":3,"start_time":157.72,"speaker_name":"Rob Schnitzler"},{"text":"All right.","index":53,"end_time":160.72,"speaker_id":1,"start_time":160.32,"speaker_name":"Tristan Pelligrino"},{"text":"Robbie.","index":54,"end_time":161.12,"speaker_id":1,"start_time":160.72,"speaker_name":"Tristan Pelligrino"},{"text":"I was just letting Bailey and Natalie know I''m losing my voice, so that''s exciting.","index":55,"end_time":166.48,"speaker_id":1,"start_time":161.12,"speaker_name":"Tristan Pelligrino"},{"text":"Oh, no.","index":56,"end_time":167.08,"speaker_id":3,"start_time":166.48,"speaker_name":"Rob Schnitzler"},{"text":"Okay.","index":57,"end_time":167.8,"speaker_id":1,"start_time":167.16,"speaker_name":"Tristan Pelligrino"},{"text":"Even more.","index":58,"end_time":168.76,"speaker_id":3,"start_time":168.12,"speaker_name":"Rob Schnitzler"},{"text":"More.","index":59,"end_time":169.6,"speaker_id":3,"start_time":169.24,"speaker_name":"Rob Schnitzler"},{"text":"Even more.","index":60,"end_time":170.12,"speaker_id":3,"start_time":169.6,"speaker_name":"Rob Schnitzler"},{"text":"Radio host.","index":61,"end_time":170.84,"speaker_id":3,"start_time":170.12,"speaker_name":"Rob Schnitzler"},{"text":"Yeah.","index":62,"end_time":172.12,"speaker_id":3,"start_time":171.64,"speaker_name":"Rob Schnitzler"},{"text":"Well, I can''t yell at my kids now the way I want to, so that''s a problem.","index":63,"end_time":176.28,"speaker_id":1,"start_time":172.68,"speaker_name":"Tristan Pelligrino"},{"text":"But, you know.","index":64,"end_time":177.72,"speaker_id":1,"start_time":176.36,"speaker_name":"Tristan Pelligrino"},{"text":"Got it.","index":65,"end_time":180.28,"speaker_id":3,"start_time":179.64,"speaker_name":"Rob Schnitzler"},{"text":"Go ahead, Natalie.","index":66,"end_time":182.89,"speaker_id":1,"start_time":181.32,"speaker_name":"Tristan Pelligrino"},{"text":"Go ahead.","index":67,"end_time":183.17,"speaker_id":1,"start_time":182.89,"speaker_name":"Tristan Pelligrino"},{"text":"I just gave you screen share for everything.","index":68,"end_time":185.45,"speaker_id":1,"start_time":183.17,"speaker_name":"Tristan Pelligrino"},{"text":"All right.","index":69,"end_time":187.21,"speaker_id":3,"start_time":186.65,"speaker_name":"Rob Schnitzler"},{"text":"Okay, so for the agenda today, Rob, just want to go through some of the website updates since the last feedback that you gave us, a review of abm.","index":70,"end_time":205.09,"speaker_id":0,"start_time":195.29,"speaker_name":"Nathalie Mintjens"},{"text":"So looking at our reporting and then just keeping track of some of the other ABM ideas that you had brought up and making sure that we stay on top of those.","index":71,"end_time":214.57,"speaker_id":0,"start_time":205.09,"speaker_name":"Nathalie Mintjens"},{"text":"So for the site, Demir finished doing the updates from the last round of feedback that you gave us.","index":72,"end_time":222.33,"speaker_id":0,"start_time":216.81,"speaker_name":"Nathalie Mintjens"},{"text":"So specifically for the about tab on the staging site, you''ll see that we added in the meet rugged area over here.","index":73,"end_time":235.09,"speaker_id":0,"start_time":223.13,"speaker_name":"Nathalie Mintjens"},{"text":"So that page should be showing now.","index":74,"end_time":236.61,"speaker_id":0,"start_time":235.09,"speaker_name":"Nathalie Mintjens"},{"text":"And then we also just made all of these look exactly the same and consistent.","index":75,"end_time":240.09,"speaker_id":0,"start_time":236.61,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":76,"end_time":241.57,"speaker_id":3,"start_time":241.21,"speaker_name":"Rob Schnitzler"},{"text":"Awesome.","index":77,"end_time":242.09,"speaker_id":3,"start_time":241.57,"speaker_name":"Rob Schnitzler"},{"text":"Yep.","index":78,"end_time":244.05,"speaker_id":0,"start_time":243.53,"speaker_name":"Nathalie Mintjens"},{"text":"And then for the use cases, we changed, there was one of them that you asked us to remove, and then we put them in the same order that you had sent over.","index":79,"end_time":254.09,"speaker_id":0,"start_time":244.05,"speaker_name":"Nathalie Mintjens"},{"text":"Just like in the footer navigation as well.","index":80,"end_time":256.89,"speaker_id":0,"start_time":254.41,"speaker_name":"Nathalie Mintjens"},{"text":"Awesome.","index":81,"end_time":258.57,"speaker_id":3,"start_time":258.01,"speaker_name":"Rob Schnitzler"},{"text":"Is this on the footer navigation?","index":82,"end_time":261.45,"speaker_id":3,"start_time":259.85,"speaker_name":"Rob Schnitzler"},{"text":"Is there a reason it''s so far over now?","index":83,"end_time":263.61,"speaker_id":3,"start_time":261.45,"speaker_name":"Rob Schnitzler"},{"text":"It''s kind of a small thing, but, like, is it just like.","index":84,"end_time":267.36,"speaker_id":3,"start_time":263.77,"speaker_name":"Rob Schnitzler"},{"text":"Because it''s tied to left align and there''s that space?","index":85,"end_time":270.96,"speaker_id":3,"start_time":267.36,"speaker_name":"Rob Schnitzler"},{"text":"Yeah.","index":86,"end_time":273.36,"speaker_id":0,"start_time":272.88,"speaker_name":"Nathalie Mintjens"},{"text":"Or you think it''s too left aligned now?","index":87,"end_time":275.2,"speaker_id":0,"start_time":273.36,"speaker_name":"Nathalie Mintjens"},{"text":"I.","index":88,"end_time":276.44,"speaker_id":3,"start_time":276.08,"speaker_name":"Rob Schnitzler"},{"text":"It''s interesting because I think on their Existing site.","index":89,"end_time":278.68,"speaker_id":3,"start_time":276.44,"speaker_name":"Rob Schnitzler"},{"text":"It''s closer to get there.","index":90,"end_time":279.92,"speaker_id":3,"start_time":278.68,"speaker_name":"Rob Schnitzler"},{"text":"I''m not.","index":91,"end_time":280.28,"speaker_id":3,"start_time":279.92,"speaker_name":"Rob Schnitzler"},{"text":"I''m not 100% sure.","index":92,"end_time":281.44,"speaker_id":3,"start_time":280.28,"speaker_name":"Rob Schnitzler"},{"text":"But there was just one thing that when I was looking at it, I don''t think it really.","index":93,"end_time":286.44,"speaker_id":3,"start_time":281.44,"speaker_name":"Rob Schnitzler"},{"text":"Matt.","index":94,"end_time":286.8,"speaker_id":3,"start_time":286.44,"speaker_name":"Rob Schnitzler"},{"text":"I don''t think it really matters, but.","index":95,"end_time":288.4,"speaker_id":3,"start_time":286.8,"speaker_name":"Rob Schnitzler"},{"text":"Oh, yeah, we can definitely fix that.","index":96,"end_time":296.25,"speaker_id":0,"start_time":292.25,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":97,"end_time":297.77,"speaker_id":3,"start_time":297.13,"speaker_name":"Rob Schnitzler"},{"text":"We don''t have to do it now.","index":98,"end_time":299.85,"speaker_id":3,"start_time":298.73,"speaker_name":"Rob Schnitzler"},{"text":"You don''t have to do it now.","index":99,"end_time":300.89,"speaker_id":3,"start_time":299.85,"speaker_name":"Rob Schnitzler"},{"text":"Try to, like, get my final stuff.","index":100,"end_time":304.81,"speaker_id":3,"start_time":300.89,"speaker_name":"Rob Schnitzler"},{"text":"If I have any other small ones.","index":101,"end_time":306.41,"speaker_id":3,"start_time":304.81,"speaker_name":"Rob Schnitzler"},{"text":"There might be one thing on the homepage that I is beyond my thing to figure out, but this is awesome.","index":102,"end_time":316.81,"speaker_id":3,"start_time":309.69,"speaker_name":"Rob Schnitzler"},{"text":"I think.","index":103,"end_time":317.69,"speaker_id":3,"start_time":317.13,"speaker_name":"Rob Schnitzler"},{"text":"I think for the most part, everything else will be text and text and photo stuff that I can just do myself.","index":104,"end_time":327.75,"speaker_id":3,"start_time":318.55,"speaker_name":"Rob Schnitzler"},{"text":"And then I think there''s.","index":105,"end_time":329.91,"speaker_id":3,"start_time":328.79,"speaker_name":"Rob Schnitzler"},{"text":"I''ve been trying.","index":106,"end_time":330.79,"speaker_id":3,"start_time":329.99,"speaker_name":"Rob Schnitzler"},{"text":"There''s still one more time.","index":107,"end_time":332.07,"speaker_id":3,"start_time":330.87,"speaker_name":"Rob Schnitzler"},{"text":"We have that like me layout asap.","index":108,"end_time":335.11,"speaker_id":3,"start_time":332.07,"speaker_name":"Rob Schnitzler"},{"text":"So I''ve been trying to switch the bottom pages on all of them and I keep finding like one or two more.","index":109,"end_time":341.87,"speaker_id":3,"start_time":335.35,"speaker_name":"Rob Schnitzler"},{"text":"So I think.","index":110,"end_time":342.43,"speaker_id":3,"start_time":341.87,"speaker_name":"Rob Schnitzler"},{"text":"I think I''m close.","index":111,"end_time":343.23,"speaker_id":3,"start_time":342.43,"speaker_name":"Rob Schnitzler"},{"text":"I just.","index":112,"end_time":343.75,"speaker_id":3,"start_time":343.23,"speaker_name":"Rob Schnitzler"},{"text":"I don''t know if I''m going to have time this week or next getting.","index":113,"end_time":347.25,"speaker_id":3,"start_time":344.29,"speaker_name":"Rob Schnitzler"},{"text":"We have our board meeting.","index":114,"end_time":348.93,"speaker_id":3,"start_time":347.73,"speaker_name":"Rob Schnitzler"},{"text":"So I''m getting crushed on that.","index":115,"end_time":351.73,"speaker_id":3,"start_time":349.17,"speaker_name":"Rob Schnitzler"},{"text":"And so it''s.","index":116,"end_time":352.53,"speaker_id":3,"start_time":351.81,"speaker_name":"Rob Schnitzler"},{"text":"Take any.","index":117,"end_time":353.01,"speaker_id":3,"start_time":352.53,"speaker_name":"Rob Schnitzler"},{"text":"Any of my working time has done that.","index":118,"end_time":354.69,"speaker_id":3,"start_time":353.01,"speaker_name":"Rob Schnitzler"},{"text":"But this is great.","index":119,"end_time":355.73,"speaker_id":3,"start_time":354.69,"speaker_name":"Rob Schnitzler"},{"text":"Hopefully I only have one more thing.","index":120,"end_time":358.69,"speaker_id":3,"start_time":357.01,"speaker_name":"Rob Schnitzler"},{"text":"One more thing for Demir.","index":121,"end_time":360.21,"speaker_id":3,"start_time":358.77,"speaker_name":"Rob Schnitzler"},{"text":"One or two, and everything else I can do.","index":122,"end_time":362.69,"speaker_id":3,"start_time":360.29,"speaker_name":"Rob Schnitzler"},{"text":"So I really appreciate this.","index":123,"end_time":363.93,"speaker_id":3,"start_time":362.69,"speaker_name":"Rob Schnitzler"},{"text":"This is awesome.","index":124,"end_time":364.85,"speaker_id":3,"start_time":363.93,"speaker_name":"Rob Schnitzler"},{"text":"The.","index":125,"end_time":365.73,"speaker_id":3,"start_time":365.33,"speaker_name":"Rob Schnitzler"},{"text":"The other.","index":126,"end_time":366.61,"speaker_id":3,"start_time":365.97,"speaker_name":"Rob Schnitzler"},{"text":"The case studies you guys that you redesigned, are those on the staging site at this point or are we still.","index":127,"end_time":372.53,"speaker_id":3,"start_time":366.61,"speaker_name":"Rob Schnitzler"},{"text":"Yes.","index":128,"end_time":374.18,"speaker_id":0,"start_time":373.9,"speaker_name":"Nathalie Mintjens"},{"text":"So we have redesigned all of the existing PDFs that you have.","index":129,"end_time":379.02,"speaker_id":0,"start_time":374.18,"speaker_name":"Nathalie Mintjens"},{"text":"So that''s one thing I wanted to check with you if you''d like us to go ahead and develop it on the staging site or if you''d like to review each of these individually first.","index":130,"end_time":387.74,"speaker_id":0,"start_time":380.22,"speaker_name":"Nathalie Mintjens"},{"text":"I mean, if the text is the same like I think and this is brought, this is probably fine.","index":131,"end_time":394.02,"speaker_id":3,"start_time":389.1,"speaker_name":"Rob Schnitzler"},{"text":"I don''t think I need to re.","index":132,"end_time":395.18,"speaker_id":3,"start_time":394.02,"speaker_name":"Rob Schnitzler"},{"text":"Look at each one.","index":133,"end_time":397.66,"speaker_id":3,"start_time":396.22,"speaker_name":"Rob Schnitzler"},{"text":"Are there more.","index":134,"end_time":400.57,"speaker_id":3,"start_time":399.93,"speaker_name":"Rob Schnitzler"},{"text":"There''s more than this or these are the ones.","index":135,"end_time":403.29,"speaker_id":3,"start_time":400.73,"speaker_name":"Rob Schnitzler"},{"text":"Roman.","index":136,"end_time":404.65,"speaker_id":3,"start_time":404.17,"speaker_name":"Rob Schnitzler"},{"text":"I don''t see Gotti.","index":137,"end_time":408.33,"speaker_id":3,"start_time":406.81,"speaker_name":"Rob Schnitzler"},{"text":"That was the original one that we sent you, the test one.","index":138,"end_time":413.05,"speaker_id":0,"start_time":409.29,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":139,"end_time":413.41,"speaker_id":3,"start_time":413.05,"speaker_name":"Rob Schnitzler"},{"text":"Yeah.","index":140,"end_time":413.77,"speaker_id":3,"start_time":413.41,"speaker_name":"Rob Schnitzler"},{"text":"Okay.","index":141,"end_time":414.57,"speaker_id":3,"start_time":413.93,"speaker_name":"Rob Schnitzler"},{"text":"These are the four that are on the site.","index":142,"end_time":416.33,"speaker_id":3,"start_time":414.89,"speaker_name":"Rob Schnitzler"},{"text":"The Turner one''s so bad.","index":143,"end_time":417.77,"speaker_id":3,"start_time":416.33,"speaker_name":"Rob Schnitzler"},{"text":"Okay.","index":144,"end_time":418.97,"speaker_id":3,"start_time":418.33,"speaker_name":"Rob Schnitzler"},{"text":"Yeah, I will have another.","index":145,"end_time":421.85,"speaker_id":3,"start_time":420.65,"speaker_name":"Rob Schnitzler"},{"text":"I will have another one soon that will be in the PDF form.","index":146,"end_time":425.96,"speaker_id":3,"start_time":421.85,"speaker_name":"Rob Schnitzler"},{"text":"And then we''ll just have to put it into this.","index":147,"end_time":427.88,"speaker_id":3,"start_time":425.96,"speaker_name":"Rob Schnitzler"},{"text":"But hopefully we have a kind of a system and it could be fast.","index":148,"end_time":430.96,"speaker_id":3,"start_time":427.88,"speaker_name":"Rob Schnitzler"},{"text":"Okay, sounds good.","index":149,"end_time":433.28,"speaker_id":0,"start_time":431.6,"speaker_name":"Nathalie Mintjens"},{"text":"Awesome.","index":150,"end_time":433.76,"speaker_id":3,"start_time":433.28,"speaker_name":"Rob Schnitzler"},{"text":"So we''ll go ahead and get these developed on the staging site as well.","index":151,"end_time":436.8,"speaker_id":0,"start_time":433.76,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":152,"end_time":438.16,"speaker_id":3,"start_time":437.6,"speaker_name":"Rob Schnitzler"},{"text":"Cool.","index":153,"end_time":442.24,"speaker_id":3,"start_time":441.76,"speaker_name":"Rob Schnitzler"},{"text":"And then so looking at our ABM activities.","index":154,"end_time":445.84,"speaker_id":0,"start_time":443.04,"speaker_name":"Nathalie Mintjens"},{"text":"So just looking at the stats since our last meeting.","index":155,"end_time":450.64,"speaker_id":0,"start_time":447.92,"speaker_name":"Nathalie Mintjens"},{"text":"So two weeks ago, we have 1074 total leads contacted on email.","index":156,"end_time":456.57,"speaker_id":0,"start_time":450.8,"speaker_name":"Nathalie Mintjens"},{"text":"The email open and click rate is still looking strong.","index":157,"end_time":459.77,"speaker_id":0,"start_time":457.21,"speaker_name":"Nathalie Mintjens"},{"text":"So what we did do since our last meeting, we talked about how we can continue to nurture these people that are showing engagement.","index":158,"end_time":466.81,"speaker_id":0,"start_time":460.17,"speaker_name":"Nathalie Mintjens"},{"text":"So we created an email open tracking sheet over here.","index":159,"end_time":471.85,"speaker_id":0,"start_time":467.13,"speaker_name":"Nathalie Mintjens"},{"text":"So I''ll send this over to you right after.","index":160,"end_time":474.29,"speaker_id":0,"start_time":472.57,"speaker_name":"Nathalie Mintjens"},{"text":"And this shows contacts that opened emails and then the number of times that they opened it in January of 2026.","index":161,"end_time":481.57,"speaker_id":0,"start_time":474.29,"speaker_name":"Nathalie Mintjens"},{"text":"So I was thinking we could do this on a monthly basis and then up to your team if this is something that you''d like to add into HubSpot to continue nurturing these specific people.","index":162,"end_time":491.29,"speaker_id":0,"start_time":481.73,"speaker_name":"Nathalie Mintjens"},{"text":"Okay, awesome.","index":163,"end_time":493.09,"speaker_id":3,"start_time":491.29,"speaker_name":"Rob Schnitzler"},{"text":"The people that open the five times, is there.","index":164,"end_time":496.53,"speaker_id":3,"start_time":493.49,"speaker_name":"Rob Schnitzler"},{"text":"Is there sometimes something weird with the data that if they''re just kind of like clicking through their emails or something like that, or not clicking through but like scrolling through or something like.","index":165,"end_time":507.25,"speaker_id":3,"start_time":496.61,"speaker_name":"Rob Schnitzler"},{"text":"Is that is your experience?","index":166,"end_time":509.77,"speaker_id":3,"start_time":508.13,"speaker_name":"Rob Schnitzler"},{"text":"That number is right.","index":167,"end_time":510.53,"speaker_id":3,"start_time":509.77,"speaker_name":"Rob Schnitzler"},{"text":"Like someone''s actually opened it five times.","index":168,"end_time":512.45,"speaker_id":3,"start_time":510.53,"speaker_name":"Rob Schnitzler"},{"text":"I can speak to that a little bit.","index":169,"end_time":514.73,"speaker_id":2,"start_time":513.25,"speaker_name":"Baylee Gunnell"},{"text":"I''ll send you an article after this too, Rob.","index":170,"end_time":517.33,"speaker_id":2,"start_time":514.73,"speaker_name":"Baylee Gunnell"},{"text":"But you can''t.","index":171,"end_time":518.53,"speaker_id":2,"start_time":517.65,"speaker_name":"Baylee Gunnell"},{"text":"Yeah, long story short, you can''t 100% trust the data here all the time.","index":172,"end_time":523.57,"speaker_id":2,"start_time":518.93,"speaker_name":"Baylee Gunnell"},{"text":"Like, some people have systems in place that''ll like automatically open emails on the back end.","index":173,"end_time":531.25,"speaker_id":2,"start_time":523.57,"speaker_name":"Baylee Gunnell"},{"text":"So.","index":174,"end_time":532.15,"speaker_id":3,"start_time":531.89,"speaker_name":"Rob Schnitzler"},{"text":"So yeah, I would look at this with a grain of salt.","index":175,"end_time":535.06,"speaker_id":2,"start_time":532.38,"speaker_name":"Baylee Gunnell"},{"text":"Like, it''s not 100% true, but it can be helpful to look.","index":176,"end_time":541.02,"speaker_id":2,"start_time":535.06,"speaker_name":"Baylee Gunnell"},{"text":"One thing I like to keep an eye on is like trends.","index":177,"end_time":543.66,"speaker_id":2,"start_time":541.02,"speaker_name":"Baylee Gunnell"},{"text":"So, like, if email one got 50 opens and email two got 30 opens, like, that trend can tell us, okay, email one, maybe the subject line was a bit more engaging or things like that.","index":178,"end_time":556.74,"speaker_id":2,"start_time":544.14,"speaker_name":"Baylee Gunnell"},{"text":"Those trends can be really helpful, but the actual number might not always be 100% true.","index":179,"end_time":561.42,"speaker_id":2,"start_time":556.74,"speaker_name":"Baylee Gunnell"},{"text":"Okay, awesome.","index":180,"end_time":563.57,"speaker_id":3,"start_time":562.45,"speaker_name":"Rob Schnitzler"},{"text":"Okay, I''ll send this sheet over right after this.","index":181,"end_time":570.53,"speaker_id":0,"start_time":566.53,"speaker_name":"Nathalie Mintjens"},{"text":"And then looking at paid media as well.","index":182,"end_time":573.45,"speaker_id":0,"start_time":571.65,"speaker_name":"Nathalie Mintjens"},{"text":"I just wanted to look back on the stats for January.","index":183,"end_time":576.05,"speaker_id":0,"start_time":573.45,"speaker_name":"Nathalie Mintjens"},{"text":"So we ended January with six conversions from Google search ads and then three conversions from LinkedIn.","index":184,"end_time":584.77,"speaker_id":0,"start_time":576.77,"speaker_name":"Nathalie Mintjens"},{"text":"And then I did see that you started annotating the list of leads already.","index":185,"end_time":589.31,"speaker_id":0,"start_time":584.93,"speaker_name":"Nathalie Mintjens"},{"text":"So I don''t know if you wanted to walk through these a little bit too.","index":186,"end_time":592.99,"speaker_id":0,"start_time":590.11,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah, I will.","index":187,"end_time":595.31,"speaker_id":3,"start_time":594.19,"speaker_name":"Rob Schnitzler"},{"text":"One question.","index":188,"end_time":596.19,"speaker_id":3,"start_time":595.63,"speaker_name":"Rob Schnitzler"},{"text":"The every lead we get from LinkedIn and Google right now, it''s is the email.","index":189,"end_time":604.11,"speaker_id":3,"start_time":596.19,"speaker_name":"Rob Schnitzler"},{"text":"Is an email going to Connor or something?","index":190,"end_time":607.39,"speaker_id":3,"start_time":604.19,"speaker_name":"Rob Schnitzler"},{"text":"Like, what''s the process right now?","index":191,"end_time":609.51,"speaker_id":3,"start_time":607.47,"speaker_name":"Rob Schnitzler"},{"text":"Is it still that?","index":192,"end_time":610.39,"speaker_id":3,"start_time":609.51,"speaker_name":"Rob Schnitzler"},{"text":"Or that process has changed a little bit.","index":193,"end_time":613.07,"speaker_id":3,"start_time":610.39,"speaker_name":"Rob Schnitzler"},{"text":"Tristan, do you Want to speak to that?","index":194,"end_time":617.45,"speaker_id":0,"start_time":616.09,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah, good question.","index":195,"end_time":618.49,"speaker_id":1,"start_time":617.61,"speaker_name":"Tristan Pelligrino"},{"text":"So we don''t have any LinkedIn legion forms.","index":196,"end_time":622.33,"speaker_id":1,"start_time":618.73,"speaker_name":"Tristan Pelligrino"},{"text":"All those would come through the website.","index":197,"end_time":624.81,"speaker_id":1,"start_time":622.33,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah.","index":198,"end_time":626.17,"speaker_id":1,"start_time":625.77,"speaker_name":"Tristan Pelligrino"},{"text":"So we would have to check the HubSpot form to confirm.","index":199,"end_time":629.29,"speaker_id":1,"start_time":626.17,"speaker_name":"Tristan Pelligrino"},{"text":"We, we didn''t change Anything on the HubSpot form.","index":200,"end_time":633.61,"speaker_id":1,"start_time":630.97,"speaker_name":"Tristan Pelligrino"},{"text":"So.","index":201,"end_time":636.89,"speaker_id":3,"start_time":636.49,"speaker_name":"Rob Schnitzler"},{"text":"Are you getting those, though?","index":202,"end_time":638.25,"speaker_id":1,"start_time":636.97,"speaker_name":"Tristan Pelligrino"},{"text":"I want to make sure you''re.","index":203,"end_time":639.49,"speaker_id":1,"start_time":638.41,"speaker_name":"Tristan Pelligrino"},{"text":"I am not.","index":204,"end_time":640.09,"speaker_id":3,"start_time":639.49,"speaker_name":"Rob Schnitzler"},{"text":"I am not.","index":205,"end_time":640.73,"speaker_id":3,"start_time":640.09,"speaker_name":"Rob Schnitzler"},{"text":"I''m trying to figure out and I don''t actually.","index":206,"end_time":646.5,"speaker_id":3,"start_time":642.18,"speaker_name":"Rob Schnitzler"},{"text":"My hunch is it''s actually not on you guys.","index":207,"end_time":650.7,"speaker_id":3,"start_time":646.98,"speaker_name":"Rob Schnitzler"},{"text":"Like there''s probably something and we''ve stopped.","index":208,"end_time":652.86,"speaker_id":3,"start_time":650.7,"speaker_name":"Rob Schnitzler"},{"text":"Some of our team has stopped responding to some of them or we haven''t, like, whatever.","index":209,"end_time":657.94,"speaker_id":3,"start_time":652.86,"speaker_name":"Rob Schnitzler"},{"text":"But I saw a number of lead forms in hotspot that our team hadn''t responded to and there''s a lot of noise to that, but I just wanted to see.","index":210,"end_time":666.42,"speaker_id":3,"start_time":657.94,"speaker_name":"Rob Schnitzler"},{"text":"I mean, if you want to set it so I get the lead form too, just so I can track it kind of going forward, that''s fine.","index":211,"end_time":673.01,"speaker_id":3,"start_time":666.74,"speaker_name":"Rob Schnitzler"},{"text":"Yeah.","index":212,"end_time":674.37,"speaker_id":1,"start_time":673.97,"speaker_name":"Tristan Pelligrino"},{"text":"So on the front end for smart lead replies, hey, reach and stuff though, those are, we just don''t have any replies from those emails right now.","index":213,"end_time":682.21,"speaker_id":1,"start_time":674.37,"speaker_name":"Tristan Pelligrino"},{"text":"Those are coming through a different.","index":214,"end_time":683.57,"speaker_id":1,"start_time":682.21,"speaker_name":"Tristan Pelligrino"},{"text":"That, that''s N8N driving that email.","index":215,"end_time":686.13,"speaker_id":1,"start_time":683.81,"speaker_name":"Tristan Pelligrino"},{"text":"But then.","index":216,"end_time":686.69,"speaker_id":1,"start_time":686.13,"speaker_name":"Tristan Pelligrino"},{"text":"Yeah, yeah, HubSpot forms have like their own notification setting.","index":217,"end_time":691.41,"speaker_id":1,"start_time":686.69,"speaker_name":"Tristan Pelligrino"},{"text":"We''ll, we''ll go ahead and take a look at that and just, we''ll use the same list, which is all three or four of you.","index":218,"end_time":698.02,"speaker_id":1,"start_time":691.57,"speaker_name":"Tristan Pelligrino"},{"text":"We''ll put that same list on the HubSpot forms.","index":219,"end_time":702.14,"speaker_id":1,"start_time":698.74,"speaker_name":"Tristan Pelligrino"},{"text":"So we''ll do that.","index":220,"end_time":702.86,"speaker_id":1,"start_time":702.14,"speaker_name":"Tristan Pelligrino"},{"text":"Okay.","index":221,"end_time":703.38,"speaker_id":3,"start_time":702.86,"speaker_name":"Rob Schnitzler"},{"text":"Yeah.","index":222,"end_time":705.02,"speaker_id":3,"start_time":704.66,"speaker_name":"Rob Schnitzler"},{"text":"And it sucks because the LinkedIn now when we''ve done the business manager, like, I don''t, I don''t think George gets the LinkedIn notifications in the same way.","index":223,"end_time":712.58,"speaker_id":3,"start_time":705.02,"speaker_name":"Rob Schnitzler"},{"text":"I can make him sign up for the business manager thing.","index":224,"end_time":715.3,"speaker_id":3,"start_time":712.58,"speaker_name":"Rob Schnitzler"},{"text":"So, yeah, it''s, it''s, it''s.","index":225,"end_time":718.98,"speaker_id":3,"start_time":715.46,"speaker_name":"Rob Schnitzler"},{"text":"Don''t worry about it.","index":226,"end_time":720.1,"speaker_id":3,"start_time":719.22,"speaker_name":"Rob Schnitzler"},{"text":"It''s just going forward.","index":227,"end_time":721.46,"speaker_id":3,"start_time":720.1,"speaker_name":"Rob Schnitzler"},{"text":"Like how I actually think some of this is on them or we''ve changed our strategy on who we''re going after a little bit.","index":228,"end_time":729.33,"speaker_id":3,"start_time":721.54,"speaker_name":"Rob Schnitzler"},{"text":"But I still, still trying to figure that out.","index":229,"end_time":732.57,"speaker_id":3,"start_time":729.33,"speaker_name":"Rob Schnitzler"},{"text":"So, so I would say broadly, like on the list, anyone, anyone with a Gmail is, you know, questionable if they''re kind of like a real business.","index":230,"end_time":745.69,"speaker_id":3,"start_time":733.61,"speaker_name":"Rob Schnitzler"},{"text":"So I, it''s not.","index":231,"end_time":747.53,"speaker_id":3,"start_time":745.85,"speaker_name":"Rob Schnitzler"},{"text":"It is what.","index":232,"end_time":748.7,"speaker_id":3,"start_time":748.26,"speaker_name":"Rob Schnitzler"},{"text":"It kind of is what it is.","index":233,"end_time":750.1,"speaker_id":3,"start_time":748.7,"speaker_name":"Rob Schnitzler"},{"text":"Or like, we get a lot of like, components things which I think is like this, the Yulia Zong and stuff like that going forward.","index":234,"end_time":761.38,"speaker_id":3,"start_time":750.1,"speaker_name":"Rob Schnitzler"},{"text":"Smaller general contractors that I did not highlight will.","index":235,"end_time":766.1,"speaker_id":3,"start_time":762.02,"speaker_name":"Rob Schnitzler"},{"text":"We will have a product to sell to them.","index":236,"end_time":768.18,"speaker_id":3,"start_time":766.1,"speaker_name":"Rob Schnitzler"},{"text":"So, like, this is a good list.","index":237,"end_time":769.66,"speaker_id":3,"start_time":768.18,"speaker_name":"Rob Schnitzler"},{"text":"Derek and I were, like, taking a look at it yesterday of knowing, like, who''s interested at kind of like the lower market that could potentially lease a robot or.","index":238,"end_time":779.32,"speaker_id":3,"start_time":769.66,"speaker_name":"Rob Schnitzler"},{"text":"Or we sell to them through a channel.","index":239,"end_time":781.15,"speaker_id":3,"start_time":779.39,"speaker_name":"Rob Schnitzler"},{"text":"The ones that I highlighted in green are larger.","index":240,"end_time":785.47,"speaker_id":3,"start_time":782.03,"speaker_name":"Rob Schnitzler"},{"text":"I''m not sure.","index":241,"end_time":786.83,"speaker_id":3,"start_time":786.11,"speaker_name":"Rob Schnitzler"},{"text":"They''re not on our list of like, hey, here are the top 20 MEP firms.","index":242,"end_time":791.55,"speaker_id":3,"start_time":786.83,"speaker_name":"Rob Schnitzler"},{"text":"Besides the one that was a really good phishing email where it made it seem like they were from EM Core, but they actually weren''t on the Outlook calendar.","index":243,"end_time":800.67,"speaker_id":3,"start_time":791.63,"speaker_name":"Rob Schnitzler"},{"text":"But so this is someone that would be on our list and we would outreach to them EM Core.","index":244,"end_time":807.23,"speaker_id":3,"start_time":801.87,"speaker_name":"Rob Schnitzler"},{"text":"The other ones in green are like, in our target core market for direct, but they''re maybe like, smaller and they weren''t on our top 20 list, but it''s still good and kind of have the team re reaching out to them.","index":245,"end_time":821.55,"speaker_id":3,"start_time":807.55,"speaker_name":"Rob Schnitzler"},{"text":"So that just kind of.","index":246,"end_time":823.75,"speaker_id":3,"start_time":822.75,"speaker_name":"Rob Schnitzler"},{"text":"These kind of show you some of the n. Like beyond some of the segmentation we''ve done.","index":247,"end_time":828.75,"speaker_id":3,"start_time":823.75,"speaker_name":"Rob Schnitzler"},{"text":"Like, these are the interesting.","index":248,"end_time":830.59,"speaker_id":3,"start_time":828.75,"speaker_name":"Rob Schnitzler"},{"text":"Anything.","index":249,"end_time":831.23,"speaker_id":3,"start_time":830.67,"speaker_name":"Rob Schnitzler"},{"text":"Anything that''s highlighted are kind of like the interesting names for us, and we potentially, you know, could target more and stuff like that going forward.","index":250,"end_time":840.27,"speaker_id":3,"start_time":831.55,"speaker_name":"Rob Schnitzler"},{"text":"Okay, that''s all good to know.","index":251,"end_time":846.75,"speaker_id":0,"start_time":843.31,"speaker_name":"Nathalie Mintjens"},{"text":"And what do the yellow ones mean?","index":252,"end_time":849.87,"speaker_id":0,"start_time":848.19,"speaker_name":"Nathalie Mintjens"},{"text":"The yellow, it''s like, it''s.","index":253,"end_time":852.67,"speaker_id":3,"start_time":850.75,"speaker_name":"Rob Schnitzler"},{"text":"It''s less interesting for, like, our direct service model and.","index":254,"end_time":858.19,"speaker_id":3,"start_time":853.63,"speaker_name":"Rob Schnitzler"},{"text":"And more just like, actually stuff I highlighted for, like, there were a number of prefab companies and I was highlighting it to show Derek, like, hey, there''s this segment of the market that''s doing inbound.","index":255,"end_time":870.3,"speaker_id":3,"start_time":858.26,"speaker_name":"Rob Schnitzler"},{"text":"We''re not really serving it like.","index":256,"end_time":872.26,"speaker_id":3,"start_time":870.3,"speaker_name":"Rob Schnitzler"},{"text":"So the yellow is more like annotations for rugged and like, things we should think about, potential partners, et cetera.","index":257,"end_time":881.38,"speaker_id":3,"start_time":872.9,"speaker_name":"Rob Schnitzler"},{"text":"Where the green stuff is more like, hey, these are direct customers that we would target and kind of go after.","index":258,"end_time":888.08,"speaker_id":3,"start_time":881.38,"speaker_name":"Rob Schnitzler"},{"text":"Got it.","index":259,"end_time":890,"speaker_id":0,"start_time":889.36,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":260,"end_time":891.44,"speaker_id":0,"start_time":890.88,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah.","index":261,"end_time":892.36,"speaker_id":0,"start_time":892,"speaker_name":"Nathalie Mintjens"},{"text":"And we''ll.","index":262,"end_time":893.04,"speaker_id":0,"start_time":892.36,"speaker_name":"Nathalie Mintjens"},{"text":"We''ll get that HubSpot form updated so that you get notifications for every submission too.","index":263,"end_time":899.28,"speaker_id":0,"start_time":893.6,"speaker_name":"Nathalie Mintjens"},{"text":"Awesome.","index":264,"end_time":900.8,"speaker_id":3,"start_time":900.24,"speaker_name":"Rob Schnitzler"},{"text":"All right.","index":265,"end_time":903.92,"speaker_id":0,"start_time":903.28,"speaker_name":"Nathalie Mintjens"},{"text":"And then also just wanted to note the other ideas that we talked about here.","index":266,"end_time":910.36,"speaker_id":0,"start_time":905.2,"speaker_name":"Nathalie Mintjens"},{"text":"There''s no action items for these just yet, but I know you wanted to talk to your team about some of them.","index":267,"end_time":915.69,"speaker_id":0,"start_time":910.36,"speaker_name":"Nathalie Mintjens"},{"text":"Like, thinking about the passive targets, the ABM Do Not Contact lists, and then also setting up a new LinkedIn ad campaign to target the people that you''re doing direct outreach to.","index":268,"end_time":926.09,"speaker_id":0,"start_time":916.17,"speaker_name":"Nathalie Mintjens"},{"text":"Okay, awesome.","index":269,"end_time":930.01,"speaker_id":3,"start_time":927.05,"speaker_name":"Rob Schnitzler"},{"text":"I think let''s.","index":270,"end_time":933.45,"speaker_id":3,"start_time":932.57,"speaker_name":"Rob Schnitzler"},{"text":"I''ll send you the do not contact list in HubSpot.","index":271,"end_time":940.81,"speaker_id":3,"start_time":938.41,"speaker_name":"Rob Schnitzler"},{"text":"It''s like seven people.","index":272,"end_time":942.21,"speaker_id":3,"start_time":940.81,"speaker_name":"Rob Schnitzler"},{"text":"I think it''s.","index":273,"end_time":946.77,"speaker_id":3,"start_time":946.05,"speaker_name":"Rob Schnitzler"},{"text":"I think the whole thing was waste of time, but whatever I''ll send you that.","index":274,"end_time":950.85,"speaker_id":3,"start_time":946.85,"speaker_name":"Rob Schnitzler"},{"text":"And then I. I don''t have the bandwidth to, like, think about these, so let''s just leave it for.","index":275,"end_time":957.33,"speaker_id":3,"start_time":950.93,"speaker_name":"Rob Schnitzler"},{"text":"Let''s leave it for next time.","index":276,"end_time":958.93,"speaker_id":3,"start_time":957.57,"speaker_name":"Rob Schnitzler"},{"text":"We''ll have another two weeks of ABM results.","index":277,"end_time":961.97,"speaker_id":3,"start_time":959.65,"speaker_name":"Rob Schnitzler"},{"text":"Our team will have another two weeks of reaching out to people, and I''ll be past the board meeting, so I''ll kind of be able to refocus on it.","index":278,"end_time":970.89,"speaker_id":3,"start_time":962.85,"speaker_name":"Rob Schnitzler"},{"text":"Sounds good.","index":279,"end_time":972.73,"speaker_id":0,"start_time":972.01,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":280,"end_time":974.93,"speaker_id":0,"start_time":974.49,"speaker_name":"Nathalie Mintjens"},{"text":"That was everything that I had.","index":281,"end_time":976.09,"speaker_id":0,"start_time":974.93,"speaker_name":"Nathalie Mintjens"},{"text":"Was there anything else you wanted to discuss?","index":282,"end_time":977.77,"speaker_id":0,"start_time":976.09,"speaker_name":"Nathalie Mintjens"},{"text":"No, this is.","index":283,"end_time":982.97,"speaker_id":3,"start_time":979.21,"speaker_name":"Rob Schnitzler"},{"text":"This is super helpful.","index":284,"end_time":984.61,"speaker_id":3,"start_time":983.61,"speaker_name":"Rob Schnitzler"},{"text":"I''m really excited about the website.","index":285,"end_time":986.97,"speaker_id":3,"start_time":984.61,"speaker_name":"Rob Schnitzler"},{"text":"Like, I.","index":286,"end_time":987.69,"speaker_id":3,"start_time":987.05,"speaker_name":"Rob Schnitzler"},{"text":"It took me forever to get going, and then, like, I got going and I had momentum, and now I''m, like, upset that I don''t have moment meta, so.","index":287,"end_time":995.88,"speaker_id":3,"start_time":987.85,"speaker_name":"Rob Schnitzler"},{"text":"No worries.","index":288,"end_time":998.44,"speaker_id":0,"start_time":997.72,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah, but we''ll.","index":289,"end_time":1000.72,"speaker_id":0,"start_time":1000.04,"speaker_name":"Nathalie Mintjens"},{"text":"We''ll get those case studies on, and then whenever you have a chance to do the rest of the reviews, then we''ll get it updated from there.","index":290,"end_time":1007,"speaker_id":0,"start_time":1000.72,"speaker_name":"Nathalie Mintjens"},{"text":"Okay, awesome.","index":291,"end_time":1009.48,"speaker_id":3,"start_time":1007.88,"speaker_name":"Rob Schnitzler"},{"text":"Sounds great.","index":292,"end_time":1010.2,"speaker_id":3,"start_time":1009.48,"speaker_name":"Rob Schnitzler"},{"text":"Thank you all.","index":293,"end_time":1011,"speaker_id":3,"start_time":1010.2,"speaker_name":"Rob Schnitzler"},{"text":"All right, thank you.","index":294,"end_time":1013.16,"speaker_id":0,"start_time":1011.64,"speaker_name":"Nathalie Mintjens"},{"text":"See ya.","index":295,"end_time":1014.24,"speaker_id":2,"start_time":1013.64,"speaker_name":"Baylee Gunnell"},{"text":"Bye.","index":296,"end_time":1014.68,"speaker_id":3,"start_time":1014.24,"speaker_name":"Rob Schnitzler"},{"text":"Bye.","index":297,"end_time":1015.56,"speaker_id":2,"start_time":1015.08,"speaker_name":"Baylee Gunnell"}],"dateString":"2026-02-04T15:00:00.000Z","host_email":"tristan.pelligrino@marketersindemand.com","meeting_link":"https://us02web.zoom.us/j/84801960534?pwd=tq9BFJBUCprJPJ0W7NRoAlJYH7bZXD.1","participants":["rob@rugged-robotics.com,tristan.pelligrino@marketersindemand.com,baylee.gunnell@marketersindemand.com,nathalie.mintjens@marketersindemand.com","rob@rugged-robotics.com","baylee.gunnell@marketersindemand.com","nathalie.mintjens@marketersindemand.com"],"transcript_url":"https://app.fireflies.ai/view/01KG33WXAXHCRDV7YHTM6SQN9C","organizer_email":"tristan.pelligrino@marketersindemand.com"}'::jsonb,
    '{"label":"positive","confidence":0.92,"bullets":["Reviewed website updates; Demir finalized requested changes including meet Rugged section and footer nav.","Rob confirmed only one or two items remain for Demir; rest he can handle directly.","Redesigned PDF case studies to be developed on staging site following Rob''s approval.","ABM campaign yielded over 1,000 leads; tracking sheet now segments by engagement frequency.","Team to update HubSpot form notifications so Rob receives all new lead alerts."],"highlights":[{"quote":"This is awesome. I really appreciate this.","speaker":"Rob Schnitzler"},{"quote":"I''m really excited about the website.","speaker":"Rob Schnitzler"},{"quote":"Those trends can be really helpful, but the actual number might not always be 100% true.","speaker":"Baylee Gunnell"}],"topics":["website","ABM","leads","delivery"],"model":"openai/gpt-4","version":1,"generated_at":"2026-02-06T00:00:00Z"}'::jsonb,
    '{"fireflies_summary":{"notes":"## **Website Updates and Content Development**\n\nThe website updates have been largely completed, with a few final tweaks pending to ensure consistency and usability.\n\n- **Demir completed the latest round of website updates**, including the About tab with a new \"Meet Rugged\" section and consistent styling across pages (04:01)  \n    - The use cases section was reordered and one was removed per Rob’s feedback  \n    - Rob plans to finish minor text and photo edits himself due to limited time before the board meeting  \n    - The footer navigation alignment issue was noted and will be fixed later to match the existing site’s layout  \n    - The case studies PDFs have been redesigned and are ready for deployment on the staging site once Rob confirms (06:13)  \n\n- **Rob confirmed the redesigned case studies PDFs cover all current content**, with a new PDF expected soon to add to the system (06:29)  \n    - Nathalie will proceed to develop these PDFs on the staging site without waiting for individual reviews  \n    - This system aims to speed up future updates and maintain consistency across case studies  \n\n## **Account-Based Marketing (ABM) Performance and Lead Management**\n\nThe ABM email campaign continues to perform steadily, with ongoing efforts to nurture engaged contacts and refine lead handling processes.\n\n- **Since the last meeting, 1,074 leads were contacted via email, maintaining strong open and click rates** (07:23)  \n    - Nathalie created an email open tracking sheet showing individual contact engagement in January 2026 for monthly review  \n    - Rob and team may integrate this tracking into HubSpot to focus nurturing on highly engaged leads  \n    - Baylee cautioned that open counts can be inflated by automated systems, so trends matter more than raw numbers (08:33)  \n\n- **Paid media efforts in January yielded six Google search ad conversions and three LinkedIn conversions** (09:26)  \n    - Rob is reviewing lead annotation lists to identify high-value prospects and refine targeting  \n    - He highlighted green-coded leads as potential direct customers and yellow-coded leads as partner or secondary market prospects (13:11)  \n    - Rob emphasized the need to update HubSpot notifications so he receives all lead form submissions promptly for better tracking and responsiveness (11:42)  \n\n## **Lead Notification and Response Process Improvements**\n\nThere is a need to enhance the lead notification system and clarify lead response roles to improve follow-up efficiency.\n\n- **Tristan confirmed LinkedIn leads come through website HubSpot forms, which currently lack full notification coverage for Rob’s team** (10:17)  \n    - The HubSpot form notifications will be updated to include Rob and others on the alert list immediately after the meeting (11:42)  \n    - Rob suspects internal follow-up gaps and some lead noise contribute to missed responses, not vendor issues (10:39)  \n    - The team agreed to monitor lead quality and adjust outreach focus accordingly, especially filtering out lower-value Gmail leads (12:44)  \n\n## **Strategic ABM Initiatives and Next Steps**\n\nThe team will pause new ABM expansions until after the board meeting, focusing on current outreach and refining lead segmentation.\n\n- **Rob will share a “Do Not Contact” list of about seven contacts to exclude from ABM efforts** (15:27)  \n    - No immediate action on new LinkedIn ad campaigns or additional passive target lists until after the board meeting workload eases  \n    - The plan is to review two more weeks of ABM results before deciding on further ABM refinements or expansions (15:50)  \n    - This approach prioritizes bandwidth management and ensures focus on high-value leads and campaigns  \n\n## **Overall Team Sentiment and Forward Momentum**\n\nThe team is aligned and optimistic about progress, with clear next steps to maintain momentum post-board meeting.\n\n- **Rob expressed excitement about the website progress and momentum despite recent time constraints** (16:19)  \n    - Nathalie reassured that case studies deployment will proceed and further updates will be made after Rob’s review  \n    - The team agreed to reconvene after the board meeting to refocus on ABM and website content updates (16:37)","outline":null,"keywords":["Website Updates","Case Studies","ABM Reporting","Lead Nurturing","HubSpot Forms","Paid Media Conversions"],"overview":"- **Website Updates Near Completion:** Final tweaks to website almost done; case studies redesign ready for deployment after Rob''s confirmation.  \n- **ABM Campaign Performance Steady:** 1,074 leads contacted; email engagement tracked for review; focus on high-value leads.  \n- **Lead Notification Gaps Identified:** Current HubSpot forms lack full notifications; updates planned for improved tracking and response.  \n- **Pause on New ABM Initiatives:** No new campaigns until after the board meeting; focus on existing outreach and lead quality.  \n- **Team Optimistic About Progress:** General excitement about website and ABM initiatives, with plans for follow-up post-board meeting.","action_items":"\n**Rob Schnitzler**\nComplete final text and photo updates on the website homepage and other pages as time permits (04:57)\nProvide upcoming case study PDF for upload and systematize rapid case study updates (07:11)\nAnnotate and send “Do Not Contact” list for HubSpot to Nathalie (15:12)\nReview ABM progress after board meeting and prepare for next steps on LinkedIn campaign and contact lists (15:27)\n\n**Nathalie Mintjens**\nDevelop redesigned case study PDFs on the staging site (07:17)\nSend email open tracking sheet to Rob monthly to support nurture efforts (08:11)\nUpdate HubSpot forms to ensure Rob and his team receive lead notifications (14:49)\n\n**Tristan Pelligrino**\nCheck and adjust HubSpot form notifications to include Rob and relevant stakeholders on lead submissions (11:30)\n\n**Baylee Gunnell**\nShare an article on email open data reliability with Rob for reference (08:33)\n"},"migrated_from":"contract_meetings","original_id":"28c34411-f5e6-4b4b-b306-242e99f1d32c","master_marketer":{"status":"migrated"}}'::jsonb,
