-- Meeting: PTO Exchange // New North Weekly Meeting (2026-02-05 18:30:00+00)
WITH new_meeting AS (
  INSERT INTO compass_meetings (contract_id, meeting_date, source, external_id, title, participants, duration_seconds, recording_url, transcript, sentiment, raw_metadata, created_at, updated_at)
  VALUES (
    '3f032f15-833e-4d7d-9347-381febf6d953',
    '2026-02-05 18:30:00+00',
    'fireflies',
    '01KG5NMVW7X36QAB907SSC6JMD',
    'PTO Exchange // New North Weekly Meeting',
    '{"Rob Whalen","Josh Reinhard","Colin Costigan","Nathalie Mintjens","Nina Belina","Dan Igo","Carmen Williams","Stephanie Lucchesi"}'::text[],
    3254,
    'https://us02web.zoom.us/j/87477024015?pwd=gVpnKPDuNsoZ0giaFoA7gicVcI6afV.1',
    '{"id":"01KG5NMVW7X36QAB907SSC6JMD","title":"PTO Exchange // New North Weekly Meeting","summary":{"notes":"## **HubSpot Audit and Database Cleanup**\n\nThe team agreed to start with a three-phase HubSpot audit focused on cleaning and optimizing data for better marketing and sales alignment.\n\n- **Phase one involves database integrity work, where the PTO Exchange team will classify HubSpot properties into keep, archive, or delete categories based on current use and trustworthiness, following an export of all custom properties led by Nathalie Mintjens** (04:58)\n    - Colin Costigan emphasized the importance of involving Sam for historical context on some fields to avoid losing critical data.\n    - The goal is to remove irrelevant or unused properties to streamline focus on data that truly supports sales and marketing efforts.\n    - This cleanup is foundational to improving reporting and attribution in later phases.\n    - Josh Reinhard will coordinate with the team to review the exported list immediately after the meeting.\n\n- **Phase two will establish trusted attribution sources within HubSpot, setting the stage for accurate lead tracking and campaign measurement** (06:58)\n    - This step is key to understanding marketing impact across channels.\n    - Carmen Williams confirmed this audit is part of ongoing efforts, not a separate initiative.\n    - Clear attribution will aid in aligning marketing spend with business results.\n\n- **Phase three focuses on defining lifecycle stages such as lead, MQL, SQL, and opportunity, and implementing workflows to automate these transitions** (07:52)\n    - This will enable consistent lead management and enhance funnel visibility.\n    - Colin Costigan will lead this effort with support from Natalie Mintjens and Nina Belina to ensure smooth execution.\n    - The team plans regular calls including Sam, balancing east coast time zones, to maintain alignment and minimize rework.\n    - Incoming HubSpot issues or anomalies will be reported via Slack for prompt fixes, exemplified by a recent workflow misassignment corrected to route leads to the proper owner, Stephanie Lucchesi.\n\n## **Marketing Campaign Performance and Reporting**\n\nThe team is seeing promising results on LinkedIn campaigns and aims to expand data visibility to optimize spend and strategy.\n\n- **Recent LinkedIn ads generated four leads from the Unlock the Power of PTO campaign, with the Reimagine Your PTO Program ad performing best across LinkedIn and AdRoll, sustaining a steady 0.10% click-through rate on AdRoll** (09:01)\n    - Nathalie Mintjens recommended A/B testing different introductory texts while keeping the same creative image to further improve engagement.\n    - Carmen Williams requested faster access to overall campaign performance and cost-per-lead data before the full attribution reporting is finalized.\n    - Colin Costigan proposed updating HubSpot’s internal reports and enhancing a live DataBox dashboard aggregating LinkedIn, Google Analytics, and other platforms for real-time cost and lead metrics.\n    - The team agreed to schedule offline deep dives on reporting concurrently with the database cleanup to accelerate insights.\n\n## **Branding, Content Strategy, and ABM Development**\n\nA strategic shift is underway to deepen emotional connection with prospects and evolve account-based marketing efforts.\n\n- **Carmen Williams outlined a vision to move PTO Exchange’s brand from product-focused messaging to a more emotional, audience-centered approach, aiming to increase engagement and momentum across the full marketing funnel** (33:49)\n    - The plan includes completing a content audit by persona, industry, and account to identify gaps and opportunities.\n    - She is developing detailed personas with input from sales to underpin refined positioning and messaging frameworks.\n    - The brand evolution will incorporate more human elements and storytelling to build trust at scale.\n\n- **A significant ABM initiative will progress from current lightweight segmentation to a robust one-to-one and one-to-few model, targeting named accounts and clusters with tailored campaigns** (38:00)\n    - Carmen will create the ABM strategy and content plan, working closely with Josh Reinhard and the team to integrate these accounts into HubSpot properly.\n    - Natalie Mintjens will act as the point person for ABM execution, coordinating data imports and campaign setup using tools like ZoomInfo.\n    - The team recognizes the need for proper CRM pipelines and segmentation to track campaigns from engagement through close.\n\n- **Website and SEO efforts will support brand and ABM goals by improving UX and optimizing pillar content for both search engines and human connection, including AI-driven content opportunities** (48:30)\n    - Nina Belina stressed starting with an SEO audit to guide website updates and new content priorities.\n    - Carmen expressed interest in proposals for SEO and AI initiatives but noted these are not immediate priorities.\n    - Sam will continue managing blog and social posts under a defined framework to maintain content consistency.\n\n## **Process Alignment, Workflow Improvements, and Meeting Cadence**\n\nThe team is refining internal processes and communication rhythms to increase efficiency and clarity.\n\n- **The Monday standing call will be removed to reduce unnecessary meetings, with Thursday calls and biweekly strategy sessions remaining for focused updates and deep dives** (24:40)\n    - Carmen prefers fewer meetings for the New North team, wanting work delivered rather than discussed extensively.\n    - Josh Reinhard will remain involved in tactical discussions where his sales pipeline knowledge is critical, like custom fields in HubSpot.\n    - Carmen will lead biweekly strategy meetings post this call, inviting Josh, Rob, and others as needed for input or presentations.\n\n- **Lead management workflows in HubSpot are being reviewed and corrected to ensure leads route properly, as highlighted by a recent misassignment where a task meant for Stephanie Lucchesi was incorrectly assigned to John Randall’s workflow** (12:30)\n    - Colin Costigan committed to adjusting workflows promptly upon receiving reports via Slack.\n    - This approach establishes a quick feedback and fix loop to reduce lead handling errors.\n    - The team agreed that all HubSpot issues should be reported in the Slack channel for immediate attention.\n\n- **File management for marketing assets like flyers will be improved by organizing existing Figma files spatially and logically, with files shared into PTO Exchange’s Figma account for easier access and replication** (16:25)\n    - Natalie Mintjens will reorganize the current Figma files to group related assets like case studies and client flyers.\n    - Carmen indicated a possible future shift from Figma to Canva for ease of use by non-designers, but the immediate priority is better file organization.\n    - This will allow the PTO Exchange team to quickly modify templates and deploy assets for multiple clients without delays.\n\n## **Long-Term Vision and Investment Planning**\n\nThe team is focused on enabling growth through data-driven marketing investments and stronger brand positioning.\n\n- **Carmen Williams is pushing to prove marketing campaign results to secure increased top-of-funnel budget, aiming for a target spend near $600,000, emphasizing full-funnel growth rather than bottom-funnel optimization alone** (33:00)\n    - The plan includes fixing lifecycle governance and lead management processes before scaling spend.\n    - A detailed SWOT analysis and competitive alternative review will clarify PTO Exchange’s unique value and positioning.\n    - Messaging frameworks and brand guidelines will be finalized within six to eight weeks to standardize communications across channels.\n\n- **There is a clear intent to develop forecasting tools and reporting confidence so that incremental marketing investments can be justified by predictable lead and revenue growth** (44:30)\n    - Carmen wants to map spend to lead volume and quality to build trust with leadership on budget increases.\n    - This will require ongoing collaboration between marketing, sales, and analytics teams to maintain data integrity and alignment.\n    - The team is committed to evolving from tactical fixes to strategic, scalable marketing operations.\n\n- **Ongoing content evolution includes exploring podcast opportunities as a thought leadership and ABM engagement tool by inviting target healthcare executives to participate, blending content marketing with direct account outreach** (41:40)\n    - Nathalie Mintjens confirmed this can integrate with ABM campaigns as an additional engagement layer.\n    - This approach aims to humanize the brand and create meaningful connections with key decision-makers.\n    - Carmen plans to review early podcast experiments to identify areas for expansion.","outline":null,"keywords":["HubSpot audit","ABM strategy","Marketing funnel","Campaign reporting","SEO audit","Brand messaging"],"overview":"- **HubSpot Audit Plan:** Three-phase cleanup to optimize data by identifying relevant properties via a comprehensive audit process.  \n- **Marketing Performance Insights:** LinkedIn campaign generated 4 leads; focus on A/B testing and real-time reporting for better campaign strategies.  \n- **Branding Evolution:** Shift to emotional, audience-centered messaging; detailed personas to guide positioning and engagement strategies.  \n- **ABM Initiative Development:** Transition to robust targeting with tailored campaigns; coordination needed for proper integration into HubSpot.  \n- **Workflow Improvements:** Removal of unnecessary meetings; streamlined lead management and quick response system for HubSpot errors established.  \n- **Growth Strategy Focus:** Aim for $600K top-of-funnel budget; emphasize forecasting and content evolution, including podcast initiatives for engagement.","action_items":"\n**Josh Reinhard**\nReview and provide feedback on upcoming customer flyer assets when delivered (05:18)\nRequest and receive asset links for APM campaigns from Natalie to facilitate review (06:08)\nProvide Sam’s availability for HubSpot historical context meeting (07:26)\nShare legacy lead contact for workflow review with Colin (12:32)\nPost HubSpot-related issues or lead irregularities in Slack channel for timely fixes (14:05)\nDiscuss internally and with Carmen decisions on flyer file storage and design platform (Figma vs. Canva) (16:47)\nCoordinate with Carmen on priorities related to campaign decks and sequences from Dave, funneling through Carmen before New North (27:20)\nProvide input on draft persona development for positioning strategy (38:01)\nCoordinate and send account list for ABM targeting to Carmen and New North (48:20)\nAssist Natalie in collecting correct account/contact data for ABM in HubSpot (52:52)\n\n**Carmen Williams**\nInclude Sam in discussions for historical context on HubSpot properties classification (07:26)\nLead strategy sessions every two weeks post this meeting, extend to weekly if needed, with Natalie and Nina (26:18)\nShare detailed marketing audit and brand evolution plans with New North team for feedback (32:41)\nPerform and finalize persona research; collaborate with Josh and Rob for sales team inputs (38:01)\nDevelop robust ABM strategy and account segmentation plan; work with Josh and New North on HubSpot integration (38:01)\nCoordinate UX and SEO evaluations for phased website improvements (40:18)\nReview AI/SEO proposals from New North experts and decide on timing and priority (50:04)\nSet up calendar availability and scheduling methods for ABM and other initiative calls with Natalie (52:08)\nContinue refining brand positioning, messaging framework, and collateral templates for campaign deployment (44:44)\n\n**Colin Costigan**\nExport HubSpot custom properties list; send to PTO Exchange for classification into keep/archive/delete categories immediately after meeting (06:11)\nLead HubSpot clean-up and audit phases; collaborate with Carmen, Natalie, and Nina to implement workflows and attribution fixes (10:36)\nInvestigate legacy workflows causing improper lead assignment; correct task allocation issues to Stephanie (12:32)\nCoordinate scheduling and invite Sam for HubSpot historical context calls (07:26)\nParticipate in reporting setup using HubSpot and data dashboards to improve visibility on campaign KPIs (15:45)\nSupport transition and organization of Figma assets for templates as requested (19:40)\nFacilitate meetings and walk-throughs step-by-step to ensure alignment on HubSpot and funnel processes (11:04)\n\n**Nathalie Mintjens**\nDeliver next two customer flyer assets (cash out and charitable giving) per approved templates (05:18)\nProvide links to all APM campaign assets and add flyer templates to PTO Exchange Figma account; organize Figma assets for better accessibility (06:11)\nServe as point person and calendar contact for ABM initiative coordination with Carmen and Josh (52:08)\nAssist with SEO audit and AI integration proposal development via New North’s expert resources (50:04)\nCollaborate with team on database cleanup and reporting improvement workflows (06:11)\n\n**Nina Belina**\nSupport website UX evaluations and SEO audit recommendations (40:18)\nProvide insights on AI integration and SEO improvements in coordination with Nathalie (50:04)\n"},"duration":54.2400016784668,"speakers":[{"id":0,"name":"Rob Whalen"},{"id":1,"name":"Josh Reinhard"},{"id":2,"name":"Colin Costigan"},{"id":3,"name":"Nathalie Mintjens"},{"id":4,"name":"Nina Belina"},{"id":5,"name":"Dan Igo"},{"id":6,"name":"Carmen Williams"},{"id":7,"name":"Stephanie Lucchesi"}],"sentences":[{"text":"Okay.","index":0,"end_time":199.67,"speaker_id":0,"start_time":199.43,"speaker_name":"Rob Whalen"},{"text":"What''s up, Colin?","index":1,"end_time":200.39,"speaker_id":1,"start_time":199.67,"speaker_name":"Josh Reinhard"},{"text":"How''s it going?","index":2,"end_time":201.27,"speaker_id":2,"start_time":200.55,"speaker_name":"Colin Costigan"},{"text":"Good.","index":3,"end_time":201.91,"speaker_id":1,"start_time":201.59,"speaker_name":"Josh Reinhard"},{"text":"How you doing?","index":4,"end_time":202.47,"speaker_id":1,"start_time":201.91,"speaker_name":"Josh Reinhard"},{"text":"Doing all right.","index":5,"end_time":203.83,"speaker_id":2,"start_time":202.95,"speaker_name":"Colin Costigan"},{"text":"How about you guys?","index":6,"end_time":208.24,"speaker_id":2,"start_time":207.36,"speaker_name":"Colin Costigan"},{"text":"Doing okay.","index":7,"end_time":212.64,"speaker_id":1,"start_time":211.76,"speaker_name":"Josh Reinhard"},{"text":"Got a bug in in our house that just won''t leave.","index":8,"end_time":216.88,"speaker_id":1,"start_time":213.76,"speaker_name":"Josh Reinhard"},{"text":"I have feeling the next week my youngest son had it.","index":9,"end_time":222.8,"speaker_id":1,"start_time":218.48,"speaker_name":"Josh Reinhard"},{"text":"This week my middle guy has it.","index":10,"end_time":225.2,"speaker_id":1,"start_time":222.88,"speaker_name":"Josh Reinhard"},{"text":"We just can''t all get sick at once, so we have to just drag it out.","index":11,"end_time":230.16,"speaker_id":1,"start_time":226.4,"speaker_name":"Josh Reinhard"},{"text":"Yeah, I think me and my daughter passing it back and forth.","index":12,"end_time":233.51,"speaker_id":2,"start_time":230.79,"speaker_name":"Colin Costigan"},{"text":"Nice.","index":13,"end_time":234.87,"speaker_id":1,"start_time":234.39,"speaker_name":"Josh Reinhard"},{"text":"Never fun.","index":14,"end_time":241.43,"speaker_id":1,"start_time":240.55,"speaker_name":"Josh Reinhard"},{"text":"How''s everyone else doing?","index":15,"end_time":249.19,"speaker_id":2,"start_time":247.91,"speaker_name":"Colin Costigan"},{"text":"Rob, Steph, Curry, Dan.","index":16,"end_time":251.27,"speaker_id":2,"start_time":249.35,"speaker_name":"Colin Costigan"},{"text":"Good to see all you guys.","index":17,"end_time":252.31,"speaker_id":2,"start_time":251.27,"speaker_name":"Colin Costigan"},{"text":"Good.","index":18,"end_time":252.99,"speaker_id":0,"start_time":252.63,"speaker_name":"Rob Whalen"},{"text":"Busy.","index":19,"end_time":253.51,"speaker_id":0,"start_time":252.99,"speaker_name":"Rob Whalen"},{"text":"Awesome.","index":20,"end_time":255.03,"speaker_id":2,"start_time":254.39,"speaker_name":"Colin Costigan"},{"text":"It''s busy season.","index":21,"end_time":256.07,"speaker_id":2,"start_time":255.19,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":22,"end_time":257.33,"speaker_id":0,"start_time":257.05,"speaker_name":"Rob Whalen"},{"text":"Getting ready for everyone to come into town, so just, you know, got to get everything put together.","index":23,"end_time":263.05,"speaker_id":0,"start_time":257.33,"speaker_name":"Rob Whalen"},{"text":"Yeah.","index":24,"end_time":263.93,"speaker_id":0,"start_time":263.45,"speaker_name":"Rob Whalen"},{"text":"Awesome.","index":25,"end_time":265.93,"speaker_id":0,"start_time":265.29,"speaker_name":"Rob Whalen"},{"text":"All right, well, sorry, Robert, were you about to chime in with something else?","index":26,"end_time":269.69,"speaker_id":2,"start_time":265.93,"speaker_name":"Colin Costigan"},{"text":"Nope.","index":27,"end_time":270.97,"speaker_id":0,"start_time":270.41,"speaker_name":"Rob Whalen"},{"text":"Oh, okay.","index":28,"end_time":271.69,"speaker_id":2,"start_time":270.97,"speaker_name":"Colin Costigan"},{"text":"Awesome.","index":29,"end_time":273.01,"speaker_id":2,"start_time":272.57,"speaker_name":"Colin Costigan"},{"text":"Well, Carmen and Nina and Natalie have been doing some great things and We''ve got some HubSpot report and audit updates, and we want to talk through all that structure and how everything''s going to come together to match up with Carmen''s vision.","index":30,"end_time":286.01,"speaker_id":2,"start_time":273.01,"speaker_name":"Colin Costigan"},{"text":"So without further ado, I''ll toss it over to Nina and Natalie.","index":31,"end_time":289.64,"speaker_id":2,"start_time":286.01,"speaker_name":"Colin Costigan"},{"text":"Okay, so just to quickly go over some of the website projects and content.","index":32,"end_time":302.68,"speaker_id":3,"start_time":296.76,"speaker_name":"Nathalie Mintjens"},{"text":"So, Josh, for the customer flyers.","index":33,"end_time":305.88,"speaker_id":3,"start_time":303.16,"speaker_name":"Nathalie Mintjens"},{"text":"So next up, we''re going to deliver the cash out one and charitable giving.","index":34,"end_time":310.28,"speaker_id":3,"start_time":306.52,"speaker_name":"Nathalie Mintjens"},{"text":"So we''ll follow the same style template that we used for the other two.","index":35,"end_time":314.2,"speaker_id":3,"start_time":310.92,"speaker_name":"Nathalie Mintjens"},{"text":"Just wanted to check if you''re still.","index":36,"end_time":316.33,"speaker_id":3,"start_time":314.68,"speaker_name":"Nathalie Mintjens"},{"text":"Still going to leave feedback on these ones or.","index":37,"end_time":318.64,"speaker_id":3,"start_time":316.48,"speaker_name":"Nathalie Mintjens"},{"text":"They look.","index":38,"end_time":319.28,"speaker_id":4,"start_time":318.72,"speaker_name":"Nina Belina"},{"text":"They were like, great as is.","index":39,"end_time":321.12,"speaker_id":1,"start_time":319.68,"speaker_name":"Josh Reinhard"},{"text":"We presented them to the client.","index":40,"end_time":322.4,"speaker_id":1,"start_time":321.12,"speaker_name":"Josh Reinhard"},{"text":"They love them.","index":41,"end_time":323.04,"speaker_id":1,"start_time":322.4,"speaker_name":"Josh Reinhard"},{"text":"Yeah, they love them, so it''s great.","index":42,"end_time":325.76,"speaker_id":5,"start_time":323.36,"speaker_name":"Dan Igo"},{"text":"Okay, cool.","index":43,"end_time":328,"speaker_id":3,"start_time":327.04,"speaker_name":"Nathalie Mintjens"},{"text":"So I''ll deliver the next two and then we are working on updating the industry pages and the other pages that you had left feedback on.","index":44,"end_time":339.36,"speaker_id":3,"start_time":328.8,"speaker_name":"Nathalie Mintjens"},{"text":"And then once that''s done, we''re going to get them developed.","index":45,"end_time":343.04,"speaker_id":3,"start_time":340.08,"speaker_name":"Nathalie Mintjens"},{"text":"And then we also have it on our list to work with Carmen to decide on the updated navigation and site map for the website.","index":46,"end_time":352.22,"speaker_id":3,"start_time":344.06,"speaker_name":"Nathalie Mintjens"},{"text":"And then we have a couple more assets that are still in review with your team.","index":47,"end_time":357.5,"speaker_id":3,"start_time":353.26,"speaker_name":"Nathalie Mintjens"},{"text":"These are all of the assets that are going to go along with the new APM campaigns.","index":48,"end_time":362.3,"speaker_id":3,"start_time":357.82,"speaker_name":"Nathalie Mintjens"},{"text":"So just let me know if you need the links to these again and I can send them over.","index":49,"end_time":366.62,"speaker_id":3,"start_time":363.02,"speaker_name":"Nathalie Mintjens"},{"text":"If you could send the links, yeah, that''d be great.","index":50,"end_time":370.62,"speaker_id":1,"start_time":368.3,"speaker_name":"Josh Reinhard"},{"text":"Okay, will do.","index":51,"end_time":373.01,"speaker_id":3,"start_time":371.49,"speaker_name":"Nathalie Mintjens"},{"text":"And then the HubSpot audit.","index":52,"end_time":378.01,"speaker_id":3,"start_time":376.29,"speaker_name":"Nathalie Mintjens"},{"text":"So after the meeting last week, we essentially put this into three different phases of how we think we should tackle this to get everything updated.","index":53,"end_time":387.169,"speaker_id":3,"start_time":378.01,"speaker_name":"Nathalie Mintjens"},{"text":"So first thing here is phase one is doing database integrity.","index":54,"end_time":392.01,"speaker_id":3,"start_time":387.89,"speaker_name":"Nathalie Mintjens"},{"text":"So this is where we clean the properties in HubSpot and then I''ve listed out here all the steps that we''d like to take.","index":55,"end_time":398.45,"speaker_id":3,"start_time":392.01,"speaker_name":"Nathalie Mintjens"},{"text":"So essentially what we do is export all of the custom properties that exist in HubSpot right now.","index":56,"end_time":404.03,"speaker_id":3,"start_time":398.45,"speaker_name":"Nathalie Mintjens"},{"text":"And then what we need the PTO exchange team to do is classify each of them into properties that you want to keep, properties that you''d like to archive and hide, and then ones that you would later on be okay with deleting.","index":57,"end_time":418.43,"speaker_id":3,"start_time":405.23,"speaker_name":"Nathalie Mintjens"},{"text":"And it''s basically figuring out which data is actually used by your team right now and trusted.","index":58,"end_time":424.59,"speaker_id":3,"start_time":419.15,"speaker_name":"Nathalie Mintjens"},{"text":"And then we can get everything else out of the way to make sure we''re only focusing on the properties that matter.","index":59,"end_time":428.83,"speaker_id":3,"start_time":424.67,"speaker_name":"Nathalie Mintjens"},{"text":"So your team will send over this list, right after this meeting, the exported list of properties, and then your team can look at what must never be removed.","index":60,"end_time":439.76,"speaker_id":3,"start_time":430.24,"speaker_name":"Nathalie Mintjens"},{"text":"Those are properties that you want to keep and then.","index":61,"end_time":442.32,"speaker_id":3,"start_time":439.76,"speaker_name":"Nathalie Mintjens"},{"text":"Which are things that we are okay with getting rid of.","index":62,"end_time":445.44,"speaker_id":3,"start_time":442.8,"speaker_name":"Nathalie Mintjens"},{"text":"And Josh, one thing we were thinking here, and I think Carmen mentioned it last week as well, is this is where it may be helpful to pull Sam into a conversation, just to have more of the historical context of what the intention was for some of these fields.","index":63,"end_time":457.6,"speaker_id":2,"start_time":446.4,"speaker_name":"Colin Costigan"},{"text":"But I''ll leave that up to you guys if you feel that that''s necessary.","index":64,"end_time":461.81,"speaker_id":2,"start_time":458.65,"speaker_name":"Colin Costigan"},{"text":"Or let''s just attack this from our best practices standpoint, build what Carmen''s vision is, and then go from there.","index":65,"end_time":467.05,"speaker_id":2,"start_time":461.81,"speaker_name":"Colin Costigan"},{"text":"And then once we''re done with this phase, second phase is going to be attribution.","index":66,"end_time":476.49,"speaker_id":3,"start_time":472.41,"speaker_name":"Nathalie Mintjens"},{"text":"So establishing trusted sources of attribution within HubSpot.","index":67,"end_time":480.29,"speaker_id":3,"start_time":476.89,"speaker_name":"Nathalie Mintjens"},{"text":"And then after that, we''ll move on to the funnel.","index":68,"end_time":482.25,"speaker_id":3,"start_time":480.29,"speaker_name":"Nathalie Mintjens"},{"text":"This is where we''ll define what is a lead MQL SQL opportunity, and then set up workflows.","index":69,"end_time":488.09,"speaker_id":3,"start_time":482.33,"speaker_name":"Nathalie Mintjens"},{"text":"This is how we''ve mapped the entire audit into actionable steps that we''ll take.","index":70,"end_time":494.38,"speaker_id":3,"start_time":488.7,"speaker_name":"Nathalie Mintjens"},{"text":"Any questions about this?","index":71,"end_time":496.54,"speaker_id":3,"start_time":495.26,"speaker_name":"Nathalie Mintjens"},{"text":"Carmen, any questions on your side?","index":72,"end_time":505.02,"speaker_id":1,"start_time":503.5,"speaker_name":"Josh Reinhard"},{"text":"No.","index":73,"end_time":507.1,"speaker_id":6,"start_time":506.7,"speaker_name":"Carmen Williams"},{"text":"So you''re saying it''s not an extra initiative?","index":74,"end_time":509.58,"speaker_id":6,"start_time":507.1,"speaker_name":"Carmen Williams"},{"text":"This is part of just a ongoing initiative program that we have together.","index":75,"end_time":513.58,"speaker_id":6,"start_time":509.58,"speaker_name":"Carmen Williams"},{"text":"Okay, thank you.","index":76,"end_time":514.7,"speaker_id":6,"start_time":513.58,"speaker_name":"Carmen Williams"},{"text":"Carmen, do you.","index":77,"end_time":516.78,"speaker_id":0,"start_time":515.82,"speaker_name":"Rob Whalen"},{"text":"On the.","index":78,"end_time":517.26,"speaker_id":0,"start_time":516.78,"speaker_name":"Rob Whalen"},{"text":"On the SAM question, do you want SAM in there or do you.","index":79,"end_time":519.54,"speaker_id":0,"start_time":517.26,"speaker_name":"Rob Whalen"},{"text":"Do we just want to move forward with your vision?","index":80,"end_time":521.3,"speaker_id":0,"start_time":519.54,"speaker_name":"Rob Whalen"},{"text":"I mean, that.","index":81,"end_time":522.14,"speaker_id":0,"start_time":521.3,"speaker_name":"Rob Whalen"},{"text":"That''s your call.","index":82,"end_time":522.86,"speaker_id":0,"start_time":522.14,"speaker_name":"Rob Whalen"},{"text":"Yeah, we can probably include him, especially in, like, the background of why some of these fields exist.","index":83,"end_time":529.18,"speaker_id":6,"start_time":523.74,"speaker_name":"Carmen Williams"},{"text":"And that''s the starting point.","index":84,"end_time":530.58,"speaker_id":6,"start_time":529.26,"speaker_name":"Carmen Williams"},{"text":"And then we can.","index":85,"end_time":531.3,"speaker_id":6,"start_time":530.58,"speaker_name":"Carmen Williams"},{"text":"Because I''m still just getting up to speed, so I think it''s a good.","index":86,"end_time":533.66,"speaker_id":6,"start_time":531.3,"speaker_name":"Carmen Williams"},{"text":"Yeah, okay, great.","index":87,"end_time":535.26,"speaker_id":0,"start_time":533.82,"speaker_name":"Rob Whalen"},{"text":"Cool.","index":88,"end_time":538.3,"speaker_id":6,"start_time":537.34,"speaker_name":"Carmen Williams"},{"text":"And then just looking at the data.","index":89,"end_time":542.71,"speaker_id":3,"start_time":541.35,"speaker_name":"Nathalie Mintjens"},{"text":"So just wanted to look over our LinkedIn ads results.","index":90,"end_time":547.03,"speaker_id":3,"start_time":543.75,"speaker_name":"Nathalie Mintjens"},{"text":"So from this past week, we had four leads generated from the Unlock the Power of PTO campaign and across different channels, we''re seeing that the reimagine your PTO program ad is performing the best both on LinkedIn and AdRoll.","index":91,"end_time":562.87,"speaker_id":3,"start_time":547.99,"speaker_name":"Nathalie Mintjens"},{"text":"So what we''d like to do next is lean into that creative more and AAB tests different introductory text on those ads but using the same image.","index":92,"end_time":572.24,"speaker_id":3,"start_time":563.19,"speaker_name":"Nathalie Mintjens"},{"text":"So yeah, we''re seeing positive results.","index":93,"end_time":574.64,"speaker_id":3,"start_time":573.12,"speaker_name":"Nathalie Mintjens"},{"text":"Even on AdRoll, the click through rate is stable at 0.10%.","index":94,"end_time":579.12,"speaker_id":3,"start_time":575.04,"speaker_name":"Nathalie Mintjens"},{"text":"Any questions about these stats?","index":95,"end_time":583.36,"speaker_id":3,"start_time":581.44,"speaker_name":"Nathalie Mintjens"},{"text":"No.","index":96,"end_time":587.52,"speaker_id":0,"start_time":587.12,"speaker_name":"Rob Whalen"},{"text":"No.","index":97,"end_time":588.56,"speaker_id":0,"start_time":588.16,"speaker_name":"Rob Whalen"},{"text":"All right.","index":98,"end_time":592.4,"speaker_id":3,"start_time":591.76,"speaker_name":"Nathalie Mintjens"},{"text":"That was everything we had to cover for this main meeting.","index":99,"end_time":598.01,"speaker_id":3,"start_time":594.49,"speaker_name":"Nathalie Mintjens"},{"text":"Was there anything else you wanted to discuss?","index":100,"end_time":600.57,"speaker_id":3,"start_time":598.09,"speaker_name":"Nathalie Mintjens"},{"text":"No, I just wondering on the.","index":101,"end_time":614.65,"speaker_id":6,"start_time":612.01,"speaker_name":"Carmen Williams"},{"text":"All the work that has to get done around the HubSpot, getting it kind of where we need to get to, you know, I definitely don''t have the HubSpot expertise, so.","index":102,"end_time":625.33,"speaker_id":6,"start_time":614.97,"speaker_name":"Carmen Williams"},{"text":"Who, who on your team?","index":103,"end_time":626.61,"speaker_id":6,"start_time":625.33,"speaker_name":"Carmen Williams"},{"text":"Like it''d be good to have sort of like a project team.","index":104,"end_time":630.13,"speaker_id":6,"start_time":626.77,"speaker_name":"Carmen Williams"},{"text":"Colin, why don''t you.","index":105,"end_time":632.05,"speaker_id":6,"start_time":631.09,"speaker_name":"Carmen Williams"},{"text":"I just would like a little bit more thoughts on how you''re going to hold our hands.","index":106,"end_time":636.53,"speaker_id":6,"start_time":632.05,"speaker_name":"Carmen Williams"},{"text":"Yeah, yeah.","index":107,"end_time":637.41,"speaker_id":2,"start_time":636.77,"speaker_name":"Colin Costigan"},{"text":"So I would be leading the HubSpot part of this.","index":108,"end_time":639.13,"speaker_id":2,"start_time":637.41,"speaker_name":"Colin Costigan"},{"text":"Okay.","index":109,"end_time":639.57,"speaker_id":0,"start_time":639.13,"speaker_name":"Rob Whalen"},{"text":"Yeah.","index":110,"end_time":640.17,"speaker_id":2,"start_time":639.65,"speaker_name":"Colin Costigan"},{"text":"Cool.","index":111,"end_time":640.61,"speaker_id":6,"start_time":640.17,"speaker_name":"Carmen Williams"},{"text":"So basically it''s probably you and me and Natalie and Nina hopping into a call, going through everything.","index":112,"end_time":646.05,"speaker_id":2,"start_time":641.09,"speaker_name":"Colin Costigan"},{"text":"If Sam is there, all the better.","index":113,"end_time":647.73,"speaker_id":2,"start_time":646.05,"speaker_name":"Colin Costigan"},{"text":"If he''s not and we just need to send him like a document to go through, then we can do that as well.","index":114,"end_time":652.47,"speaker_id":2,"start_time":647.73,"speaker_name":"Colin Costigan"},{"text":"But yeah, we''ll be walking through like this step by step to make sure we''re all on the same page because the last thing that we need is like we go off and start building and then we show you halfway and we need to change things.","index":115,"end_time":661.55,"speaker_id":2,"start_time":652.47,"speaker_name":"Colin Costigan"},{"text":"Yeah, yeah.","index":116,"end_time":664.23,"speaker_id":6,"start_time":662.27,"speaker_name":"Carmen Williams"},{"text":"And I think if you''re going to have Sam, it''s going to have to be, you know, because he''s east coast time frame.","index":117,"end_time":668.83,"speaker_id":0,"start_time":664.23,"speaker_name":"Rob Whalen"},{"text":"Yeah, that''s fine.","index":118,"end_time":670.67,"speaker_id":6,"start_time":669.71,"speaker_name":"Carmen Williams"},{"text":"We can, we can meet early in the day, have our work sessions then.","index":119,"end_time":675.23,"speaker_id":6,"start_time":671.07,"speaker_name":"Carmen Williams"},{"text":"Okay.","index":120,"end_time":675.79,"speaker_id":6,"start_time":675.23,"speaker_name":"Carmen Williams"},{"text":"We should check with Sam.","index":121,"end_time":677.59,"speaker_id":1,"start_time":676.43,"speaker_name":"Josh Reinhard"},{"text":"I think sometimes for him it''s easier to meet in the evenings because.","index":122,"end_time":680.11,"speaker_id":1,"start_time":677.59,"speaker_name":"Josh Reinhard"},{"text":"Oh yeah, that''s right.","index":123,"end_time":680.99,"speaker_id":6,"start_time":680.11,"speaker_name":"Carmen Williams"},{"text":"Yeah, yeah, I, I was meeting him at nine, which was his noon or.","index":124,"end_time":686.71,"speaker_id":6,"start_time":682.27,"speaker_name":"Carmen Williams"},{"text":"Yeah, four o''.","index":125,"end_time":687.43,"speaker_id":6,"start_time":686.71,"speaker_name":"Carmen Williams"},{"text":"Clock.","index":126,"end_time":687.59,"speaker_id":6,"start_time":687.43,"speaker_name":"Carmen Williams"},{"text":"Yeah, yeah.","index":127,"end_time":688.51,"speaker_id":6,"start_time":687.59,"speaker_name":"Carmen Williams"},{"text":"Is that, that''ll work for you guys though?","index":128,"end_time":690.59,"speaker_id":6,"start_time":688.83,"speaker_name":"Carmen Williams"},{"text":"Could do though.","index":129,"end_time":691.39,"speaker_id":6,"start_time":690.59,"speaker_name":"Carmen Williams"},{"text":"Because that''s like your evening.","index":130,"end_time":692.83,"speaker_id":6,"start_time":691.39,"speaker_name":"Carmen Williams"},{"text":"Yeah, yeah.","index":131,"end_time":695.15,"speaker_id":2,"start_time":693.79,"speaker_name":"Colin Costigan"},{"text":"I mean it should be totally fine.","index":132,"end_time":696.19,"speaker_id":2,"start_time":695.15,"speaker_name":"Colin Costigan"},{"text":"We''ll, we''ll put together a calendar link and then we can just book like any availability that works for you guys.","index":133,"end_time":700.75,"speaker_id":2,"start_time":696.19,"speaker_name":"Colin Costigan"},{"text":"Just a question.","index":134,"end_time":706.59,"speaker_id":1,"start_time":705.63,"speaker_name":"Josh Reinhard"},{"text":"When things do come up in HubSpot now, like little things like today, it was a, it was a BS lead because the person didn''t put a real name in or.","index":135,"end_time":721.62,"speaker_id":1,"start_time":708.74,"speaker_name":"Josh Reinhard"},{"text":"Or a real company name, but they filled out a form for request, a demo, but they didn''t put in a real email address.","index":136,"end_time":732.06,"speaker_id":1,"start_time":721.62,"speaker_name":"Josh Reinhard"},{"text":"They didn''t put in the real information, but it triggered something that assigned a task to John.","index":137,"end_time":738.65,"speaker_id":1,"start_time":732.06,"speaker_name":"Josh Reinhard"},{"text":"Okay.","index":138,"end_time":741.29,"speaker_id":1,"start_time":740.81,"speaker_name":"Josh Reinhard"},{"text":"So I''m wondering like who.","index":139,"end_time":744.73,"speaker_id":1,"start_time":741.29,"speaker_name":"Josh Reinhard"},{"text":"Who fix that so that it gets sent to Steph even though this, like, it doesn''t matter for this one, but if it did matter.","index":140,"end_time":751.21,"speaker_id":1,"start_time":744.73,"speaker_name":"Josh Reinhard"},{"text":"Yeah, yeah.","index":141,"end_time":752.85,"speaker_id":2,"start_time":752.09,"speaker_name":"Colin Costigan"},{"text":"So anytime, like send us anything that you notice like that.","index":142,"end_time":755.73,"speaker_id":2,"start_time":752.85,"speaker_name":"Colin Costigan"},{"text":"Any question, we''ll dive in right away.","index":143,"end_time":757.29,"speaker_id":2,"start_time":755.73,"speaker_name":"Colin Costigan"},{"text":"Do you have the name of the contact or I can even just go to the latest form fills.","index":144,"end_time":761.17,"speaker_id":2,"start_time":758.25,"speaker_name":"Colin Costigan"},{"text":"I mean, the contact name is like UGTZ N U V W. I was.","index":145,"end_time":767.6,"speaker_id":1,"start_time":761.4,"speaker_name":"Josh Reinhard"},{"text":"Actually curious when you said that, Josh, what the four leads are that you were talking about and just how they''re kind of delivered to us.","index":146,"end_time":776.6,"speaker_id":7,"start_time":767.6,"speaker_name":"Stephanie Lucchesi"},{"text":"I''m just making sure that I''m getting them.","index":147,"end_time":778.56,"speaker_id":7,"start_time":776.6,"speaker_name":"Stephanie Lucchesi"},{"text":"If any of them are mine.","index":148,"end_time":779.64,"speaker_id":7,"start_time":778.56,"speaker_name":"Stephanie Lucchesi"},{"text":"That link that I just put into the chat is the HubSpot link.","index":149,"end_time":786.44,"speaker_id":1,"start_time":781.96,"speaker_name":"Josh Reinhard"},{"text":"Okay.","index":150,"end_time":787.17,"speaker_id":0,"start_time":786.77,"speaker_name":"Rob Whalen"},{"text":"Yeah, I see them in here.","index":151,"end_time":788.53,"speaker_id":2,"start_time":787.17,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":152,"end_time":791.93,"speaker_id":2,"start_time":791.57,"speaker_name":"Colin Costigan"},{"text":"This is one of those legacy workflows that it went through that we talked about in the audit.","index":153,"end_time":795.57,"speaker_id":2,"start_time":791.93,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":154,"end_time":804.09,"speaker_id":2,"start_time":803.73,"speaker_name":"Colin Costigan"},{"text":"And Steph, the leads that we were talking about were from LinkedIn, not the requested demo form on the website.","index":155,"end_time":809.33,"speaker_id":2,"start_time":804.09,"speaker_name":"Colin Costigan"},{"text":"So those have been the same where you''re getting the task assigned the next business day.","index":156,"end_time":813.33,"speaker_id":2,"start_time":810.13,"speaker_name":"Colin Costigan"},{"text":"Got it.","index":157,"end_time":814.2,"speaker_id":0,"start_time":813.8,"speaker_name":"Rob Whalen"},{"text":"Yeah.","index":158,"end_time":817.48,"speaker_id":2,"start_time":817.16,"speaker_name":"Colin Costigan"},{"text":"We''ll definitely take it as an action item to look at all of the workflows, but it''s literally went through a John Randall territory workflow.","index":159,"end_time":827.64,"speaker_id":2,"start_time":817.48,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":160,"end_time":831.24,"speaker_id":1,"start_time":830.76,"speaker_name":"Josh Reinhard"},{"text":"So.","index":161,"end_time":832.44,"speaker_id":0,"start_time":832.04,"speaker_name":"Rob Whalen"},{"text":"Yep, we will adjust that.","index":162,"end_time":835.96,"speaker_id":2,"start_time":833.8,"speaker_name":"Colin Costigan"},{"text":"So.","index":163,"end_time":836.32,"speaker_id":2,"start_time":836.04,"speaker_name":"Colin Costigan"},{"text":"Yeah, and that should go to Steph.","index":164,"end_time":837.52,"speaker_id":2,"start_time":836.32,"speaker_name":"Colin Costigan"},{"text":"So we''ll adjust that.","index":165,"end_time":838.36,"speaker_id":2,"start_time":837.52,"speaker_name":"Colin Costigan"},{"text":"Perfect.","index":166,"end_time":840.09,"speaker_id":2,"start_time":839.81,"speaker_name":"Colin Costigan"},{"text":"I mean, obviously this one.","index":167,"end_time":841.33,"speaker_id":1,"start_time":840.09,"speaker_name":"Josh Reinhard"},{"text":"Seth, there''s nothing you need to do.","index":168,"end_time":842.85,"speaker_id":1,"start_time":841.33,"speaker_name":"Josh Reinhard"},{"text":"Right.","index":169,"end_time":843.57,"speaker_id":0,"start_time":843.17,"speaker_name":"Rob Whalen"},{"text":"But so as these come up just into the Slack channel, if something like this happens.","index":170,"end_time":850.85,"speaker_id":1,"start_time":845.57,"speaker_name":"Josh Reinhard"},{"text":"Yes.","index":171,"end_time":851.57,"speaker_id":0,"start_time":851.01,"speaker_name":"Rob Whalen"},{"text":"Place it in there.","index":172,"end_time":852.45,"speaker_id":1,"start_time":851.57,"speaker_name":"Josh Reinhard"},{"text":"Perfect.","index":173,"end_time":853.17,"speaker_id":0,"start_time":852.61,"speaker_name":"Rob Whalen"},{"text":"There was something else I wanted to ask.","index":174,"end_time":858.29,"speaker_id":1,"start_time":856.45,"speaker_name":"Josh Reinhard"},{"text":"Now I''m forgetting what it was.","index":175,"end_time":859.81,"speaker_id":1,"start_time":858.29,"speaker_name":"Josh Reinhard"},{"text":"I''m sure I''ll think of it as soon as we get off the cough.","index":176,"end_time":865.81,"speaker_id":1,"start_time":863.57,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":177,"end_time":866.65,"speaker_id":0,"start_time":866.25,"speaker_name":"Rob Whalen"},{"text":"Yeah.","index":178,"end_time":872.33,"speaker_id":1,"start_time":871.77,"speaker_name":"Josh Reinhard"},{"text":"Dang it.","index":179,"end_time":873.85,"speaker_id":1,"start_time":873.13,"speaker_name":"Josh Reinhard"},{"text":"Just have it.","index":180,"end_time":875.37,"speaker_id":1,"start_time":874.49,"speaker_name":"Josh Reinhard"},{"text":"I found it.","index":181,"end_time":876.93,"speaker_id":2,"start_time":876.25,"speaker_name":"Colin Costigan"},{"text":"It''s a savings exchange legacy workflow.","index":182,"end_time":880.73,"speaker_id":2,"start_time":876.93,"speaker_name":"Colin Costigan"},{"text":"That''s where that lead went through.","index":183,"end_time":884.81,"speaker_id":2,"start_time":883.45,"speaker_name":"Colin Costigan"},{"text":"I have a question about like just the performance across all our campaigns, all our programs, how.","index":184,"end_time":893.73,"speaker_id":6,"start_time":884.81,"speaker_name":"Carmen Williams"},{"text":"Like I know we''re going to get the full attribution reporting, which I think spake Danda HubSpot.","index":185,"end_time":899.89,"speaker_id":6,"start_time":893.73,"speaker_name":"Carmen Williams"},{"text":"I think we''re going to.","index":186,"end_time":901.41,"speaker_id":6,"start_time":900.53,"speaker_name":"Carmen Williams"},{"text":"Obviously step two was going to get that in good shape, but before then, like we''re.","index":187,"end_time":907.809,"speaker_id":6,"start_time":901.41,"speaker_name":"Carmen Williams"},{"text":"While we''re waiting, can we just.","index":188,"end_time":910.81,"speaker_id":6,"start_time":907.809,"speaker_name":"Carmen Williams"},{"text":"You Know how quickly can we get a little bit more visibility into just overall?","index":189,"end_time":915.65,"speaker_id":6,"start_time":910.81,"speaker_name":"Carmen Williams"},{"text":"So when you say LinkedIn, we had great LinkedIn ads for leads.","index":190,"end_time":921.01,"speaker_id":6,"start_time":916.69,"speaker_name":"Carmen Williams"},{"text":"Like, you know, I, I feel like I''m missing a lot of information about that like relative to what and what''s the cost per lead relative to the other leads.","index":191,"end_time":930.64,"speaker_id":6,"start_time":921.01,"speaker_name":"Carmen Williams"},{"text":"So, so I''m wondering can we, can we tackle the reporting kind of at the same time or at the beginning or what''s your thoughts on, you know, some of the asks I''ve had around reporting?","index":192,"end_time":943.96,"speaker_id":6,"start_time":930.64,"speaker_name":"Carmen Williams"},{"text":"Yeah, yeah.","index":193,"end_time":945.24,"speaker_id":6,"start_time":943.96,"speaker_name":"Carmen Williams"},{"text":"So there''s a few things.","index":194,"end_time":946.24,"speaker_id":2,"start_time":945.24,"speaker_name":"Colin Costigan"},{"text":"So one, we could do internal like inside of HubSpot''s reporting using their features.","index":195,"end_time":950.68,"speaker_id":2,"start_time":946.24,"speaker_name":"Colin Costigan"},{"text":"We''ll just only have to update it once we do UPD source fields, things like that.","index":196,"end_time":954.5,"speaker_id":2,"start_time":951.08,"speaker_name":"Colin Costigan"},{"text":"That is pretty easy.","index":197,"end_time":955.58,"speaker_id":2,"start_time":954.5,"speaker_name":"Colin Costigan"},{"text":"No problem.","index":198,"end_time":956.02,"speaker_id":2,"start_time":955.58,"speaker_name":"Colin Costigan"},{"text":"The other thing that we have is a data box which is just a live Data dashboard from LinkedIn webs like Google Analytics, all of these different sources feeding into one.","index":199,"end_time":964.5,"speaker_id":2,"start_time":956.02,"speaker_name":"Colin Costigan"},{"text":"So we can do more of a comprehensive update to that to show you like cost per lead numbers.","index":200,"end_time":968.86,"speaker_id":2,"start_time":965.22,"speaker_name":"Colin Costigan"},{"text":"And then that''s just a live updated.","index":201,"end_time":970.74,"speaker_id":2,"start_time":968.86,"speaker_name":"Colin Costigan"},{"text":"You pull it up anytime you want, link doesn''t change.","index":202,"end_time":972.74,"speaker_id":2,"start_time":970.74,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":203,"end_time":974.3,"speaker_id":3,"start_time":973.86,"speaker_name":"Nathalie Mintjens"},{"text":"So maybe we could take an offline conversation, a deep dive in around recording with you and whoever else and get that going or get that conversation started at the same time that we''re doing the database cleanup, if possible.","index":204,"end_time":989.16,"speaker_id":6,"start_time":974.3,"speaker_name":"Carmen Williams"},{"text":"That''d be great.","index":205,"end_time":990.04,"speaker_id":6,"start_time":989.24,"speaker_name":"Carmen Williams"},{"text":"Yeah, cool.","index":206,"end_time":991.64,"speaker_id":6,"start_time":990.04,"speaker_name":"Carmen Williams"},{"text":"Thanks.","index":207,"end_time":992.04,"speaker_id":6,"start_time":991.64,"speaker_name":"Carmen Williams"},{"text":"I thought of.","index":208,"end_time":993.28,"speaker_id":1,"start_time":992.6,"speaker_name":"Josh Reinhard"},{"text":"My other question is for Natalie, for the flyers that you created for Man I.","index":209,"end_time":1000.12,"speaker_id":1,"start_time":993.28,"speaker_name":"Josh Reinhard"},{"text":"Where.","index":210,"end_time":1001.76,"speaker_id":1,"start_time":1001.4,"speaker_name":"Josh Reinhard"},{"text":"Where do those sit?","index":211,"end_time":1002.84,"speaker_id":1,"start_time":1001.76,"speaker_name":"Josh Reinhard"},{"text":"Like where is the, the live file for that?","index":212,"end_time":1006.92,"speaker_id":1,"start_time":1004.2,"speaker_name":"Josh Reinhard"},{"text":"The Figma file?","index":213,"end_time":1008.89,"speaker_id":3,"start_time":1007.85,"speaker_name":"Nathalie Mintjens"},{"text":"Is it, is it in our Figma account?","index":214,"end_time":1011.77,"speaker_id":1,"start_time":1009.61,"speaker_name":"Josh Reinhard"},{"text":"We made it in ours, but we can add it into yours if you want.","index":215,"end_time":1016.73,"speaker_id":3,"start_time":1012.49,"speaker_name":"Nathalie Mintjens"},{"text":"I''m just thinking if we just wanted to replicate that for another client rather than having to send it back to you each time.","index":216,"end_time":1025.85,"speaker_id":1,"start_time":1018.09,"speaker_name":"Josh Reinhard"},{"text":"If it''s just like small changes that we need to make and that''s the template, it would be good to have that somewhere on our side.","index":217,"end_time":1032.57,"speaker_id":1,"start_time":1025.85,"speaker_name":"Josh Reinhard"},{"text":"And Carmen, maybe this is.","index":218,"end_time":1033.93,"speaker_id":1,"start_time":1032.57,"speaker_name":"Josh Reinhard"},{"text":"I don''t know if we''re ready now to make the break from figma.","index":219,"end_time":1037.96,"speaker_id":1,"start_time":1035,"speaker_name":"Josh Reinhard"},{"text":"If you wanted to do that and use.","index":220,"end_time":1039.96,"speaker_id":1,"start_time":1037.96,"speaker_name":"Josh Reinhard"},{"text":"I know you said you''re more familiar with Canva.","index":221,"end_time":1042.76,"speaker_id":1,"start_time":1040.36,"speaker_name":"Josh Reinhard"},{"text":"I don''t know if that''s something that we want to do or what.","index":222,"end_time":1047.8,"speaker_id":1,"start_time":1045,"speaker_name":"Josh Reinhard"},{"text":"Yeah, so I, I did get access to Figma and for just easy edits.","index":223,"end_time":1052.72,"speaker_id":6,"start_time":1047.88,"speaker_name":"Carmen Williams"},{"text":"It sounds like you and I, anybody can do those.","index":224,"end_time":1055.08,"speaker_id":6,"start_time":1052.72,"speaker_name":"Carmen Williams"},{"text":"It''s.","index":225,"end_time":1056.44,"speaker_id":6,"start_time":1055.88,"speaker_name":"Carmen Williams"},{"text":"I don''t.","index":226,"end_time":1057.04,"speaker_id":6,"start_time":1056.44,"speaker_name":"Carmen Williams"},{"text":"I''m not as familiar with how you make more, you know, wholesale changes to things with figma.","index":227,"end_time":1063.96,"speaker_id":6,"start_time":1057.04,"speaker_name":"Carmen Williams"},{"text":"And I was thinking as part of the next phase of the brand kind of build out that we could kind of do some kind of a shift then.","index":228,"end_time":1073.16,"speaker_id":6,"start_time":1065,"speaker_name":"Carmen Williams"},{"text":"Okay.","index":229,"end_time":1074.04,"speaker_id":0,"start_time":1073.48,"speaker_name":"Rob Whalen"},{"text":"Yeah.","index":230,"end_time":1076.4,"speaker_id":6,"start_time":1076.04,"speaker_name":"Carmen Williams"},{"text":"I mean, I think just if it''s still.","index":231,"end_time":1078.52,"speaker_id":6,"start_time":1076.4,"speaker_name":"Carmen Williams"},{"text":"I''m assuming whatever they''re building is in that, that Figma location, right.","index":232,"end_time":1085.08,"speaker_id":6,"start_time":1078.52,"speaker_name":"Carmen Williams"},{"text":"Natalie, we could find it in with Figma, with the other ones and just be able to go find it and.","index":233,"end_time":1089.64,"speaker_id":6,"start_time":1085.32,"speaker_name":"Carmen Williams"},{"text":"Make it sounds like once she moves it over to.","index":234,"end_time":1091.64,"speaker_id":1,"start_time":1089.64,"speaker_name":"Josh Reinhard"},{"text":"Oh, okay.","index":235,"end_time":1092.68,"speaker_id":6,"start_time":1091.8,"speaker_name":"Carmen Williams"},{"text":"Yeah, yeah, yeah, yeah.","index":236,"end_time":1094.16,"speaker_id":6,"start_time":1092.84,"speaker_name":"Carmen Williams"},{"text":"Cool.","index":237,"end_time":1094.465,"speaker_id":6,"start_time":1094.16,"speaker_name":"Carmen Williams"},{"text":"Yeah, yeah.","index":238,"end_time":1095.12,"speaker_id":6,"start_time":1094.465,"speaker_name":"Carmen Williams"},{"text":"I can drop that into your Figma account pretty easily.","index":239,"end_time":1098.84,"speaker_id":3,"start_time":1096.16,"speaker_name":"Nathalie Mintjens"},{"text":"And then you can just copy.","index":240,"end_time":1100.16,"speaker_id":3,"start_time":1098.84,"speaker_name":"Nathalie Mintjens"},{"text":"Copy it and change the text in it.","index":241,"end_time":1102.24,"speaker_id":3,"start_time":1100.24,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":242,"end_time":1103.12,"speaker_id":1,"start_time":1102.56,"speaker_name":"Josh Reinhard"},{"text":"And I guess it''s probably not worth it since if you think.","index":243,"end_time":1107.12,"speaker_id":1,"start_time":1103.12,"speaker_name":"Josh Reinhard"},{"text":"Carmen, ultimately we''re going to move away from figma.","index":244,"end_time":1109.24,"speaker_id":1,"start_time":1107.12,"speaker_name":"Josh Reinhard"},{"text":"But one of the things that I wasn''t a huge fan of is like sandwiches.","index":245,"end_time":1114.56,"speaker_id":1,"start_time":1109.24,"speaker_name":"Josh Reinhard"},{"text":"Put like everything on one page.","index":246,"end_time":1116.16,"speaker_id":1,"start_time":1114.56,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":247,"end_time":1116.96,"speaker_id":6,"start_time":1116.56,"speaker_name":"Carmen Williams"},{"text":"As opposed to like some things, you know, client flyers here, case studies here.","index":248,"end_time":1123.5,"speaker_id":1,"start_time":1116.96,"speaker_name":"Josh Reinhard"},{"text":"Josh.","index":249,"end_time":1123.98,"speaker_id":1,"start_time":1123.58,"speaker_name":"Josh Reinhard"},{"text":"I think that was the first thing that Natalie said to me when we got into your account.","index":250,"end_time":1126.94,"speaker_id":2,"start_time":1123.98,"speaker_name":"Colin Costigan"},{"text":"Oh, everything is in one folder.","index":251,"end_time":1130.62,"speaker_id":3,"start_time":1127.98,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah.","index":252,"end_time":1131.42,"speaker_id":1,"start_time":1130.94,"speaker_name":"Josh Reinhard"},{"text":"And he''d be like, oh, it''s so easy.","index":253,"end_time":1133.06,"speaker_id":1,"start_time":1131.82,"speaker_name":"Josh Reinhard"},{"text":"You just.","index":254,"end_time":1133.42,"speaker_id":1,"start_time":1133.06,"speaker_name":"Josh Reinhard"},{"text":"I know that this is over here.","index":255,"end_time":1134.7,"speaker_id":1,"start_time":1133.42,"speaker_name":"Josh Reinhard"},{"text":"So you just scroll to this side of the page and it''s like, why don''t we just index these so that it''s.","index":256,"end_time":1139.1,"speaker_id":1,"start_time":1134.7,"speaker_name":"Josh Reinhard"},{"text":"But I don''t know if it''s worth manipulating that if we''re ultimately going to move away from figma.","index":257,"end_time":1147.34,"speaker_id":1,"start_time":1139.1,"speaker_name":"Josh Reinhard"},{"text":"I don''t know, Carmen.","index":258,"end_time":1148.96,"speaker_id":1,"start_time":1148.2,"speaker_name":"Josh Reinhard"},{"text":"Like, how long when that phase of the brand stuff is happening, if it''s months away, maybe we should make it easier to navigate Figma.","index":259,"end_time":1158.64,"speaker_id":1,"start_time":1148.96,"speaker_name":"Josh Reinhard"},{"text":"And now they don''t know how easy it is to do that.","index":260,"end_time":1160.84,"speaker_id":1,"start_time":1158.64,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":261,"end_time":1161.64,"speaker_id":6,"start_time":1161.16,"speaker_name":"Carmen Williams"},{"text":"I mean, I''m sure it''s not that hard.","index":262,"end_time":1163.24,"speaker_id":6,"start_time":1161.64,"speaker_name":"Carmen Williams"},{"text":"Right.","index":263,"end_time":1163.839,"speaker_id":6,"start_time":1163.48,"speaker_name":"Carmen Williams"},{"text":"Just to organize it.","index":264,"end_time":1165,"speaker_id":6,"start_time":1163.839,"speaker_name":"Carmen Williams"},{"text":"So I mean, I say go for it.","index":265,"end_time":1168.2,"speaker_id":6,"start_time":1165.24,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":266,"end_time":1169.64,"speaker_id":6,"start_time":1169.08,"speaker_name":"Carmen Williams"},{"text":"If it''s not that hard to do, I would just prefer bring some organization to it.","index":267,"end_time":1174.25,"speaker_id":6,"start_time":1170.28,"speaker_name":"Carmen Williams"},{"text":"I''m sure everybody.","index":268,"end_time":1175.81,"speaker_id":6,"start_time":1174.25,"speaker_name":"Carmen Williams"},{"text":"Yeah, no worries.","index":269,"end_time":1177.09,"speaker_id":6,"start_time":1175.81,"speaker_name":"Carmen Williams"},{"text":"Okay.","index":270,"end_time":1178.93,"speaker_id":0,"start_time":1178.37,"speaker_name":"Rob Whalen"},{"text":"If you wouldn''t mind doing that, Natalie.","index":271,"end_time":1181.89,"speaker_id":1,"start_time":1180.05,"speaker_name":"Josh Reinhard"},{"text":"Yeah, sure.","index":272,"end_time":1183.17,"speaker_id":3,"start_time":1182.53,"speaker_name":"Nathalie Mintjens"},{"text":"I think, I think they''re like grouped together spatially on the page.","index":273,"end_time":1187.97,"speaker_id":1,"start_time":1183.73,"speaker_name":"Josh Reinhard"},{"text":"So yeah, there''s like case studies on one side and.","index":274,"end_time":1193.01,"speaker_id":3,"start_time":1188.37,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah, together.","index":275,"end_time":1196.21,"speaker_id":1,"start_time":1193.65,"speaker_name":"Josh Reinhard"},{"text":"So yeah, whatever.","index":276,"end_time":1197.57,"speaker_id":1,"start_time":1196.29,"speaker_name":"Josh Reinhard"},{"text":"Whatever makes the most sense.","index":277,"end_time":1199.41,"speaker_id":1,"start_time":1198.21,"speaker_name":"Josh Reinhard"},{"text":"But that, that would be helpful.","index":278,"end_time":1204.66,"speaker_id":1,"start_time":1199.41,"speaker_name":"Josh Reinhard"},{"text":"But just we.","index":279,"end_time":1205.7,"speaker_id":1,"start_time":1204.98,"speaker_name":"Josh Reinhard"},{"text":"We have another request from another client and I was just thinking like, I like the way these look.","index":280,"end_time":1210.02,"speaker_id":1,"start_time":1205.7,"speaker_name":"Josh Reinhard"},{"text":"Why not just use the same thing, replace the logo, change a little bit about what''s on here.","index":281,"end_time":1214.94,"speaker_id":1,"start_time":1210.1,"speaker_name":"Josh Reinhard"},{"text":"Although there''s this cash out, so I need to wait until you create the cash out one.","index":282,"end_time":1218.22,"speaker_id":1,"start_time":1214.94,"speaker_name":"Josh Reinhard"},{"text":"But it''s Gonna just.","index":283,"end_time":1219.1,"speaker_id":1,"start_time":1218.22,"speaker_name":"Josh Reinhard"},{"text":"We''re just gonna mimic that.","index":284,"end_time":1220.74,"speaker_id":1,"start_time":1219.1,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":285,"end_time":1222.02,"speaker_id":3,"start_time":1221.54,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":286,"end_time":1223.54,"speaker_id":3,"start_time":1222.98,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah.","index":287,"end_time":1224.54,"speaker_id":6,"start_time":1224.1,"speaker_name":"Carmen Williams"},{"text":"So I think, Colin, if you want to share good time SP spots for whoever needs to be on your team with me and Sam to just dig deeper into the HubSpot initiatives and maybe map out a little bit more detail of what we''re going to do.","index":288,"end_time":1240.65,"speaker_id":6,"start_time":1224.54,"speaker_name":"Carmen Williams"},{"text":"And then.","index":289,"end_time":1242.81,"speaker_id":6,"start_time":1242.25,"speaker_name":"Carmen Williams"},{"text":"So that''s great.","index":290,"end_time":1243.65,"speaker_id":6,"start_time":1242.89,"speaker_name":"Carmen Williams"},{"text":"So whenever, just let me know.","index":291,"end_time":1245.29,"speaker_id":6,"start_time":1243.65,"speaker_name":"Carmen Williams"},{"text":"And then I think, Natalie, Nina, we have some time after this call to kind of talk through my recent audit initiatives, kind of where I''m thinking of, of taking PTO exchange from a marketing perspective and where I''d love your help.","index":292,"end_time":1261.77,"speaker_id":6,"start_time":1246.17,"speaker_name":"Carmen Williams"},{"text":"So unless, Colin, you think you should be on that conversation, we can shift it to a better time.","index":293,"end_time":1268.17,"speaker_id":6,"start_time":1263.45,"speaker_name":"Carmen Williams"},{"text":"Just let me know.","index":294,"end_time":1268.89,"speaker_id":6,"start_time":1268.17,"speaker_name":"Carmen Williams"},{"text":"No, no, I think continues that I''m watching the recordings as well.","index":295,"end_time":1272.25,"speaker_id":2,"start_time":1269.13,"speaker_name":"Colin Costigan"},{"text":"My calendar is not the friendliest.","index":296,"end_time":1275.33,"speaker_id":2,"start_time":1273.13,"speaker_name":"Colin Costigan"},{"text":"So.","index":297,"end_time":1275.57,"speaker_id":2,"start_time":1275.33,"speaker_name":"Colin Costigan"},{"text":"Yeah, no, I want to make sure that doesn''t hinder us from moving forward quickly.","index":298,"end_time":1278.73,"speaker_id":2,"start_time":1275.57,"speaker_name":"Colin Costigan"},{"text":"Yeah, perfect.","index":299,"end_time":1279.69,"speaker_id":6,"start_time":1278.97,"speaker_name":"Carmen Williams"},{"text":"Okay, great.","index":300,"end_time":1280.41,"speaker_id":6,"start_time":1279.69,"speaker_name":"Carmen Williams"},{"text":"I have a question on these for May and I, and just getting your feedback.","index":301,"end_time":1284.97,"speaker_id":5,"start_time":1281.37,"speaker_name":"Dan Igo"},{"text":"First of all, they''re awesome, but do we think that a.","index":302,"end_time":1287.37,"speaker_id":5,"start_time":1285.13,"speaker_name":"Dan Igo"},{"text":"A QR code to the login site would be beneficial on these?","index":303,"end_time":1291.3,"speaker_id":5,"start_time":1287.78,"speaker_name":"Dan Igo"},{"text":"What''s the.","index":304,"end_time":1295.06,"speaker_id":2,"start_time":1294.34,"speaker_name":"Colin Costigan"},{"text":"Sorry, go ahead.","index":305,"end_time":1296.86,"speaker_id":2,"start_time":1296.18,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":306,"end_time":1297.1,"speaker_id":3,"start_time":1296.86,"speaker_name":"Nathalie Mintjens"},{"text":"Are they going to be sent digitally?","index":307,"end_time":1298.66,"speaker_id":3,"start_time":1297.1,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":308,"end_time":1299.86,"speaker_id":0,"start_time":1299.3,"speaker_name":"Rob Whalen"},{"text":"They are going to be sent digitally.","index":309,"end_time":1302.22,"speaker_id":1,"start_time":1300.74,"speaker_name":"Josh Reinhard"},{"text":"So this is like a link in their newsletter that''s like, goes out monthly.","index":310,"end_time":1308.98,"speaker_id":1,"start_time":1302.22,"speaker_name":"Josh Reinhard"},{"text":"In one month, they''re going to send the 401k one.","index":311,"end_time":1311.06,"speaker_id":1,"start_time":1308.98,"speaker_name":"Josh Reinhard"},{"text":"One month, they''re going to send me HSA one.","index":312,"end_time":1314.9,"speaker_id":1,"start_time":1311.06,"speaker_name":"Josh Reinhard"},{"text":"The next month, they''re going to send THE CASH OUT one.","index":313,"end_time":1316.7,"speaker_id":1,"start_time":1314.9,"speaker_name":"Josh Reinhard"},{"text":"The next month they''re going to send a charitable giving one or like every other month or whatever their cadence is.","index":314,"end_time":1320.62,"speaker_id":1,"start_time":1316.7,"speaker_name":"Josh Reinhard"},{"text":"But it''s a link inside of a newsletter that''s going to open up this PDF is the way I understood it.","index":315,"end_time":1326.74,"speaker_id":1,"start_time":1320.62,"speaker_name":"Josh Reinhard"},{"text":"Or are they hyperlinked in the PDF when they open it?","index":316,"end_time":1330.74,"speaker_id":5,"start_time":1327.94,"speaker_name":"Dan Igo"},{"text":"Natalie.","index":317,"end_time":1331.38,"speaker_id":5,"start_time":1330.74,"speaker_name":"Dan Igo"},{"text":"Because we''re just trying to make it as easy as possible for employees to get to our platform.","index":318,"end_time":1335.22,"speaker_id":5,"start_time":1331.78,"speaker_name":"Dan Igo"},{"text":"Yeah.","index":319,"end_time":1336.46,"speaker_id":3,"start_time":1336.02,"speaker_name":"Nathalie Mintjens"},{"text":"So this, it says go to ptoexchange.com SignIn this is hyperlinked.","index":320,"end_time":1341.62,"speaker_id":3,"start_time":1336.46,"speaker_name":"Nathalie Mintjens"},{"text":"That is hyperlinked.","index":321,"end_time":1342.9,"speaker_id":5,"start_time":1342.1,"speaker_name":"Dan Igo"},{"text":"Okay, great.","index":322,"end_time":1343.38,"speaker_id":1,"start_time":1342.9,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":323,"end_time":1343.86,"speaker_id":6,"start_time":1343.38,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":324,"end_time":1346.94,"speaker_id":6,"start_time":1346.58,"speaker_name":"Carmen Williams"},{"text":"Dan, I think just because it''s being delivered digitally, I don''t think QR code is the best way to go.","index":325,"end_time":1351.14,"speaker_id":2,"start_time":1346.94,"speaker_name":"Colin Costigan"},{"text":"Okay.","index":326,"end_time":1351.94,"speaker_id":0,"start_time":1351.46,"speaker_name":"Rob Whalen"},{"text":"That''s why.","index":327,"end_time":1352.42,"speaker_id":5,"start_time":1351.94,"speaker_name":"Dan Igo"},{"text":"Yeah, I wanted your opinion on that.","index":328,"end_time":1353.9,"speaker_id":5,"start_time":1352.42,"speaker_name":"Dan Igo"},{"text":"And I didn''t know that that was hyperlinked.","index":329,"end_time":1355.7,"speaker_id":5,"start_time":1353.9,"speaker_name":"Dan Igo"},{"text":"Unless we want to have a QR code to download the mobile app.","index":330,"end_time":1361.78,"speaker_id":1,"start_time":1356.74,"speaker_name":"Josh Reinhard"},{"text":"You.","index":331,"end_time":1366.58,"speaker_id":0,"start_time":1366.26,"speaker_name":"Rob Whalen"},{"text":"Could have like a Q. I don''t know how I.","index":332,"end_time":1368.58,"speaker_id":1,"start_time":1366.58,"speaker_name":"Josh Reinhard"},{"text":"Embarrassing.","index":333,"end_time":1370.76,"speaker_id":1,"start_time":1370.24,"speaker_name":"Josh Reinhard"},{"text":"We don''t really know how QR Codes work, but I guess we would probably have a separate QR code for Android and the separate QR code for iOS and it would just bring them to the App Store for each of them.","index":334,"end_time":1379.92,"speaker_id":1,"start_time":1370.76,"speaker_name":"Josh Reinhard"},{"text":"Yeah, that''s something that.","index":335,"end_time":1382.4,"speaker_id":1,"start_time":1380.4,"speaker_name":"Josh Reinhard"},{"text":"And it would also highlight that you have an app, so that could be good.","index":336,"end_time":1387.68,"speaker_id":4,"start_time":1383.76,"speaker_name":"Nina Belina"},{"text":"I don''t know what the QR code is to get to them to the app.","index":337,"end_time":1394.96,"speaker_id":1,"start_time":1390.72,"speaker_name":"Josh Reinhard"},{"text":"We can just go on the App Store in the Google Play Store and find them.","index":338,"end_time":1399.31,"speaker_id":2,"start_time":1396.11,"speaker_name":"Colin Costigan"},{"text":"But maybe that would be a nice addition.","index":339,"end_time":1401.39,"speaker_id":1,"start_time":1399.31,"speaker_name":"Josh Reinhard"},{"text":"I wonder where the one on our demo site takes us, Josh.","index":340,"end_time":1404.95,"speaker_id":5,"start_time":1401.95,"speaker_name":"Dan Igo"},{"text":"Does it take us to the Apple or the.","index":341,"end_time":1406.67,"speaker_id":5,"start_time":1404.95,"speaker_name":"Dan Igo"},{"text":"On our demo site?","index":342,"end_time":1410.51,"speaker_id":1,"start_time":1409.47,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":343,"end_time":1411.55,"speaker_id":5,"start_time":1411.23,"speaker_name":"Dan Igo"},{"text":"When you go to the login, when you''re logging into the demo, if you scroll down at the bottom, there''s a QR code with a link to the app.","index":344,"end_time":1416.99,"speaker_id":5,"start_time":1411.55,"speaker_name":"Dan Igo"},{"text":"I think I''ve just done that so many times that I don''t even, like, pay attention to the fact that it''s.","index":345,"end_time":1425.8,"speaker_id":1,"start_time":1421.64,"speaker_name":"Josh Reinhard"},{"text":"Does it.","index":346,"end_time":1426.16,"speaker_id":0,"start_time":1425.8,"speaker_name":"Rob Whalen"},{"text":"Does it not just take you to either whatever your phone is when you take that QR code?","index":347,"end_time":1430.96,"speaker_id":0,"start_time":1426.16,"speaker_name":"Rob Whalen"},{"text":"I think it does.","index":348,"end_time":1431.64,"speaker_id":0,"start_time":1430.96,"speaker_name":"Rob Whalen"},{"text":"If it''s an iOS, it takes you to Apple.","index":349,"end_time":1435.88,"speaker_id":0,"start_time":1433.56,"speaker_name":"Rob Whalen"},{"text":"If it''s, you know, Android, it took.","index":350,"end_time":1440.16,"speaker_id":0,"start_time":1436.04,"speaker_name":"Rob Whalen"},{"text":"Me to Google Play, which is.","index":351,"end_time":1441.28,"speaker_id":5,"start_time":1440.16,"speaker_name":"Dan Igo"},{"text":"Right.","index":352,"end_time":1441.56,"speaker_id":1,"start_time":1441.28,"speaker_name":"Josh Reinhard"},{"text":"Yeah, I think it''s in there.","index":353,"end_time":1443.96,"speaker_id":0,"start_time":1441.96,"speaker_name":"Rob Whalen"},{"text":"Mine went to the iOS store, so.","index":354,"end_time":1446.84,"speaker_id":1,"start_time":1445.08,"speaker_name":"Josh Reinhard"},{"text":"Yeah, there we go.","index":355,"end_time":1449.32,"speaker_id":1,"start_time":1447.88,"speaker_name":"Josh Reinhard"},{"text":"So maybe if we can do that, that would be.","index":356,"end_time":1456.28,"speaker_id":1,"start_time":1454.36,"speaker_name":"Josh Reinhard"},{"text":"That would be a good addition to these.","index":357,"end_time":1460.12,"speaker_id":1,"start_time":1458.12,"speaker_name":"Josh Reinhard"},{"text":"We want as many people downloading the mobile app as we can.","index":358,"end_time":1462.92,"speaker_id":1,"start_time":1460.12,"speaker_name":"Josh Reinhard"},{"text":"Okay.","index":359,"end_time":1465,"speaker_id":3,"start_time":1464.44,"speaker_name":"Nathalie Mintjens"},{"text":"And Colin, Colin, the other thing, now that you mentioned how your calendar is a mess, what do we want to do about the weekly schedule?","index":360,"end_time":1479.12,"speaker_id":1,"start_time":1469.16,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":361,"end_time":1481.56,"speaker_id":2,"start_time":1481.12,"speaker_name":"Colin Costigan"},{"text":"So I think you guys met earlier this week, right.","index":362,"end_time":1483.32,"speaker_id":2,"start_time":1481.56,"speaker_name":"Colin Costigan"},{"text":"To kind of go through that.","index":363,"end_time":1484.2,"speaker_id":2,"start_time":1483.32,"speaker_name":"Colin Costigan"},{"text":"What works best on your end or what you were.","index":364,"end_time":1485.84,"speaker_id":2,"start_time":1484.2,"speaker_name":"Colin Costigan"},{"text":"We didn''t actually.","index":365,"end_time":1486.96,"speaker_id":1,"start_time":1486.16,"speaker_name":"Josh Reinhard"},{"text":"We had.","index":366,"end_time":1487.44,"speaker_id":1,"start_time":1486.96,"speaker_name":"Josh Reinhard"},{"text":"We, like, really just talked about Carmen''s audit, like a holistic marketing audit.","index":367,"end_time":1493.04,"speaker_id":1,"start_time":1487.44,"speaker_name":"Josh Reinhard"},{"text":"We didn''t talk schedules, but we have that standing Monday call, which we''ve now skipped a couple weeks in a row because I know that, Carmen, you''re meeting with the New north team more frequently than we were in the past.","index":368,"end_time":1505.52,"speaker_id":1,"start_time":1493.04,"speaker_name":"Josh Reinhard"},{"text":"So do we want to just take that Monday call off the calendar?","index":369,"end_time":1510.38,"speaker_id":1,"start_time":1505.98,"speaker_name":"Josh Reinhard"},{"text":"Yeah, I think so.","index":370,"end_time":1512.7,"speaker_id":2,"start_time":1511.74,"speaker_name":"Colin Costigan"},{"text":"But I know that you guys also, like, are working out your.","index":371,"end_time":1516.14,"speaker_id":2,"start_time":1513.82,"speaker_name":"Colin Costigan"},{"text":"More like sales and marketing calendar.","index":372,"end_time":1519.26,"speaker_id":2,"start_time":1516.62,"speaker_name":"Colin Costigan"},{"text":"So if there''s any updates there at any point, please just let us know where we can be of use.","index":373,"end_time":1523.74,"speaker_id":2,"start_time":1519.5,"speaker_name":"Colin Costigan"},{"text":"Yeah, I don''t.","index":374,"end_time":1526.14,"speaker_id":1,"start_time":1525.34,"speaker_name":"Josh Reinhard"},{"text":"I think when we.","index":375,"end_time":1526.82,"speaker_id":1,"start_time":1526.14,"speaker_name":"Josh Reinhard"},{"text":"Carmen and I first talked about it, Carmen, I think you had mentioned, like, you don''t think it''s necessary for them to join our Wednesday Meeting you''re going to cover the market.","index":376,"end_time":1533.05,"speaker_id":1,"start_time":1526.82,"speaker_name":"Josh Reinhard"},{"text":"Not what I''ve seen so far.","index":377,"end_time":1534.97,"speaker_id":6,"start_time":1533.69,"speaker_name":"Carmen Williams"},{"text":"Yeah, I mean that''s.","index":378,"end_time":1536.09,"speaker_id":1,"start_time":1535.13,"speaker_name":"Josh Reinhard"},{"text":"Those are pretty typical of what those Wednesday calls are like.","index":379,"end_time":1539.45,"speaker_id":1,"start_time":1536.09,"speaker_name":"Josh Reinhard"},{"text":"Like, I would love to see on Wednesday that we''re like.","index":380,"end_time":1542.77,"speaker_id":6,"start_time":1539.69,"speaker_name":"Carmen Williams"},{"text":"For example, when we do this ABM initiative is we should know each week what, like how did it go, where you know, who did you contact, how you know, a deeper dive into the sales and marketing.","index":381,"end_time":1555.21,"speaker_id":6,"start_time":1542.77,"speaker_name":"Carmen Williams"},{"text":"But I don''t think New north needs to sit in on that.","index":382,"end_time":1557.45,"speaker_id":6,"start_time":1555.21,"speaker_name":"Carmen Williams"},{"text":"That would be okay.","index":383,"end_time":1559.38,"speaker_id":6,"start_time":1557.74,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":384,"end_time":1559.66,"speaker_id":1,"start_time":1559.38,"speaker_name":"Josh Reinhard"},{"text":"I mean, I don''t want to put unnecessary calls on your calendar.","index":385,"end_time":1562.7,"speaker_id":1,"start_time":1559.66,"speaker_name":"Josh Reinhard"},{"text":"Rather you guys like doing work for us rather than talking about the work.","index":386,"end_time":1566.94,"speaker_id":1,"start_time":1562.94,"speaker_name":"Josh Reinhard"},{"text":"So let''s take the Monday call off.","index":387,"end_time":1570.54,"speaker_id":1,"start_time":1567.82,"speaker_name":"Josh Reinhard"},{"text":"We''ll keep this Thursday call on and then whatever else Carmen, you have count you have scheduled with like Natalie.","index":388,"end_time":1578.38,"speaker_id":1,"start_time":1571.42,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":389,"end_time":1579.38,"speaker_id":6,"start_time":1578.94,"speaker_name":"Carmen Williams"},{"text":"So every two weeks right after this call, we''re going to do strategy.","index":390,"end_time":1582.98,"speaker_id":6,"start_time":1579.38,"speaker_name":"Carmen Williams"},{"text":"And if we need it weekly, we can do it weekly.","index":391,"end_time":1584.9,"speaker_id":6,"start_time":1582.98,"speaker_name":"Carmen Williams"},{"text":"And if it doesn''t need to be bi weekly and it''s monthly, we''ll figure that out.","index":392,"end_time":1588.72,"speaker_id":6,"start_time":1584.9,"speaker_name":"Carmen Williams"},{"text":"But right after this call and we''ll invite you and Robin where.","index":393,"end_time":1592.56,"speaker_id":6,"start_time":1588.72,"speaker_name":"Carmen Williams"},{"text":"When we need, when we''re presenting to you or when we need your input.","index":394,"end_time":1596.04,"speaker_id":6,"start_time":1592.56,"speaker_name":"Carmen Williams"},{"text":"But I suspect we''ll have these like work deep dive sessions, like really get into reporting, what the heck are we going to do with that?","index":395,"end_time":1603.96,"speaker_id":6,"start_time":1596.36,"speaker_name":"Carmen Williams"},{"text":"Or really get into the website and what are we doing there?","index":396,"end_time":1606.2,"speaker_id":6,"start_time":1603.96,"speaker_name":"Carmen Williams"},{"text":"So I don''t, I don''t think you want to be on that.","index":397,"end_time":1608.16,"speaker_id":6,"start_time":1606.2,"speaker_name":"Carmen Williams"},{"text":"I think you want us to come to you with here''s collectively what we think we want to do.","index":398,"end_time":1613.64,"speaker_id":6,"start_time":1608.16,"speaker_name":"Carmen Williams"},{"text":"And yeah, I do think things like the custom fields in HubSpot, like I have to be on that because I know where it fits into the sales pipeline.","index":399,"end_time":1624.37,"speaker_id":1,"start_time":1613.64,"speaker_name":"Josh Reinhard"},{"text":"But for sure, like what you''re talking about.","index":400,"end_time":1626.29,"speaker_id":1,"start_time":1624.37,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":401,"end_time":1626.53,"speaker_id":1,"start_time":1626.29,"speaker_name":"Josh Reinhard"},{"text":"I''d rather just hear the result of it.","index":402,"end_time":1628.85,"speaker_id":1,"start_time":1626.53,"speaker_name":"Josh Reinhard"},{"text":"And yeah.","index":403,"end_time":1630.01,"speaker_id":6,"start_time":1628.85,"speaker_name":"Carmen Williams"},{"text":"And once we get the reporting, like having that really tight tracking and reporting in place, then we''re going to be looking at the numbers and that''s the conversation we want to get to.","index":404,"end_time":1639.81,"speaker_id":6,"start_time":1630.01,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":405,"end_time":1640.63,"speaker_id":1,"start_time":1640.31,"speaker_name":"Josh Reinhard"},{"text":"So rather than tactical, we''ll get there.","index":406,"end_time":1643.11,"speaker_id":6,"start_time":1640.95,"speaker_name":"Carmen Williams"},{"text":"And then like we.","index":407,"end_time":1645.35,"speaker_id":1,"start_time":1643.75,"speaker_name":"Josh Reinhard"},{"text":"I had something today and Carmen, maybe this is a conversation for, for me and you, but I''ll at least throw it out today.","index":408,"end_time":1652.19,"speaker_id":1,"start_time":1645.35,"speaker_name":"Josh Reinhard"},{"text":"And like Dave sent me, we had all the ultimate column.","index":409,"end_time":1657.03,"speaker_id":1,"start_time":1652.19,"speaker_name":"Josh Reinhard"},{"text":"We went a different direction than the, than the deck that you guys put together for Dave, but Dave created a new deck that I think is more in line with what we want.","index":410,"end_time":1666.19,"speaker_id":1,"start_time":1657.03,"speaker_name":"Josh Reinhard"},{"text":"But it''s.","index":411,"end_time":1666.59,"speaker_id":1,"start_time":1666.19,"speaker_name":"Josh Reinhard"},{"text":"Dave created.","index":412,"end_time":1667.35,"speaker_id":1,"start_time":1666.59,"speaker_name":"Josh Reinhard"},{"text":"It''s not, you know, like it needs help from a stylistic perspective.","index":413,"end_time":1671.8,"speaker_id":1,"start_time":1667.35,"speaker_name":"Josh Reinhard"},{"text":"And he also put together a sequence that he wants to send out through HubSpot.","index":414,"end_time":1677.84,"speaker_id":1,"start_time":1671.8,"speaker_name":"Josh Reinhard"},{"text":"Yeah, Carmen, what should.","index":415,"end_time":1680.96,"speaker_id":1,"start_time":1678.32,"speaker_name":"Josh Reinhard"},{"text":"Yeah, so it''s kind of like we want to keep the ship going because I''m doing a lot of strategic stuff and we don''t want to stop, close the store.","index":416,"end_time":1689.84,"speaker_id":6,"start_time":1681.04,"speaker_name":"Carmen Williams"},{"text":"Right.","index":417,"end_time":1690.08,"speaker_id":6,"start_time":1689.84,"speaker_name":"Carmen Williams"},{"text":"We want to keep things going.","index":418,"end_time":1691.12,"speaker_id":6,"start_time":1690.08,"speaker_name":"Carmen Williams"},{"text":"So I think you just keep things going.","index":419,"end_time":1692.6,"speaker_id":6,"start_time":1691.12,"speaker_name":"Carmen Williams"},{"text":"It may not be perfect, but as we get things, you know, the positioning strategy, the messaging framework, then that''s going to also be.","index":420,"end_time":1700.69,"speaker_id":6,"start_time":1692.6,"speaker_name":"Carmen Williams"},{"text":"Go into, you know, updating the website, updating the deck, updating whatever campaigns.","index":421,"end_time":1706.68,"speaker_id":6,"start_time":1700.84,"speaker_name":"Carmen Williams"},{"text":"So, I mean, I think when David''s got something, throw it over to us and.","index":422,"end_time":1712.52,"speaker_id":6,"start_time":1707.8,"speaker_name":"Carmen Williams"},{"text":"And we''ll figure out what makes sense that New north needs to tackle versus what I can tackle or I don''t know.","index":423,"end_time":1719,"speaker_id":6,"start_time":1712.52,"speaker_name":"Carmen Williams"},{"text":"So throw it to you first and you kind of filter what goes to New North.","index":424,"end_time":1723.64,"speaker_id":1,"start_time":1719.4,"speaker_name":"Josh Reinhard"},{"text":"That was what I was thinking personally.","index":425,"end_time":1725.72,"speaker_id":1,"start_time":1723.72,"speaker_name":"Josh Reinhard"},{"text":"That''s what I told Dave because he wanted me to send it today.","index":426,"end_time":1727.92,"speaker_id":1,"start_time":1725.72,"speaker_name":"Josh Reinhard"},{"text":"And I was like, let''s just like, let''s talk to Carmen first before this.","index":427,"end_time":1731.95,"speaker_id":1,"start_time":1727.92,"speaker_name":"Josh Reinhard"},{"text":"But that.","index":428,"end_time":1734.43,"speaker_id":1,"start_time":1732.19,"speaker_name":"Josh Reinhard"},{"text":"So that sounds like what our plan will be.","index":429,"end_time":1736.11,"speaker_id":1,"start_time":1734.43,"speaker_name":"Josh Reinhard"},{"text":"So.","index":430,"end_time":1736.43,"speaker_id":1,"start_time":1736.11,"speaker_name":"Josh Reinhard"},{"text":"Yeah, yeah, have them throw it to you and I and we can decide what.","index":431,"end_time":1739.87,"speaker_id":6,"start_time":1736.43,"speaker_name":"Carmen Williams"},{"text":"What we want to do with it and then whether it needs to be New north because we''ll want to prioritize what New north does for their retainer they don''t want to be doing, you know.","index":432,"end_time":1748.59,"speaker_id":6,"start_time":1740.35,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":433,"end_time":1750.11,"speaker_id":6,"start_time":1749.63,"speaker_name":"Carmen Williams"},{"text":"All right.","index":434,"end_time":1755.56,"speaker_id":1,"start_time":1755.16,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":435,"end_time":1756.6,"speaker_id":6,"start_time":1756.04,"speaker_name":"Carmen Williams"},{"text":"Amazing.","index":436,"end_time":1757.24,"speaker_id":6,"start_time":1756.6,"speaker_name":"Carmen Williams"},{"text":"Awesome.","index":437,"end_time":1759.88,"speaker_id":0,"start_time":1759.24,"speaker_name":"Rob Whalen"},{"text":"All right, well, thank you guys very much.","index":438,"end_time":1761.4,"speaker_id":2,"start_time":1759.88,"speaker_name":"Colin Costigan"},{"text":"I know Carmen, you, Nina, and Natalie, I think, are staying on.","index":439,"end_time":1763.88,"speaker_id":2,"start_time":1761.4,"speaker_name":"Colin Costigan"},{"text":"Yeah, if it works.","index":440,"end_time":1765.52,"speaker_id":6,"start_time":1764.44,"speaker_name":"Carmen Williams"},{"text":"To use this spot.","index":441,"end_time":1768.12,"speaker_id":6,"start_time":1765.52,"speaker_name":"Carmen Williams"},{"text":"Actually, I think you, Natalie, did that work last week when I.","index":442,"end_time":1772.28,"speaker_id":2,"start_time":1768.84,"speaker_name":"Colin Costigan"},{"text":"Because I always have my meeting that bounces right after this.","index":443,"end_time":1775.64,"speaker_id":2,"start_time":1772.28,"speaker_name":"Colin Costigan"},{"text":"Were you able to stay on this link?","index":444,"end_time":1777.24,"speaker_id":2,"start_time":1775.8,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":445,"end_time":1778.2,"speaker_id":3,"start_time":1777.72,"speaker_name":"Nathalie Mintjens"},{"text":"Okay, cool, then.","index":446,"end_time":1779.12,"speaker_id":2,"start_time":1778.36,"speaker_name":"Colin Costigan"},{"text":"Yeah, just don''t end the meeting for everyone.","index":447,"end_time":1780.76,"speaker_id":3,"start_time":1779.12,"speaker_name":"Nathalie Mintjens"},{"text":"You have to make.","index":448,"end_time":1781.48,"speaker_id":6,"start_time":1780.76,"speaker_name":"Carmen Williams"},{"text":"Make her.","index":449,"end_time":1782.39,"speaker_id":6,"start_time":1781.99,"speaker_name":"Carmen Williams"},{"text":"Yeah, I gotta make her the host.","index":450,"end_time":1783.83,"speaker_id":2,"start_time":1782.63,"speaker_name":"Colin Costigan"},{"text":"Yep.","index":451,"end_time":1784.43,"speaker_id":2,"start_time":1783.99,"speaker_name":"Colin Costigan"},{"text":"Yeah, all the fun stuff.","index":452,"end_time":1785.59,"speaker_id":2,"start_time":1784.43,"speaker_name":"Colin Costigan"},{"text":"All right, awesome.","index":453,"end_time":1787.39,"speaker_id":2,"start_time":1786.55,"speaker_name":"Colin Costigan"},{"text":"Well, Josh, I hope the family starts feeling better.","index":454,"end_time":1789.91,"speaker_id":2,"start_time":1787.39,"speaker_name":"Colin Costigan"},{"text":"It is.","index":455,"end_time":1790.47,"speaker_id":1,"start_time":1789.91,"speaker_name":"Josh Reinhard"},{"text":"It''s the pits.","index":456,"end_time":1791.59,"speaker_id":2,"start_time":1790.79,"speaker_name":"Colin Costigan"},{"text":"It is the pits, but we''re just trying to hope everybody gets better for the Super Bowl.","index":457,"end_time":1797.07,"speaker_id":1,"start_time":1792.23,"speaker_name":"Josh Reinhard"},{"text":"We got a big, big weekend coming up.","index":458,"end_time":1798.75,"speaker_id":1,"start_time":1797.07,"speaker_name":"Josh Reinhard"},{"text":"Yeah, I know.","index":459,"end_time":1800.55,"speaker_id":6,"start_time":1798.75,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":460,"end_time":1802.15,"speaker_id":0,"start_time":1801.67,"speaker_name":"Rob Whalen"},{"text":"Should be a good one.","index":461,"end_time":1802.99,"speaker_id":2,"start_time":1802.31,"speaker_name":"Colin Costigan"},{"text":"I''m just hoping for a good game.","index":462,"end_time":1804.23,"speaker_id":2,"start_time":1802.99,"speaker_name":"Colin Costigan"},{"text":"Have you and Rob made a.","index":463,"end_time":1805.79,"speaker_id":1,"start_time":1804.39,"speaker_name":"Josh Reinhard"},{"text":"Made a bet yet?","index":464,"end_time":1806.63,"speaker_id":1,"start_time":1805.79,"speaker_name":"Josh Reinhard"},{"text":"I mean, feels like they got something.","index":465,"end_time":1810.11,"speaker_id":1,"start_time":1806.63,"speaker_name":"Josh Reinhard"},{"text":"Some kind of stakes going.","index":466,"end_time":1811.31,"speaker_id":1,"start_time":1810.11,"speaker_name":"Josh Reinhard"},{"text":"Oh, wow.","index":467,"end_time":1812.63,"speaker_id":7,"start_time":1811.79,"speaker_name":"Stephanie Lucchesi"},{"text":"We gotta talk about this.","index":468,"end_time":1813.71,"speaker_id":7,"start_time":1812.63,"speaker_name":"Stephanie Lucchesi"},{"text":"The Pat''s win.","index":469,"end_time":1816.47,"speaker_id":1,"start_time":1815.71,"speaker_name":"Josh Reinhard"},{"text":"Rob should have to wear a Patriots jersey during, like, the first.","index":470,"end_time":1819.47,"speaker_id":1,"start_time":1816.47,"speaker_name":"Josh Reinhard"},{"text":"I will wear.","index":471,"end_time":1820.91,"speaker_id":1,"start_time":1820.19,"speaker_name":"Josh Reinhard"},{"text":"I will go buy one and wear one.","index":472,"end_time":1822.79,"speaker_id":0,"start_time":1820.91,"speaker_name":"Rob Whalen"},{"text":"For the whole thing if they win.","index":473,"end_time":1824.43,"speaker_id":0,"start_time":1822.79,"speaker_name":"Rob Whalen"},{"text":"But then Steph needs to wear a Seahawks jersey if.","index":474,"end_time":1827.47,"speaker_id":1,"start_time":1825.07,"speaker_name":"Josh Reinhard"},{"text":"100%.","index":475,"end_time":1829.326,"speaker_id":0,"start_time":1828.03,"speaker_name":"Rob Whalen"},{"text":"100%.","index":476,"end_time":1830.91,"speaker_id":0,"start_time":1829.614,"speaker_name":"Rob Whalen"},{"text":"Another client that Natalie and I work with, they''re huge New England fans, and he just decided, like, yeah, I''m just gonna go to the Super Bowl.","index":477,"end_time":1839.66,"speaker_id":2,"start_time":1832.43,"speaker_name":"Colin Costigan"},{"text":"So he just bought a ticket.","index":478,"end_time":1840.66,"speaker_id":2,"start_time":1839.66,"speaker_name":"Colin Costigan"},{"text":"What?","index":479,"end_time":1841.14,"speaker_id":6,"start_time":1840.74,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":480,"end_time":1841.94,"speaker_id":4,"start_time":1841.46,"speaker_name":"Nina Belina"},{"text":"How do you get it?","index":481,"end_time":1844.1,"speaker_id":1,"start_time":1843.38,"speaker_name":"Josh Reinhard"},{"text":"It''s so expensive.","index":482,"end_time":1845.22,"speaker_id":0,"start_time":1844.1,"speaker_name":"Rob Whalen"},{"text":"Yeah, I''d rather be on my couch.","index":483,"end_time":1847.94,"speaker_id":7,"start_time":1845.3,"speaker_name":"Stephanie Lucchesi"},{"text":"I did buy the.","index":484,"end_time":1850.26,"speaker_id":7,"start_time":1849.06,"speaker_name":"Stephanie Lucchesi"},{"text":"The shirt that has, like, Tom Brady and Drake May like the step brothers.","index":485,"end_time":1855.3,"speaker_id":7,"start_time":1850.42,"speaker_name":"Stephanie Lucchesi"},{"text":"I was like, I have to buy this.","index":486,"end_time":1857.18,"speaker_id":7,"start_time":1855.78,"speaker_name":"Stephanie Lucchesi"},{"text":"That''s pretty funny.","index":487,"end_time":1858.14,"speaker_id":1,"start_time":1857.18,"speaker_name":"Josh Reinhard"},{"text":"So if we win, I''ll wear that.","index":488,"end_time":1859.86,"speaker_id":7,"start_time":1858.14,"speaker_name":"Stephanie Lucchesi"},{"text":"We have someone in my son''s class, my little guy''s class, where this flu is just ripping through their class.","index":489,"end_time":1869.02,"speaker_id":1,"start_time":1861.74,"speaker_name":"Josh Reinhard"},{"text":"They had five kids at school on Monday, six on Tuesday, out of, like, 17 or something that could go because everybody''s sick.","index":490,"end_time":1876.46,"speaker_id":1,"start_time":1869.02,"speaker_name":"Josh Reinhard"},{"text":"And this one family has tickets, and they''re like, whatever.","index":491,"end_time":1880.46,"speaker_id":1,"start_time":1876.46,"speaker_name":"Josh Reinhard"},{"text":"We need to pump our kid full of, like, don''t come flu, whatever we can do so that they can go.","index":492,"end_time":1885.74,"speaker_id":1,"start_time":1880.54,"speaker_name":"Josh Reinhard"},{"text":"They''re not even bringing him.","index":493,"end_time":1886.74,"speaker_id":1,"start_time":1885.74,"speaker_name":"Josh Reinhard"},{"text":"They just want to make sure he''s healthy before they leave him.","index":494,"end_time":1888.86,"speaker_id":1,"start_time":1886.74,"speaker_name":"Josh Reinhard"},{"text":"So they''re, like, just trying to get him fluids and everything.","index":495,"end_time":1891.75,"speaker_id":1,"start_time":1889.02,"speaker_name":"Josh Reinhard"},{"text":"So you''re going to homeschool this week?","index":496,"end_time":1893.31,"speaker_id":2,"start_time":1891.75,"speaker_name":"Colin Costigan"},{"text":"Yeah, exactly.","index":497,"end_time":1894.75,"speaker_id":6,"start_time":1893.79,"speaker_name":"Carmen Williams"},{"text":"Awesome.","index":498,"end_time":1895.63,"speaker_id":1,"start_time":1895.15,"speaker_name":"Josh Reinhard"},{"text":"All right.","index":499,"end_time":1895.91,"speaker_id":1,"start_time":1895.63,"speaker_name":"Josh Reinhard"},{"text":"Always good seeing you guys.","index":500,"end_time":1897.15,"speaker_id":2,"start_time":1895.91,"speaker_name":"Colin Costigan"},{"text":"I have to bounce into the next.","index":501,"end_time":1898.31,"speaker_id":0,"start_time":1897.23,"speaker_name":"Rob Whalen"},{"text":"One, but have a great rest of your day.","index":502,"end_time":1900.15,"speaker_id":2,"start_time":1898.31,"speaker_name":"Colin Costigan"},{"text":"All right, thanks, everybody.","index":503,"end_time":1901.23,"speaker_id":1,"start_time":1900.15,"speaker_name":"Josh Reinhard"},{"text":"Thanks.","index":504,"end_time":1902.71,"speaker_id":2,"start_time":1902.35,"speaker_name":"Colin Costigan"},{"text":"Yeah.","index":505,"end_time":1902.99,"speaker_id":6,"start_time":1902.71,"speaker_name":"Carmen Williams"},{"text":"Josh and Rob, I''m just going to walk through, I think, a very quick version of the audit I did and talk about where New north can help, where we can create these awesome.","index":506,"end_time":1913.51,"speaker_id":6,"start_time":1902.99,"speaker_name":"Carmen Williams"},{"text":"I''m going to jump off.","index":507,"end_time":1914.31,"speaker_id":0,"start_time":1913.51,"speaker_name":"Rob Whalen"},{"text":"Carmen, did you get the invite for dinner on Tuesday?","index":508,"end_time":1916.43,"speaker_id":0,"start_time":1914.31,"speaker_name":"Rob Whalen"},{"text":"I''ll be hoping you.","index":509,"end_time":1917.94,"speaker_id":0,"start_time":1916.98,"speaker_name":"Rob Whalen"},{"text":"I''m hoping you can make it.","index":510,"end_time":1918.82,"speaker_id":0,"start_time":1917.94,"speaker_name":"Rob Whalen"},{"text":"Great.","index":511,"end_time":1919.06,"speaker_id":0,"start_time":1918.82,"speaker_name":"Rob Whalen"},{"text":"Thank you.","index":512,"end_time":1919.78,"speaker_id":0,"start_time":1919.14,"speaker_name":"Rob Whalen"},{"text":"I''m out.","index":513,"end_time":1920.5,"speaker_id":0,"start_time":1919.94,"speaker_name":"Rob Whalen"},{"text":"Thank you.","index":514,"end_time":1921.38,"speaker_id":0,"start_time":1920.82,"speaker_name":"Rob Whalen"},{"text":"Carmen, do you need me on this?","index":515,"end_time":1924.82,"speaker_id":1,"start_time":1923.38,"speaker_name":"Josh Reinhard"},{"text":"I don''t think so.","index":516,"end_time":1925.94,"speaker_id":6,"start_time":1925.06,"speaker_name":"Carmen Williams"},{"text":"Unless you want to chime in if you have any additional thoughts from when I shared it with you, and I haven''t talked since Tuesday, so.","index":517,"end_time":1932.82,"speaker_id":6,"start_time":1925.94,"speaker_name":"Carmen Williams"},{"text":"Yeah, I mean, I can hang on, and I could just be a fly on the wall.","index":518,"end_time":1936.54,"speaker_id":1,"start_time":1933.78,"speaker_name":"Josh Reinhard"},{"text":"Chime in.","index":519,"end_time":1937.22,"speaker_id":1,"start_time":1936.54,"speaker_name":"Josh Reinhard"},{"text":"Sure.","index":520,"end_time":1937.94,"speaker_id":1,"start_time":1937.54,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":521,"end_time":1938.5,"speaker_id":6,"start_time":1938.02,"speaker_name":"Carmen Williams"},{"text":"I gotta remember where I put it.","index":522,"end_time":1940.62,"speaker_id":6,"start_time":1939.3,"speaker_name":"Carmen Williams"},{"text":"Yeah, Here we go.","index":523,"end_time":1941.38,"speaker_id":6,"start_time":1940.62,"speaker_name":"Carmen Williams"},{"text":"Actually, maybe I''ll show it from the canva.","index":524,"end_time":1944.45,"speaker_id":6,"start_time":1941.38,"speaker_name":"Carmen Williams"},{"text":"And actually, I don''t even need to go through the whole thing because I''m sure you read it, right.","index":525,"end_time":1948.37,"speaker_id":6,"start_time":1944.85,"speaker_name":"Carmen Williams"},{"text":"You guys had a quick peek through it?","index":526,"end_time":1950.05,"speaker_id":6,"start_time":1948.37,"speaker_name":"Carmen Williams"},{"text":"No, we didn''t.","index":527,"end_time":1952.37,"speaker_id":3,"start_time":1951.41,"speaker_name":"Nathalie Mintjens"},{"text":"The PDF didn''t come through.","index":528,"end_time":1954.29,"speaker_id":3,"start_time":1952.93,"speaker_name":"Nathalie Mintjens"},{"text":"Okay.","index":529,"end_time":1954.73,"speaker_id":3,"start_time":1954.29,"speaker_name":"Nathalie Mintjens"},{"text":"Oh, on the email, I don''t know.","index":530,"end_time":1956.37,"speaker_id":6,"start_time":1954.73,"speaker_name":"Carmen Williams"},{"text":"If you got my response, but I think.","index":531,"end_time":1958.77,"speaker_id":3,"start_time":1956.37,"speaker_name":"Nathalie Mintjens"},{"text":"I think if you Try to send it through SharePoint.","index":532,"end_time":1961.41,"speaker_id":3,"start_time":1959.009,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah.","index":533,"end_time":1961.97,"speaker_id":6,"start_time":1961.57,"speaker_name":"Carmen Williams"},{"text":"You don''t have access to that, right?","index":534,"end_time":1964.05,"speaker_id":6,"start_time":1961.97,"speaker_name":"Carmen Williams"},{"text":"Well what it is is I think because I''m using the Microsoft email, anything I attach, even though I attached the PDF, it gets converted to a link is what I think is happening.","index":535,"end_time":1975.68,"speaker_id":6,"start_time":1964.37,"speaker_name":"Carmen Williams"},{"text":"Because I didn''t give you a link, I gave you the attachment.","index":536,"end_time":1978.48,"speaker_id":6,"start_time":1975.84,"speaker_name":"Carmen Williams"},{"text":"But it''s okay, I''ll put it into, I guess can I load it into your portal Google Drive?","index":537,"end_time":1985.76,"speaker_id":6,"start_time":1978.48,"speaker_name":"Carmen Williams"},{"text":"Okay, yeah, just I''ll put it into Slack or you can tell me where to put it.","index":538,"end_time":1990.08,"speaker_id":6,"start_time":1986.88,"speaker_name":"Carmen Williams"},{"text":"But just real quick, we''re gonna try to prove the campaign results to get more money to spend top of funnel which is where we are under index.","index":539,"end_time":2002.31,"speaker_id":6,"start_time":1990.08,"speaker_name":"Carmen Williams"},{"text":"So you can read all this explanation as to kind of where you know where we want to get to to deliver on our 4.5 target.","index":540,"end_time":2010.79,"speaker_id":6,"start_time":2002.31,"speaker_name":"Carmen Williams"},{"text":"And you know we''re over indexed in the software tech tools which is kind of was my question about HubSpot.","index":541,"end_time":2017.03,"speaker_id":6,"start_time":2011.11,"speaker_name":"Carmen Williams"},{"text":"I think it''s four to five thousand a month.","index":542,"end_time":2019.11,"speaker_id":6,"start_time":2017.19,"speaker_name":"Carmen Williams"},{"text":"So you know, I think if we''re stuck there we''re going to have to just find ways to balance the budget to get more money spent at the top of funneled, build awareness.","index":543,"end_time":2029.89,"speaker_id":6,"start_time":2019.59,"speaker_name":"Carmen Williams"},{"text":"So this is kind of a target we''re going to shoot for.","index":544,"end_time":2032.73,"speaker_id":6,"start_time":2030.61,"speaker_name":"Carmen Williams"},{"text":"We won''t get it right out of the gate.","index":545,"end_time":2034.29,"speaker_id":6,"start_time":2032.73,"speaker_name":"Carmen Williams"},{"text":"But like I said, if we can prove results around some of these campaigns like the ABM campaign, these top of funnel campaigns, then we can work with Josh and Rob to you know, get the money to invest top of funnel, get kind of near that 600,000 range.","index":546,"end_time":2048.37,"speaker_id":6,"start_time":2034.29,"speaker_name":"Carmen Williams"},{"text":"Obviously this is, this section here is a lot of the information that came out of the audit.","index":547,"end_time":2054.05,"speaker_id":6,"start_time":2049.65,"speaker_name":"Carmen Williams"},{"text":"But you know, when it was a quick prompt into chat GTP kind of same same results came through which is before we invest in more spend we want to fix those life cycle governance issues that came out, you know, want to be marketing top to bottom of funnel and knowing the attribution.","index":548,"end_time":2072.21,"speaker_id":6,"start_time":2054.37,"speaker_name":"Carmen Williams"},{"text":"So this is a lot of detail.","index":549,"end_time":2074.77,"speaker_id":6,"start_time":2072.45,"speaker_name":"Carmen Williams"},{"text":"Like I said you can read it when I send it over to you.","index":550,"end_time":2077.33,"speaker_id":6,"start_time":2074.77,"speaker_name":"Carmen Williams"},{"text":"But this the you know, ex explanation of kind of we''re missing that tracking from top to bottom of funnel and you know how we need to fix, fix the funnel.","index":551,"end_time":2086.91,"speaker_id":6,"start_time":2077.33,"speaker_name":"Carmen Williams"},{"text":"So I''m not going to bore you with all the details.","index":552,"end_time":2088.99,"speaker_id":6,"start_time":2086.91,"speaker_name":"Carmen Williams"},{"text":"It''s kind of a little bit more of the minutia that we''re going to talk through and how we''re going to fix HubSpot and the lead management process.","index":553,"end_time":2097.63,"speaker_id":6,"start_time":2090.27,"speaker_name":"Carmen Williams"},{"text":"So that''s that piece.","index":554,"end_time":2099.63,"speaker_id":6,"start_time":2097.71,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":555,"end_time":2100.35,"speaker_id":6,"start_time":2099.95,"speaker_name":"Carmen Williams"},{"text":"And you know you guys can get into it.","index":556,"end_time":2102.15,"speaker_id":6,"start_time":2100.35,"speaker_name":"Carmen Williams"},{"text":"This is your, you know, your, your summary that you guys presented.","index":557,"end_time":2105.55,"speaker_id":6,"start_time":2102.15,"speaker_name":"Carmen Williams"},{"text":"So.","index":558,"end_time":2105.79,"speaker_id":6,"start_time":2105.55,"speaker_name":"Carmen Williams"},{"text":"Yeah, so yeah, then what we want to do is we don''t want to choke the funnel.","index":559,"end_time":2109.43,"speaker_id":6,"start_time":2105.79,"speaker_name":"Carmen Williams"},{"text":"If we'' focused on the bottom of the funnel, we''re just not going to end up, you know, driving the results we want to, we want to get to.","index":560,"end_time":2115.61,"speaker_id":6,"start_time":2109.43,"speaker_name":"Carmen Williams"},{"text":"So growth doesn''t come from optimizing just that one stage.","index":561,"end_time":2118.49,"speaker_id":6,"start_time":2115.61,"speaker_name":"Carmen Williams"},{"text":"We want a full funnel approach and design that entire journey from awareness through to conversion.","index":562,"end_time":2125.89,"speaker_id":6,"start_time":2119.05,"speaker_name":"Carmen Williams"},{"text":"So this kind of goes into detail of, you know, what''s broken, what we need to fix and, you know, kind of some of the key examples of, you know, the things we want to be doing at, you know, top to bottom of funnel.","index":563,"end_time":2139.4,"speaker_id":6,"start_time":2125.89,"speaker_name":"Carmen Williams"},{"text":"So this is just a visual that explains kind of, you know, the fun full funnel approach versus a short term GTM approach.","index":564,"end_time":2146.64,"speaker_id":6,"start_time":2139.4,"speaker_name":"Carmen Williams"},{"text":"So anyway, the brand.","index":565,"end_time":2150.08,"speaker_id":6,"start_time":2147.36,"speaker_name":"Carmen Williams"},{"text":"So love some of the things you''re doing.","index":566,"end_time":2152.88,"speaker_id":6,"start_time":2150.32,"speaker_name":"Carmen Williams"},{"text":"I kind of likened it to going from, you know, step one to step two and then step three.","index":567,"end_time":2157.92,"speaker_id":6,"start_time":2152.96,"speaker_name":"Carmen Williams"},{"text":"So I think we''re kind of just moving into step two where we''re adding.","index":568,"end_time":2161.32,"speaker_id":6,"start_time":2158,"speaker_name":"Carmen Williams"},{"text":"And you can see I, I, I''m not a great designer and I didn''t go buy photos, but I just added pictures of people which was not on the original PowerPoint.","index":569,"end_time":2169.1,"speaker_id":6,"start_time":2161.32,"speaker_name":"Carmen Williams"},{"text":"So just, you know, adding that human element, building that emotional connection and kind of really evolving the brand to, you know, kind of the final phase.","index":570,"end_time":2176.7,"speaker_id":6,"start_time":2169.1,"speaker_name":"Carmen Williams"},{"text":"That''s kind of what I want to help with you guys do.","index":571,"end_time":2179.02,"speaker_id":6,"start_time":2176.7,"speaker_name":"Carmen Williams"},{"text":"You know, prospects, when they feel understood, they lean in.","index":572,"end_time":2182.18,"speaker_id":6,"start_time":2179.74,"speaker_name":"Carmen Williams"},{"text":"And if they''re just feeling like they''re being informed, then they hesitate.","index":573,"end_time":2185.26,"speaker_id":6,"start_time":2182.18,"speaker_name":"Carmen Williams"},{"text":"And this is just to I wrote a book and that''s start with why is Simon?","index":574,"end_time":2189.94,"speaker_id":6,"start_time":2185.66,"speaker_name":"Carmen Williams"},{"text":"He has great book and mine''s kind of more the science behind it.","index":575,"end_time":2192.94,"speaker_id":6,"start_time":2189.94,"speaker_name":"Carmen Williams"},{"text":"So I''m going to use that in a couple of weeks when Josh, Rob and I get together and kind of talk, talk about our why and kind of how we want to build that emotional relationship with our audiences.","index":576,"end_time":2201.92,"speaker_id":6,"start_time":2192.94,"speaker_name":"Carmen Williams"},{"text":"So that''s just for what it''s worth.","index":577,"end_time":2204.28,"speaker_id":6,"start_time":2201.92,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":578,"end_time":2205.16,"speaker_id":6,"start_time":2204.68,"speaker_name":"Carmen Williams"},{"text":"So, you know, right now we''re gonna, you know, again, there''s this work that''s in the works that''s being done by you guys that''s gonna improve things.","index":579,"end_time":2213.44,"speaker_id":6,"start_time":2205.24,"speaker_name":"Carmen Williams"},{"text":"But just out of the gate, if you, you know, kind of get the chat GTP assessment, which is kind of my assessment, which is we''re talking too much about us.","index":580,"end_time":2221.16,"speaker_id":6,"start_time":2213.44,"speaker_name":"Carmen Williams"},{"text":"Right.","index":581,"end_time":2221.48,"speaker_id":6,"start_time":2221.16,"speaker_name":"Carmen Williams"},{"text":"You know, we''re very product centric and it''s all about us rather than about them and who they are and what''s going on.","index":582,"end_time":2227.16,"speaker_id":6,"start_time":2221.48,"speaker_name":"Carmen Williams"},{"text":"In their life.","index":583,"end_time":2227.8,"speaker_id":6,"start_time":2227.16,"speaker_name":"Carmen Williams"},{"text":"That''s kind of the main opportunity to fix that.","index":584,"end_time":2232.34,"speaker_id":6,"start_time":2228.66,"speaker_name":"Carmen Williams"},{"text":"And, you know, rational brands generate interest, but emotional brands generate that momentum.","index":585,"end_time":2239.18,"speaker_id":6,"start_time":2232.58,"speaker_name":"Carmen Williams"},{"text":"So that''s the goal.","index":586,"end_time":2240.1,"speaker_id":6,"start_time":2239.18,"speaker_name":"Carmen Williams"},{"text":"There''s some things we''re doing well, but there''s opportunity to, you know, improve.","index":587,"end_time":2245.14,"speaker_id":6,"start_time":2240.74,"speaker_name":"Carmen Williams"},{"text":"Kind of how we''re driving from top to bottom of funnel with your brand.","index":588,"end_time":2248.5,"speaker_id":6,"start_time":2245.3,"speaker_name":"Carmen Williams"},{"text":"So gets more details.","index":589,"end_time":2251.78,"speaker_id":6,"start_time":2249.62,"speaker_name":"Carmen Williams"},{"text":"Like I said, you guys can read this at your leisure.","index":590,"end_time":2254.26,"speaker_id":6,"start_time":2251.78,"speaker_name":"Carmen Williams"},{"text":"I think this is some of the stuff I want to work with you guys on.","index":591,"end_time":2257.9,"speaker_id":6,"start_time":2254.74,"speaker_name":"Carmen Williams"},{"text":"I''m just finished up my first draft of the Persona, so a little bit deeper, more robust exercise and good to get me up to date because I''m kind of new here and I''ll share those Personas with you.","index":592,"end_time":2271.62,"speaker_id":6,"start_time":2258.38,"speaker_name":"Carmen Williams"},{"text":"I''m just going to get Rob and Josh''s input and potentially the sales team''s input next week and then we can work from that as we kind of begin the positioning around the brand.","index":593,"end_time":2279.66,"speaker_id":6,"start_time":2271.62,"speaker_name":"Carmen Williams"},{"text":"The other thing that I feel like we''re at sort of stage two, we need to get to stage three or step three around is the abm.","index":594,"end_time":2287.5,"speaker_id":6,"start_time":2281.1,"speaker_name":"Carmen Williams"},{"text":"So, like, what you''re doing now is great as far as, you know, segmenting by industry and Persona, but what we want to do is also do more of a outbound abm, which is your one to one and one to few.","index":595,"end_time":2301.16,"speaker_id":6,"start_time":2288.36,"speaker_name":"Carmen Williams"},{"text":"So.","index":596,"end_time":2302.2,"speaker_id":6,"start_time":2301.8,"speaker_name":"Carmen Williams"},{"text":"So right now, like I said, we''re kind of doing a light ABM with the segmentation that you''re doing.","index":597,"end_time":2307.24,"speaker_id":6,"start_time":2302.36,"speaker_name":"Carmen Williams"},{"text":"But what we want to do is evolve to a more robust, you know, tier one, tier two, where you, you have named accounts and then you have named accounts in clusters, sort of that one to one, one to few.","index":598,"end_time":2319.5,"speaker_id":6,"start_time":2307.56,"speaker_name":"Carmen Williams"},{"text":"So I''m going to build out.","index":599,"end_time":2321.1,"speaker_id":6,"start_time":2320.06,"speaker_name":"Carmen Williams"},{"text":"I just got a list from Josh and I''m going to the next project.","index":600,"end_time":2325.5,"speaker_id":6,"start_time":2321.1,"speaker_name":"Carmen Williams"},{"text":"I''m going to start tackling, well, two things.","index":601,"end_time":2327.38,"speaker_id":6,"start_time":2325.5,"speaker_name":"Carmen Williams"},{"text":"I''m going to do a complete content audit, mapping of all of the existing content to find out what we have and what we don''t have from top to bottom of funnel, by Persona, by industry and then by account for these accounts.","index":602,"end_time":2340.42,"speaker_id":6,"start_time":2327.38,"speaker_name":"Carmen Williams"},{"text":"But.","index":603,"end_time":2340.7,"speaker_id":6,"start_time":2340.42,"speaker_name":"Carmen Williams"},{"text":"But then the other initiative is to do this sort of very thorough strategy and plan around Help Healthcare Enterprise abm.","index":604,"end_time":2347.69,"speaker_id":6,"start_time":2340.7,"speaker_name":"Carmen Williams"},{"text":"So that is an initiative.","index":605,"end_time":2349.69,"speaker_id":6,"start_time":2348.41,"speaker_name":"Carmen Williams"},{"text":"Once we have that strategy and plan, we''ll want to work with you and your team on building out campaigns.","index":606,"end_time":2354.41,"speaker_id":6,"start_time":2349.69,"speaker_name":"Carmen Williams"},{"text":"So that''s that initiative.","index":607,"end_time":2356.57,"speaker_id":6,"start_time":2354.65,"speaker_name":"Carmen Williams"},{"text":"And then you already know, I''d like to do just a little bit more due diligence around the UX for the website.","index":608,"end_time":2362.81,"speaker_id":6,"start_time":2356.57,"speaker_name":"Carmen Williams"},{"text":"And in that it''s an evolution, like, I think there''s no reason we can''t launch, you know, some of these things you''ve been working on, like the industry pages and such, but we can kind of keep it going and get to kind of, yeah, step three for that as well.","index":609,"end_time":2375.68,"speaker_id":6,"start_time":2363.21,"speaker_name":"Carmen Williams"},{"text":"So, you know, I''m not going to bore you with all the details, but like just some, you know, what''s working, what''s not working, kind of how we want to, you know, because you have to imagine the prospects are coming to your website.","index":610,"end_time":2387.36,"speaker_id":6,"start_time":2376.96,"speaker_name":"Carmen Williams"},{"text":"They''re not all bottom of funnel.","index":611,"end_time":2388.8,"speaker_id":6,"start_time":2387.36,"speaker_name":"Carmen Williams"},{"text":"Some are top, some are bottom.","index":612,"end_time":2390.16,"speaker_id":6,"start_time":2388.8,"speaker_name":"Carmen Williams"},{"text":"So we''ve got to, you know, kind of, you know, build out those customer journeys for, you know, for all of the prospects that are coming top to bottom of Funnel.","index":613,"end_time":2398.08,"speaker_id":6,"start_time":2390.16,"speaker_name":"Carmen Williams"},{"text":"And then I think there''s more to be done around SEO.","index":614,"end_time":2400.36,"speaker_id":6,"start_time":2398.32,"speaker_name":"Carmen Williams"},{"text":"SEO isn''t like, you know, top of the burner, front burner, like, you know, some E commerce brands that live and die by your, you know, traffic coming in.","index":615,"end_time":2408.55,"speaker_id":6,"start_time":2400.36,"speaker_name":"Carmen Williams"},{"text":"But I think there''s more that we can do around the pillar content.","index":616,"end_time":2412.63,"speaker_id":6,"start_time":2408.55,"speaker_name":"Carmen Williams"},{"text":"You know, intentionality about optimizing for, for both.","index":617,"end_time":2417.35,"speaker_id":6,"start_time":2413.35,"speaker_name":"Carmen Williams"},{"text":"And also thinking about AO as well.","index":618,"end_time":2420.63,"speaker_id":4,"start_time":2418.07,"speaker_name":"Nina Belina"},{"text":"Exactly.","index":619,"end_time":2421.35,"speaker_id":6,"start_time":2420.79,"speaker_name":"Carmen Williams"},{"text":"And, and I don''t know if I don''t know why I didn''t put that on there, the AI, but certainly I''ve got the content or this messaging specifics in there.","index":620,"end_time":2429.39,"speaker_id":6,"start_time":2421.35,"speaker_name":"Carmen Williams"},{"text":"So, yeah, 100%.","index":621,"end_time":2430.47,"speaker_id":6,"start_time":2429.39,"speaker_name":"Carmen Williams"},{"text":"So more we can talk about on that, that we''ll work together on.","index":622,"end_time":2434.66,"speaker_id":6,"start_time":2432.1,"speaker_name":"Carmen Williams"},{"text":"And then from, yeah, top of Funnel, like, again, there''s so much content on, like, maybe there''s a bunch of thought leadership content that I just can''t find yet and maybe it''s not being utilized correctly or maybe it''s missing.","index":623,"end_time":2444.22,"speaker_id":6,"start_time":2434.74,"speaker_name":"Carmen Williams"},{"text":"So we''ll find that out here when I''m finished with the content audit.","index":624,"end_time":2447.9,"speaker_id":6,"start_time":2444.22,"speaker_name":"Carmen Williams"},{"text":"But I think there''s an opportunity to do more, to really position us as a thought leader at the top of Funnel and interject in the day of our audience, you know, when they are, you know, exploring topics that are, you know, addressing their pain and, and kind of what''s on their heart.","index":625,"end_time":2464.11,"speaker_id":6,"start_time":2447.9,"speaker_name":"Carmen Williams"},{"text":"So I know that there''s been some experimentation around like a podcast.","index":626,"end_time":2469.55,"speaker_id":6,"start_time":2464.27,"speaker_name":"Carmen Williams"},{"text":"I think we can, you know, I''d like to discuss kind of how those early experience experimenting went.","index":627,"end_time":2476.39,"speaker_id":6,"start_time":2469.55,"speaker_name":"Carmen Williams"},{"text":"And I think there''s an opportunity to do more around, you know, evolving that podcast.","index":628,"end_time":2482.27,"speaker_id":6,"start_time":2476.39,"speaker_name":"Carmen Williams"},{"text":"And for example, a great tactic that lots of companies use is, let''s say we have this list of, you know, top 25 or 100 target healthcare executives that we want to reach and engage for our ABM initiative.","index":629,"end_time":2500.34,"speaker_id":6,"start_time":2483.14,"speaker_name":"Carmen Williams"},{"text":"We can invite those, you know, chief people officer, HR Leaders on our podcast.","index":630,"end_time":2505.86,"speaker_id":6,"start_time":2500.34,"speaker_name":"Carmen Williams"},{"text":"And so that''s a good way to kind of prove ROI around initiative like that.","index":631,"end_time":2511.69,"speaker_id":6,"start_time":2506.5,"speaker_name":"Carmen Williams"},{"text":"So what else?","index":632,"end_time":2513.85,"speaker_id":6,"start_time":2511.69,"speaker_name":"Carmen Williams"},{"text":"We''ve seen that work well.","index":633,"end_time":2515.45,"speaker_id":6,"start_time":2514.17,"speaker_name":"Carmen Williams"},{"text":"We''ve seen that work well.","index":634,"end_time":2516.73,"speaker_id":3,"start_time":2515.77,"speaker_name":"Nathalie Mintjens"},{"text":"And also to tie it into the ABM campaign.","index":635,"end_time":2518.73,"speaker_id":3,"start_time":2516.73,"speaker_name":"Nathalie Mintjens"},{"text":"Like it doesn''t have to be a separate thing.","index":636,"end_time":2520.61,"speaker_id":3,"start_time":2518.73,"speaker_name":"Nathalie Mintjens"},{"text":"It can be another layer that we add on.","index":637,"end_time":2522.65,"speaker_id":3,"start_time":2520.61,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah, Love it.","index":638,"end_time":2523.53,"speaker_id":6,"start_time":2522.73,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":639,"end_time":2523.81,"speaker_id":6,"start_time":2523.53,"speaker_name":"Carmen Williams"},{"text":"So I''m sure actually once you guys have had a just chance to kind of glance through this and we have our next, you know, we can set some times to deep dive into the website and such.","index":640,"end_time":2532.65,"speaker_id":6,"start_time":2523.81,"speaker_name":"Carmen Williams"},{"text":"You guys, I''m sure will have lots of great ideas to, you know, help take this to the next level.","index":641,"end_time":2537.73,"speaker_id":6,"start_time":2533.21,"speaker_name":"Carmen Williams"},{"text":"So I''m expecting that fully.","index":642,"end_time":2539.65,"speaker_id":6,"start_time":2537.81,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":643,"end_time":2541.01,"speaker_id":6,"start_time":2540.53,"speaker_name":"Carmen Williams"},{"text":"So humanizing the brand, building trust at scale, creating reasonable content across channels.","index":644,"end_time":2546.85,"speaker_id":6,"start_time":2541.01,"speaker_name":"Carmen Williams"},{"text":"And so that''s kind of the aim.","index":645,"end_time":2549.25,"speaker_id":6,"start_time":2547.65,"speaker_name":"Carmen Williams"},{"text":"And let''s see what else.","index":646,"end_time":2551.33,"speaker_id":6,"start_time":2549.81,"speaker_name":"Carmen Williams"},{"text":"Yeah, anyway, you can go through this.","index":647,"end_time":2553.73,"speaker_id":6,"start_time":2552.13,"speaker_name":"Carmen Williams"},{"text":"I don''t want to bore you, but next steps.","index":648,"end_time":2555.73,"speaker_id":6,"start_time":2553.73,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":649,"end_time":2558.05,"speaker_id":6,"start_time":2557.57,"speaker_name":"Carmen Williams"},{"text":"So this is what we talked about earlier on the call with Colin.","index":650,"end_time":2561.01,"speaker_id":6,"start_time":2558.05,"speaker_name":"Carmen Williams"},{"text":"You know, fixing that funnel, aligning marketing and sales on the lead management process, enforcing that lifecycle, governance, cleaning and segmenting the database, identifying the true ICP accounts, segmenting by industry size and then the ABM suppressing or re nurturing low quality leads.","index":651,"end_time":2578.38,"speaker_id":6,"start_time":2561.01,"speaker_name":"Carmen Williams"},{"text":"And then we get into clarifying the brand positioning.","index":652,"end_time":2581.5,"speaker_id":6,"start_time":2578.94,"speaker_name":"Carmen Williams"},{"text":"So the work that''s going to be done next week, no, the 17th, I''m going to have a work session with Rob and Josh and whoever else and we''re going to, you know, really tap into Rob''s why, you know, why you started a company and what really, really, truly is why we''re doing this and how that relates to our audience.","index":653,"end_time":2600.34,"speaker_id":6,"start_time":2581.5,"speaker_name":"Carmen Williams"},{"text":"And you know, out of that we''ll come, we''ll also do a swap.","index":654,"end_time":2604.26,"speaker_id":6,"start_time":2600.9,"speaker_name":"Carmen Williams"},{"text":"Strength, weakness, opportunities, threats against the competition.","index":655,"end_time":2606.94,"speaker_id":6,"start_time":2604.26,"speaker_name":"Carmen Williams"},{"text":"I know we don''t have direct competitors, but you know, there''s always alternatives to where people spend their time and money.","index":656,"end_time":2614.5,"speaker_id":6,"start_time":2606.94,"speaker_name":"Carmen Williams"},{"text":"So we''ll talk through kind of, you know, really what is our strength and our value, you know, unique selling proposition.","index":657,"end_time":2621.02,"speaker_id":6,"start_time":2614.58,"speaker_name":"Carmen Williams"},{"text":"Finalize that with a positioning statement and then out of that and the Persona work will come a messaging framework that I''ll throw over to you guys, I''ll throw over to our PR consultant.","index":658,"end_time":2633.66,"speaker_id":6,"start_time":2621.9,"speaker_name":"Carmen Williams"},{"text":"She''s fantastic as well.","index":659,"end_time":2635.02,"speaker_id":6,"start_time":2633.66,"speaker_name":"Carmen Williams"},{"text":"Kind of get your final inputs and then we''ll have a final messaging, you know, brand guidelines that''s a little bit more robust beyond just design and a messaging framework that we''re all, you know, agreed on, aligned on.","index":660,"end_time":2648.92,"speaker_id":6,"start_time":2635.34,"speaker_name":"Carmen Williams"},{"text":"And we''ll kind of use that as our, you know, starting point when we''re building out our campaigns going forward.","index":661,"end_time":2655.84,"speaker_id":6,"start_time":2648.92,"speaker_name":"Carmen Williams"},{"text":"So is there anything else?","index":662,"end_time":2657.56,"speaker_id":6,"start_time":2656,"speaker_name":"Carmen Williams"},{"text":"Yeah, we talked about the other things, so.","index":663,"end_time":2659.44,"speaker_id":6,"start_time":2657.56,"speaker_name":"Carmen Williams"},{"text":"Yeah, so that''s just kind of a quick.","index":664,"end_time":2661.2,"speaker_id":6,"start_time":2659.52,"speaker_name":"Carmen Williams"},{"text":"By the way, it''s not a full plan, as you know, that''s just kind of was a, you know, quick two weeks in making sure I am heading in the right direction, getting early input from Josh and Rob and then as we kind of get these things in place, then, you know, within maybe six, eight weeks, I should have like a strawman plan.","index":665,"end_time":2683.46,"speaker_id":6,"start_time":2661.2,"speaker_name":"Carmen Williams"},{"text":"Ultimately, I want to get to really seeing the data and having confidence in that so we can map out a numbers plan, a forecasting tool.","index":666,"end_time":2694.26,"speaker_id":6,"start_time":2684.34,"speaker_name":"Carmen Williams"},{"text":"So that''s kind of where I want to get to so that we can give Rob and Josh confidence that if we spend an extra hundred thousand, it''s going to drive these leads and, you know, that''s how we''ll get to $600,000 then Josh.","index":667,"end_time":2709.43,"speaker_id":6,"start_time":2695.86,"speaker_name":"Carmen Williams"},{"text":"So, yeah, I know that was a whirlwind, but I''ll throw it into Slack so you guys can, you know, take a look and anything you disagree, let me know.","index":668,"end_time":2720.15,"speaker_id":6,"start_time":2709.43,"speaker_name":"Carmen Williams"},{"text":"If you have questions, let me know.","index":669,"end_time":2722.95,"speaker_id":6,"start_time":2721.35,"speaker_name":"Carmen Williams"},{"text":"And then how we can move forward together on, you know, the, obviously the HubSpot project, but the, the branding.","index":670,"end_time":2732.1,"speaker_id":6,"start_time":2723.27,"speaker_name":"Carmen Williams"},{"text":"So I kind of want to, you know, really get a little bit more of a structure around that do''s and don''ts and you know, messaging and the feel and all that kind of stuff and then build out some additional like for example, you know, Sam''s keeping things going with blog posts and the social posts.","index":671,"end_time":2754.9,"speaker_id":6,"start_time":2732.18,"speaker_name":"Carmen Williams"},{"text":"At some point I''ll kind of take those on or we''ll get like a, a light service that does it or whatever.","index":672,"end_time":2759.21,"speaker_id":6,"start_time":2754.9,"speaker_name":"Carmen Williams"},{"text":"But we need the framework.","index":673,"end_time":2760.25,"speaker_id":6,"start_time":2759.21,"speaker_name":"Carmen Williams"},{"text":"We need like, okay, here''s the templates, here''s the structure and I can show how I''ve done this with our other brands and we work together.","index":674,"end_time":2766.97,"speaker_id":6,"start_time":2760.25,"speaker_name":"Carmen Williams"},{"text":"I use Canva only because it''s, it''s easier, I think, but you know, we can figure that out.","index":675,"end_time":2772.37,"speaker_id":6,"start_time":2766.97,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":676,"end_time":2774.01,"speaker_id":6,"start_time":2773.65,"speaker_name":"Carmen Williams"},{"text":"So branding, abm, website.","index":677,"end_time":2776.21,"speaker_id":6,"start_time":2774.01,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":678,"end_time":2777.09,"speaker_id":6,"start_time":2776.69,"speaker_name":"Carmen Williams"},{"text":"So those are the main.","index":679,"end_time":2778.05,"speaker_id":6,"start_time":2777.09,"speaker_name":"Carmen Williams"},{"text":"And then eventually a top of funnel like, you know, so, you know, and right now I don''t have what this is going to look like, so but we''ll work together.","index":680,"end_time":2787.91,"speaker_id":6,"start_time":2778.21,"speaker_name":"Carmen Williams"},{"text":"And what exactly this, you know, what''s the content calendar, what are these pillar themes, you know, and, and I, I think it''ll all kind of tie into kind of the work you''ve done.","index":681,"end_time":2795.95,"speaker_id":6,"start_time":2787.91,"speaker_name":"Carmen Williams"},{"text":"So nothing should be too, too far apart.","index":682,"end_time":2798.75,"speaker_id":6,"start_time":2795.95,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":683,"end_time":2799.11,"speaker_id":6,"start_time":2798.75,"speaker_name":"Carmen Williams"},{"text":"So, okay, I''ll stop talking.","index":684,"end_time":2800.27,"speaker_id":6,"start_time":2799.11,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":685,"end_time":2801.95,"speaker_id":6,"start_time":2801.47,"speaker_name":"Carmen Williams"},{"text":"Thoughts, questions, where you Want to add?","index":686,"end_time":2804.99,"speaker_id":6,"start_time":2802.11,"speaker_name":"Carmen Williams"},{"text":"Yeah, no, that''s really great.","index":687,"end_time":2807.71,"speaker_id":3,"start_time":2805.15,"speaker_name":"Nathalie Mintjens"},{"text":"I think so.","index":688,"end_time":2809.43,"speaker_id":3,"start_time":2807.71,"speaker_name":"Nathalie Mintjens"},{"text":"Everything makes sense.","index":689,"end_time":2810.23,"speaker_id":3,"start_time":2809.43,"speaker_name":"Nathalie Mintjens"},{"text":"But if I''m understanding correctly, for right now, our immediate priority is just going to be HubSpot.","index":690,"end_time":2814.75,"speaker_id":3,"start_time":2810.23,"speaker_name":"Nathalie Mintjens"},{"text":"Right.","index":691,"end_time":2815.07,"speaker_id":3,"start_time":2814.75,"speaker_name":"Nathalie Mintjens"},{"text":"Making sure that we get all of that taken care of.","index":692,"end_time":2817.41,"speaker_id":3,"start_time":2815.37,"speaker_name":"Nathalie Mintjens"},{"text":"Because once that''s done, then we''ll be able to really get into the reporting and making sure that''s accurate.","index":693,"end_time":2822.65,"speaker_id":3,"start_time":2817.41,"speaker_name":"Nathalie Mintjens"},{"text":"So just understanding from our side that that''s where we''re starting.","index":694,"end_time":2826.17,"speaker_id":3,"start_time":2823.29,"speaker_name":"Nathalie Mintjens"},{"text":"And then you''re also going to be working on the messaging and all that in tandem.","index":695,"end_time":2830.09,"speaker_id":3,"start_time":2826.17,"speaker_name":"Nathalie Mintjens"},{"text":"And then in a couple of weeks, we''ll be in a place to start drilling that down into, like, the website and everything else.","index":696,"end_time":2835.37,"speaker_id":3,"start_time":2830.09,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah.","index":697,"end_time":2836.37,"speaker_id":6,"start_time":2835.93,"speaker_name":"Carmen Williams"},{"text":"And then for the abm, we actually have a list of accounts.","index":698,"end_time":2839.73,"speaker_id":6,"start_time":2836.37,"speaker_name":"Carmen Williams"},{"text":"And what we need to do now is get those in, like, in a good way in HubSpot.","index":699,"end_time":2846.1,"speaker_id":6,"start_time":2839.73,"speaker_name":"Carmen Williams"},{"text":"Right.","index":700,"end_time":2846.42,"speaker_id":6,"start_time":2846.1,"speaker_name":"Carmen Williams"},{"text":"So, like, do we use our Zoom info tool?","index":701,"end_time":2848.58,"speaker_id":6,"start_time":2846.5,"speaker_name":"Carmen Williams"},{"text":"Do we use your tool?","index":702,"end_time":2849.78,"speaker_id":6,"start_time":2848.58,"speaker_name":"Carmen Williams"},{"text":"You know, I would like your.","index":703,"end_time":2852.18,"speaker_id":6,"start_time":2850.42,"speaker_name":"Carmen Williams"},{"text":"I''d love your team''s help in getting that, like, that''s a great initiative where we can, from top to bottom, like, get it set up correctly from a, you know.","index":704,"end_time":2862.58,"speaker_id":6,"start_time":2852.18,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":705,"end_time":2863.02,"speaker_id":3,"start_time":2862.58,"speaker_name":"Nathalie Mintjens"},{"text":"The right spot of HubSpot.","index":706,"end_time":2864.46,"speaker_id":6,"start_time":2863.02,"speaker_name":"Carmen Williams"},{"text":"I don''t even know, like, how to even articulate this because with my smaller clients, I use a light CRM like Zoho or Sharp Spring, and I just would dump those in the sales pipeline.","index":707,"end_time":2874,"speaker_id":6,"start_time":2864.46,"speaker_name":"Carmen Williams"},{"text":"I would create an ABM sales pipeline.","index":708,"end_time":2876.32,"speaker_id":6,"start_time":2874,"speaker_name":"Carmen Williams"},{"text":"And because we''d be like, these are qualified, you know, so there''s.","index":709,"end_time":2880.04,"speaker_id":6,"start_time":2876.64,"speaker_name":"Carmen Williams"},{"text":"It might be a better way to do that in HubSpot that I just don''t have that, you know, the wisdom there.","index":710,"end_time":2885.28,"speaker_id":6,"start_time":2880.04,"speaker_name":"Carmen Williams"},{"text":"And so I''d love your hand holding on.","index":711,"end_time":2888,"speaker_id":6,"start_time":2885.28,"speaker_name":"Carmen Williams"},{"text":"Let''s get the right.","index":712,"end_time":2889.52,"speaker_id":6,"start_time":2888.4,"speaker_name":"Carmen Williams"},{"text":"Like, we want a robust set of contacts for these.","index":713,"end_time":2893.6,"speaker_id":6,"start_time":2890,"speaker_name":"Carmen Williams"},{"text":"I think 30 and 30 and 10.","index":714,"end_time":2896.72,"speaker_id":6,"start_time":2894.24,"speaker_name":"Carmen Williams"},{"text":"So I think it''s 70.","index":715,"end_time":2898.53,"speaker_id":6,"start_time":2896.72,"speaker_name":"Carmen Williams"},{"text":"I think Josh, or however many we end up with this account list that we''re going after, that''s where we''re at.","index":716,"end_time":2904.65,"speaker_id":6,"start_time":2898.61,"speaker_name":"Carmen Williams"},{"text":"Right now is seven.","index":717,"end_time":2905.73,"speaker_id":1,"start_time":2904.65,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":718,"end_time":2907.09,"speaker_id":6,"start_time":2906.61,"speaker_name":"Carmen Williams"},{"text":"And so, you know, getting all of the correct leads in organized as segments or lists.","index":719,"end_time":2913.41,"speaker_id":6,"start_time":2907.41,"speaker_name":"Carmen Williams"},{"text":"You know, how are we going to track from.","index":720,"end_time":2916.85,"speaker_id":6,"start_time":2914.37,"speaker_name":"Carmen Williams"},{"text":"From when we start these campaigns to, you know, close to one.","index":721,"end_time":2921.25,"speaker_id":6,"start_time":2917.25,"speaker_name":"Carmen Williams"},{"text":"And so, yeah, I would.","index":722,"end_time":2924.3,"speaker_id":6,"start_time":2921.81,"speaker_name":"Carmen Williams"},{"text":"I would like your team''s expertise on the best way to do that and to help build up the campaigns.","index":723,"end_time":2929.66,"speaker_id":6,"start_time":2924.3,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":724,"end_time":2930.1,"speaker_id":6,"start_time":2929.66,"speaker_name":"Carmen Williams"},{"text":"I also wanted to mention, because you said working on the website and taking over the blog from Sam is to.","index":725,"end_time":2938.98,"speaker_id":4,"start_time":2932.66,"speaker_name":"Nina Belina"},{"text":"It''s always a good idea to start from SEO, because a lot of the times people make changes on the website and make a whole website plan.","index":726,"end_time":2946.62,"speaker_id":4,"start_time":2938.98,"speaker_name":"Nina Belina"},{"text":"Without thinking about it.","index":727,"end_time":2947.94,"speaker_id":4,"start_time":2946.62,"speaker_name":"Nina Belina"},{"text":"So since you''re starting from a new.","index":728,"end_time":2949.94,"speaker_id":4,"start_time":2948.18,"speaker_name":"Nina Belina"},{"text":"It would be really great to just kind of make that starting point, like make an SEO audit and then work from there for any new content that you want to set up.","index":729,"end_time":2958.85,"speaker_id":4,"start_time":2949.94,"speaker_name":"Nina Belina"},{"text":"Yeah.","index":730,"end_time":2960.41,"speaker_id":6,"start_time":2959.97,"speaker_name":"Carmen Williams"},{"text":"And I''m a believer that you''ve got to have both.","index":731,"end_time":2962.69,"speaker_id":6,"start_time":2960.41,"speaker_name":"Carmen Williams"},{"text":"So you''ve got to have the content that is, you know, like, what''s the goal?","index":732,"end_time":2967.45,"speaker_id":6,"start_time":2962.93,"speaker_name":"Carmen Williams"},{"text":"And the goal might be to connect emotionally and, you know, talk directly to these whatever people.","index":733,"end_time":2974.85,"speaker_id":6,"start_time":2967.45,"speaker_name":"Carmen Williams"},{"text":"And not SEO is the primary, but then there should be content that SEO is the primary.","index":734,"end_time":2979.73,"speaker_id":6,"start_time":2974.85,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":735,"end_time":2980.21,"speaker_id":6,"start_time":2979.73,"speaker_name":"Carmen Williams"},{"text":"So I think that the intentionality, which is what you''re talking about.","index":736,"end_time":2983.47,"speaker_id":6,"start_time":2980.21,"speaker_name":"Carmen Williams"},{"text":"I completely agree.","index":737,"end_time":2984.63,"speaker_id":6,"start_time":2983.47,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":738,"end_time":2985.07,"speaker_id":4,"start_time":2984.63,"speaker_name":"Nina Belina"},{"text":"And for example, it also connects to the human side because now with ao, you are basically giving an answer to a question.","index":739,"end_time":2992.71,"speaker_id":4,"start_time":2985.07,"speaker_name":"Nina Belina"},{"text":"So it''s.","index":740,"end_time":2993.95,"speaker_id":4,"start_time":2992.95,"speaker_name":"Nina Belina"},{"text":"I mean, whenever people search for PTO benefits, it would be really good to have those kind of connections that would show up in Gemini Perplexity or any other system.","index":741,"end_time":3004.39,"speaker_id":4,"start_time":2993.95,"speaker_name":"Nina Belina"},{"text":"Now, can you remind me, Josh, you guys had hired.","index":742,"end_time":3007.43,"speaker_id":6,"start_time":3004.95,"speaker_name":"Carmen Williams"},{"text":"I don''t know if it was New north or if it was a separate entity that did an AI initiative and you didn''t really feel like you got the results.","index":743,"end_time":3014.93,"speaker_id":6,"start_time":3007.43,"speaker_name":"Carmen Williams"},{"text":"What was.","index":744,"end_time":3015.65,"speaker_id":6,"start_time":3015.09,"speaker_name":"Carmen Williams"},{"text":"Was that a different company?","index":745,"end_time":3017.01,"speaker_id":6,"start_time":3015.73,"speaker_name":"Carmen Williams"},{"text":"And that was.","index":746,"end_time":3017.89,"speaker_id":6,"start_time":3017.01,"speaker_name":"Carmen Williams"},{"text":"Yeah, it was 11 11x.","index":747,"end_time":3020.05,"speaker_id":1,"start_time":3018.05,"speaker_name":"Josh Reinhard"},{"text":"Okay.","index":748,"end_time":3020.89,"speaker_id":6,"start_time":3020.29,"speaker_name":"Carmen Williams"},{"text":"The company that we used for them.","index":749,"end_time":3022.29,"speaker_id":1,"start_time":3020.89,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":750,"end_time":3022.89,"speaker_id":6,"start_time":3022.45,"speaker_name":"Carmen Williams"},{"text":"So.","index":751,"end_time":3023.25,"speaker_id":4,"start_time":3022.89,"speaker_name":"Nina Belina"},{"text":"So maybe Nina and Natalie.","index":752,"end_time":3025.97,"speaker_id":6,"start_time":3023.49,"speaker_name":"Carmen Williams"},{"text":"Like, I don''t know if this is a separate initiative, like, if it''s your team.","index":753,"end_time":3030.13,"speaker_id":6,"start_time":3025.97,"speaker_name":"Carmen Williams"},{"text":"If you have.","index":754,"end_time":3030.69,"speaker_id":6,"start_time":3030.13,"speaker_name":"Carmen Williams"},{"text":"Like, if you guys want to give us a proposal.","index":755,"end_time":3032.85,"speaker_id":6,"start_time":3030.69,"speaker_name":"Carmen Williams"},{"text":"Okay.","index":756,"end_time":3033.77,"speaker_id":6,"start_time":3033.25,"speaker_name":"Carmen Williams"},{"text":"On what you want to do for us from an SEO AI.","index":757,"end_time":3037.37,"speaker_id":6,"start_time":3033.77,"speaker_name":"Carmen Williams"},{"text":"I think we''re interested in hearing whether or not it becomes a priority right out of the gate or if it''s down the road.","index":758,"end_time":3043.12,"speaker_id":6,"start_time":3037.37,"speaker_name":"Carmen Williams"},{"text":"But we''re open to hearing.","index":759,"end_time":3044.6,"speaker_id":6,"start_time":3043.12,"speaker_name":"Carmen Williams"},{"text":"Hearing about that, I''m sure.","index":760,"end_time":3048.04,"speaker_id":6,"start_time":3046.28,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":761,"end_time":3048.68,"speaker_id":6,"start_time":3048.2,"speaker_name":"Carmen Williams"},{"text":"We can set that up.","index":762,"end_time":3051.8,"speaker_id":4,"start_time":3050.76,"speaker_name":"Nina Belina"},{"text":"We have an AO and SEO expert within the team, so we can create the plan and you can look what we mean when we mean working on AI.","index":763,"end_time":3062.2,"speaker_id":4,"start_time":3051.88,"speaker_name":"Nina Belina"},{"text":"Yeah.","index":764,"end_time":3068.13,"speaker_id":6,"start_time":3067.81,"speaker_name":"Carmen Williams"},{"text":"Cool.","index":765,"end_time":3068.77,"speaker_id":6,"start_time":3068.29,"speaker_name":"Carmen Williams"},{"text":"We''ve tried two different services for this, and neither of them really panned out.","index":766,"end_time":3073.89,"speaker_id":1,"start_time":3068.85,"speaker_name":"Josh Reinhard"},{"text":"I don''t know that the technology is there yet for what we were trying to do.","index":767,"end_time":3080.85,"speaker_id":1,"start_time":3073.89,"speaker_name":"Josh Reinhard"},{"text":"Yeah.","index":768,"end_time":3081.81,"speaker_id":6,"start_time":3081.33,"speaker_name":"Carmen Williams"},{"text":"And there''s, like, you know, I. I mean, there''s things we can do without the heavy lift, but, um.","index":769,"end_time":3092.64,"speaker_id":6,"start_time":3081.81,"speaker_name":"Carmen Williams"},{"text":"But it''d be good to see what was.","index":770,"end_time":3094.16,"speaker_id":6,"start_time":3092.64,"speaker_name":"Carmen Williams"},{"text":"What does the heavy lift look like and.","index":771,"end_time":3096.52,"speaker_id":6,"start_time":3094.16,"speaker_name":"Carmen Williams"},{"text":"And what''s the expected return and how can we evaluate and.","index":772,"end_time":3101.16,"speaker_id":6,"start_time":3096.84,"speaker_name":"Carmen Williams"},{"text":"Yeah, so, yeah, it''s not like a top burner, you know, but it''s.","index":773,"end_time":3106.36,"speaker_id":6,"start_time":3101.16,"speaker_name":"Carmen Williams"},{"text":"Yeah, it''s a potential as we evolve yeah, for sure.","index":774,"end_time":3109.48,"speaker_id":6,"start_time":3106.52,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":775,"end_time":3110.4,"speaker_id":6,"start_time":3110.04,"speaker_name":"Carmen Williams"},{"text":"Amazing.","index":776,"end_time":3110.92,"speaker_id":6,"start_time":3110.4,"speaker_name":"Carmen Williams"},{"text":"So.","index":777,"end_time":3111.32,"speaker_id":3,"start_time":3110.92,"speaker_name":"Nathalie Mintjens"},{"text":"So.","index":778,"end_time":3114.04,"speaker_id":6,"start_time":3113.64,"speaker_name":"Carmen Williams"},{"text":"So, Natalie, are you going to be the point person for, like, if we say, hey, we want to work on this ABM initiative together?","index":779,"end_time":3121.16,"speaker_id":6,"start_time":3114.12,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":780,"end_time":3123.84,"speaker_id":6,"start_time":3123.6,"speaker_name":"Carmen Williams"},{"text":"Okay, cool.","index":781,"end_time":3124.6,"speaker_id":6,"start_time":3123.84,"speaker_name":"Carmen Williams"},{"text":"And do you have a calendar?","index":782,"end_time":3127.68,"speaker_id":6,"start_time":3124.6,"speaker_name":"Carmen Williams"},{"text":"Point of contact?","index":783,"end_time":3129.76,"speaker_id":3,"start_time":3128.64,"speaker_name":"Nathalie Mintjens"},{"text":"A calendar link like, Addison?","index":784,"end_time":3133.88,"speaker_id":6,"start_time":3131.44,"speaker_name":"Carmen Williams"},{"text":"If I''m connecting with Josh and figuring out when we''re going to do a deep dive, and we may want to include you, just, you know, we can either go back and forth in Slack or if you have a link that I can use to schedule some time, just let me know.","index":785,"end_time":3146.16,"speaker_id":6,"start_time":3133.88,"speaker_name":"Carmen Williams"},{"text":"Next steps is.","index":786,"end_time":3148.44,"speaker_id":6,"start_time":3147.6,"speaker_name":"Carmen Williams"},{"text":"I''m going to take that list.","index":787,"end_time":3149.6,"speaker_id":6,"start_time":3148.44,"speaker_name":"Carmen Williams"},{"text":"I''m going to do my insights gathering and research and kind of map out this sort of strategy and plan.","index":788,"end_time":3156.97,"speaker_id":6,"start_time":3150.33,"speaker_name":"Carmen Williams"},{"text":"And, you know, I''ll use chat to kind of come up with some context.","index":789,"end_time":3161.85,"speaker_id":6,"start_time":3157.85,"speaker_name":"Carmen Williams"},{"text":"But what we really then need to do is actually go and get the full list of contacts from either Zoom Info or your tool or whatever tool we want to use.","index":790,"end_time":3170.93,"speaker_id":6,"start_time":3161.85,"speaker_name":"Carmen Williams"},{"text":"Yeah, yeah, yeah.","index":791,"end_time":3172.65,"speaker_id":6,"start_time":3170.93,"speaker_name":"Carmen Williams"},{"text":"We can definitely help with that.","index":792,"end_time":3173.93,"speaker_id":3,"start_time":3172.65,"speaker_name":"Nathalie Mintjens"},{"text":"Yeah.","index":793,"end_time":3174.73,"speaker_id":6,"start_time":3174.25,"speaker_name":"Carmen Williams"},{"text":"Cool.","index":794,"end_time":3176.66,"speaker_id":1,"start_time":3176.34,"speaker_name":"Josh Reinhard"},{"text":"Okay, great.","index":795,"end_time":3178.74,"speaker_id":6,"start_time":3178.1,"speaker_name":"Carmen Williams"},{"text":"Well, I just wanted to, you know, kind of get.","index":796,"end_time":3180.9,"speaker_id":6,"start_time":3178.74,"speaker_name":"Carmen Williams"},{"text":"Plant the seeds, give you kind of the vision and invite input.","index":797,"end_time":3185.7,"speaker_id":6,"start_time":3181.06,"speaker_name":"Carmen Williams"},{"text":"So feel free to take a look and.","index":798,"end_time":3188.02,"speaker_id":6,"start_time":3185.7,"speaker_name":"Carmen Williams"},{"text":"And get back to us with some questions or thoughts or input, and we''ll probably tackle these things separately.","index":799,"end_time":3194.9,"speaker_id":6,"start_time":3188.02,"speaker_name":"Carmen Williams"},{"text":"And, you know, when I''m ready to kind of engage you guys on abm, I will.","index":800,"end_time":3200.18,"speaker_id":6,"start_time":3195.22,"speaker_name":"Carmen Williams"},{"text":"When I''m ready to engage you on the branding, I will.","index":801,"end_time":3204.32,"speaker_id":6,"start_time":3200.18,"speaker_name":"Carmen Williams"},{"text":"And then website will probably follow.","index":802,"end_time":3206.64,"speaker_id":6,"start_time":3204.32,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":803,"end_time":3208,"speaker_id":6,"start_time":3207.44,"speaker_name":"Carmen Williams"},{"text":"Yeah.","index":804,"end_time":3209.4,"speaker_id":6,"start_time":3209.04,"speaker_name":"Carmen Williams"},{"text":"All right.","index":805,"end_time":3209.84,"speaker_id":0,"start_time":3209.4,"speaker_name":"Rob Whalen"},{"text":"Okay.","index":806,"end_time":3210.96,"speaker_id":6,"start_time":3210.4,"speaker_name":"Carmen Williams"},{"text":"Josh, anything else?","index":807,"end_time":3214.4,"speaker_id":6,"start_time":3212.72,"speaker_name":"Carmen Williams"},{"text":"No, I think we''re in a good spot.","index":808,"end_time":3217.76,"speaker_id":1,"start_time":3214.8,"speaker_name":"Josh Reinhard"},{"text":"Okay, amazing.","index":809,"end_time":3219.04,"speaker_id":6,"start_time":3217.919,"speaker_name":"Carmen Williams"},{"text":"See you in two weeks.","index":810,"end_time":3221.6,"speaker_id":6,"start_time":3220.64,"speaker_name":"Carmen Williams"},{"text":"If I don''t talk to you in between on some of these initiatives, we''ll.","index":811,"end_time":3225.04,"speaker_id":6,"start_time":3221.6,"speaker_name":"Carmen Williams"},{"text":"Yeah, sure.","index":812,"end_time":3226,"speaker_id":6,"start_time":3225.28,"speaker_name":"Carmen Williams"},{"text":"Keep us in the loop.","index":813,"end_time":3227.12,"speaker_id":4,"start_time":3226.16,"speaker_name":"Nina Belina"},{"text":"Thank you.","index":814,"end_time":3227.68,"speaker_id":4,"start_time":3227.12,"speaker_name":"Nina Belina"},{"text":"Okay, thanks.","index":815,"end_time":3228.42,"speaker_id":6,"start_time":3227.86,"speaker_name":"Carmen Williams"},{"text":"Thank you.","index":816,"end_time":3229.26,"speaker_id":0,"start_time":3228.74,"speaker_name":"Rob Whalen"},{"text":"Thank you.","index":817,"end_time":3229.74,"speaker_id":3,"start_time":3229.26,"speaker_name":"Nathalie Mintjens"},{"text":"Bye.","index":818,"end_time":3230.1,"speaker_id":4,"start_time":3229.74,"speaker_name":"Nina Belina"},{"text":"Bye.","index":819,"end_time":3230.58,"speaker_id":4,"start_time":3230.1,"speaker_name":"Nina Belina"}],"dateString":"2026-02-05T18:30:00.000Z","host_email":"colin.costigan@marketersindemand.c